-- Poems batch 455
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('yuding-8','南賓郡齋即事，寄楊萬州','白居易','唐','御定全唐诗','yuding','','[]','山上巴子城，山下巴江水。中有窮獨人，強名為刺史。',96,'御定全唐詩/json/434.json','["山上巴子城，山下巴江水。中有窮獨人，強名為刺史。", "時時竊自哂，刺史豈如是。倉粟喂家人，黃縑裹妻子。", "莓苔翳冠帶，霧雨霾樓雉。衙鼓暮複朝，郡齋臥還起。", "回頭望南浦，亦在煙波裏。而我複何嗟，夫君猶滯此。"]'),
('yuding-9','招蕭處士','白居易','唐','御定全唐诗','yuding','','[]','峽內豈無人，所逢非所思。門前亦有客，相對不相知。',96,'御定全唐詩/json/434.json','["峽內豈無人，所逢非所思。門前亦有客，相對不相知。", "仰望但雲樹，俯顧惟妻兒。寢食起居外，端然無所為。", "東郊蕭處士，聊可與開眉。能飲滿杯酒，善吟長句詩。", "庭前吏散後，江畔路幹時。請君攜竹杖，一赴郡齋期。"]'),
('yuding-10','庭槐','白居易','唐','御定全唐诗','yuding','','[]','南方饒竹樹，唯有青槐稀。十種七八死，縱活亦支離。',96,'御定全唐詩/json/434.json','["南方饒竹樹，唯有青槐稀。十種七八死，縱活亦支離。", "何此郡庭下，一株獨華滋。濛濛碧煙葉，嫋嫋黃花枝。", "我家渭水上，此樹蔭前墀。忽向天涯見，憶在故園時。", "人生有情感，遇物牽所思。樹木猶複爾，況見舊親知。"]'),
('yuding-11','送客回晚興','白居易','唐','御定全唐诗','yuding','','[]','城上雲霧開，沙頭風浪定。參差亂山出，澹濘平江淨。',48,'御定全唐詩/json/434.json','["城上雲霧開，沙頭風浪定。參差亂山出，澹濘平江淨。", "行客舟已遠，居人酒初醒。嫋嫋秋竹梢，巴蟬聲似磬。"]'),
('yuding-12','東樓竹','白居易','唐','御定全唐诗','yuding','','[]','瀟灑城東樓，繞樓多修竹。森然一萬竿，白粉封青玉。',72,'御定全唐詩/json/434.json','["瀟灑城東樓，繞樓多修竹。森然一萬竿，白粉封青玉。", "捲簾睡初覺，欹枕看未足。影轉色入樓，床席生浮綠。", "空城絕賓客，向夕彌幽獨。樓上夜不歸，此君留我宿。"]'),
('yuding-13','九日登巴台','白居易','唐','御定全唐诗','yuding','','[]','黍香酒初熟，菊暖花未開。閑聽竹枝曲，淺酌茱萸杯。',72,'御定全唐詩/json/434.json','["黍香酒初熟，菊暖花未開。閑聽竹枝曲，淺酌茱萸杯。", "去年重陽日，漂泊湓城隈。今歲重陽日，蕭條巴子台。", "旅鬢尋已白，鄉書久不來。臨觴一搔首，座客亦裴回。"]'),
('yuding-14','東城尋春','白居易','唐','御定全唐诗','yuding','','[]','老色日上面，歡情日去心。今既不如昔，後當不如今。',72,'御定全唐詩/json/434.json','["老色日上面，歡情日去心。今既不如昔，後當不如今。", "今猶未甚衰，每事力可任。花時仍愛出，酒後尚能吟。", "但恐如此興，亦隨日銷沉。東城春欲老，勉強一來尋。"]'),
('yuding-15','江上送客','白居易','唐','御定全唐诗','yuding','','[]','江花已萎絕，江草已消歇。遠客何處歸，孤舟今日發。',48,'御定全唐詩/json/434.json','["江花已萎絕，江草已消歇。遠客何處歸，孤舟今日發。", "杜鵑聲似哭，湘竹斑如血。共是多感人，仍為此中別。"]'),
('yuding-16','桐花','白居易','唐','御定全唐诗','yuding','','[]','春令有常候，清明桐始發。何此巴峽中，桐花開十月。',96,'御定全唐詩/json/434.json','["春令有常候，清明桐始發。何此巴峽中，桐花開十月。", "豈伊物理變，信是土宜別。地氣反寒暄，天時倒生殺。", "草木堅強物，所稟固難奪。風候一參差，榮枯遂乖剌。", "況吾北人性，不耐南方熱。強羸壽夭間，安得依時節。"]'),
('yuding-17','早祭風伯，因懷李十一舍人','白居易','唐','御定全唐诗','yuding','','[]','遠郡雖褊陋，時祀奉朝經。夙興祭風伯，天氣曉冥冥。',96,'御定全唐詩/json/434.json','["遠郡雖褊陋，時祀奉朝經。夙興祭風伯，天氣曉冥冥。", "導騎與從吏，引我出東坰。水霧重如雨，山火高於星。", "忽憶早朝日，與君趨紫庭。步登龍尾道，卻望終南青。", "一別身向老，所思心未寧。至今想在耳，玉音尚玲玲。"]'),
('yuding-18','花下對酒二首','白居易','唐','御定全唐诗','yuding','','[]','藹藹江氣春，南賓閏正月。梅櫻與桃杏，次第城上發。',192,'御定全唐詩/json/434.json','["藹藹江氣春，南賓閏正月。梅櫻與桃杏，次第城上發。", "紅房爛簇火，素豔紛團雪。香惜委風飄，愁牽壓枝折。", "樓中老太守，頭上新白髮。冷澹病心情，暄和好時節。", "故園音信斷，遠郡親賓絕。欲問花前尊，依然為誰設。", "引手攀紅櫻，紅櫻落似霰。仰首看白日，白日走如箭。", "年芳與時景，頃刻猶衰變。況是血肉身，安能長強健。", "人心苦迷執，慕貴憂貧賤。愁色常在眉，歡容不上面。", "況吾頭半白，把鏡非不見。何必花下杯，更待他人勸。"]'),
('yuding-19','不二門','白居易','唐','御定全唐诗','yuding','','[]','兩眼日將暗，四肢漸衰瘦。束帶剩昔圍，穿衣妨寬袖。',144,'御定全唐詩/json/434.json','["兩眼日將暗，四肢漸衰瘦。束帶剩昔圍，穿衣妨寬袖。", "流年似江水，奔注無昏晝。志氣與形骸，安得長依舊。", "亦曾登玉陛，舉措多紕繆。至今金闕籍，名姓獨遺漏。", "亦曾燒大藥，消息乖火候。至今殘丹砂，燒幹不成就。", "行藏事兩失，憂惱心交鬥。化作憔悴翁，拋身在荒陋。", "坐看老病逼，須得醫王救。唯有不二門，其間無夭壽。"]'),
('yuding-20','我身','白居易','唐','御定全唐诗','yuding','','[]','我身何所似，似彼孤生蓬。秋霜剪根斷，浩浩隨長風。',108,'御定全唐詩/json/434.json','["我身何所似，似彼孤生蓬。秋霜剪根斷，浩浩隨長風。", "昔游秦雍間，今落巴蠻中。昔為意氣郎，今作寂寥翁。", "外貌雖寂寞，中懷頗沖融。賦命有厚薄，委心任窮通。", "通當為大鵬，舉翅摩蒼穹。窮則為鷦鷯，一枝足自容。", "苟知此道者，身窮心不窮。"]'),
('yuding-21','哭王質夫','白居易','唐','御定全唐诗','yuding','','[]','仙遊寺前別，別來十年餘。生別猶怏怏，死別複何如。',156,'御定全唐詩/json/434.json','["仙遊寺前別，別來十年餘。生別猶怏怏，死別複何如。", "客從梓潼來，道君死不虛。驚疑心未信，欲哭複踟躕。", "踟躕寢門側，聲發涕亦俱。衣上今日淚，篋中前月書。", "憐君古人風，重有君子儒。篇詠陶謝輩，風流嵇阮徒。", "出身既蹇屯，生世仍須臾。誠知天至高，安得不一呼。", "江南有毒蟒，江北有妖狐。皆享千年壽，多於王質夫。", "不知彼何德，不識此何辜。"]'),
('yuding-22','東坡種花二首','白居易','唐','御定全唐诗','yuding','','[]','持錢買花樹，城東坡上栽。但購有花者，不限桃杏梅。',276,'御定全唐詩/json/434.json','["持錢買花樹，城東坡上栽。但購有花者，不限桃杏梅。", "百果參雜種，千枝次第開。天時有早晚，地力無高低。", "紅者霞豔豔，白者雪皚皚。遊蜂逐不去，好鳥亦來棲。", "前有長流水，下有小平臺。時拂臺上石，一舉風前杯。", "花枝蔭我頭，花蕊落我懷。獨酌複獨詠，不覺月平西。", "巴俗不愛花，竟春無人來。唯此醉太守，盡日不能回。", "東坡春向暮，樹木今何如。漠漠花落盡，翳翳葉生初。", "每日領童僕，荷鋤仍決渠。剗土壅其本，引泉溉其枯。", "小樹低數尺，大樹長丈餘。封植來幾時，高下隨扶疏。", "養樹既如此，養民亦何殊。將欲茂枝葉，必先救根株。", "雲何救根株，勸農均賦租。雲何茂枝葉，省事寬刑書。", "移此為郡政，庶幾甿俗蘇。"]'),
('yuding-23','登城東古台','白居易','唐','御定全唐诗','yuding','','[]','迢迢東郊上，有土青崔嵬。不知何代物，疑是巴王台。',96,'御定全唐詩/json/434.json','["迢迢東郊上，有土青崔嵬。不知何代物，疑是巴王台。", "巴歌久無聲，巴宮沒黃埃。靡靡春草合，牛羊緣四隈。", "我來一登眺，目極心悠哉。始見江山勢，峰疊水環回。", "憑高視聽曠，向遠胸襟開。唯有故園念，時時東北來。"]'),
('yuding-24','哭諸故人，因寄元八','白居易','唐','御定全唐诗','yuding','','[]','昨日哭寢門，今日哭寢門。借問所哭誰，無非故交親。',120,'御定全唐詩/json/434.json','["昨日哭寢門，今日哭寢門。借問所哭誰，無非故交親。", "偉卿既長往，質夫亦幽淪。屈指數年世，收涕自思身。", "彼皆少於我，先為泉下人。我今頭半白，焉得身久存。", "好狂元郎中，相識二十春。昔見君生子，今聞君抱孫。", "存者盡老大，逝者已成塵。早晚升平宅，開眉一見君。"]'),
('yuding-25','郡中春宴，因贈諸客','白居易','唐','御定全唐诗','yuding','','[]','僕本儒家子，待詔金馬門。塵忝親近地，孤負聖明恩。',192,'御定全唐詩/json/434.json','["僕本儒家子，待詔金馬門。塵忝親近地，孤負聖明恩。", "一旦奉優詔，萬里牧遠人。可憐島夷帥，自稱為使君。", "身騎牂牁馬，口食塗江鱗。暗澹緋衫故，斕斑白發新。", "是時歲二月，玉曆布春分。頒條示皇澤，命宴及良辰。", "冉冉趨府吏，蚩蚩聚州民。有如蟄蟲鳥，亦應天地春。", "熏草席鋪坐，藤枝酒注樽。中庭無平地，高下隨所陳。", "蠻鼓聲坎坎，巴女舞蹲蹲。使君居上頭，掩口語眾賓。", "勿笑風俗陋，勿欺官府貧。蜂巢與蟻穴，隨分有君臣。"]'),
('yuding-26','開元寺東池早春','白居易','唐','御定全唐诗','yuding','','[]','池水暖溫暾，水清波瀲灩。簇簇青泥中，新蒲葉如劍。',72,'御定全唐詩/json/434.json','["池水暖溫暾，水清波瀲灩。簇簇青泥中，新蒲葉如劍。", "梅房小白裹，柳彩輕黃染。順氣草熏熏，適情鷗泛泛。", "舊游成夢寐，往事隨陽焱。芳物感幽懷，一動平生念。"]'),
('yuding-27','東溪種柳','白居易','唐','御定全唐诗','yuding','','[]','野性愛栽植，植柳水中坻。乘春持斧斫，裁截而樹之。',132,'御定全唐詩/json/434.json','["野性愛栽植，植柳水中坻。乘春持斧斫，裁截而樹之。", "長短既不一，高下隨所宜。倚岸埋大幹，臨流插小枝。", "松柏不可待，楩楠固難移。不如種此樹，此樹易榮滋。", "無根亦可活，成陰況非遲。三年未離郡，可以見依依。", "種罷水邊憩，仰頭閑自思。富貴本非望，功名須待時。", "不種東溪柳，端坐欲何為。"]'),
('yuding-28','臥小齋','白居易','唐','御定全唐诗','yuding','','[]','朝起視事畢，晏坐飽食終。散步長廊下，臥退小齋中。',48,'御定全唐詩/json/434.json','["朝起視事畢，晏坐飽食終。散步長廊下，臥退小齋中。", "拙政自多暇，幽情誰與同。孰雲二千石，心如田野翁。"]'),
('yuding-29','步東坡','白居易','唐','御定全唐诗','yuding','','[]','朝上東坡步，夕上東坡步。東坡何所愛，愛此新成樹。',96,'御定全唐詩/json/434.json','["朝上東坡步，夕上東坡步。東坡何所愛，愛此新成樹。", "種植當歲初，滋榮及春暮。信意取次栽，無行亦無數。", "綠陰斜景轉，芳氣微風度。新葉鳥下來，萎花蝶飛去。", "閑攜斑竹杖，徐曳黃麻屨。欲識往來頻，青蕪成白路。"]'),
('yuding-30','征秋稅畢，題郡南亭','白居易','唐','御定全唐诗','yuding','','[]','高城直下視，蠢蠢見巴蠻。安可施政教，尚不通語言。',84,'御定全唐詩/json/434.json','["高城直下視，蠢蠢見巴蠻。安可施政教，尚不通語言。", "且喜賦斂畢，幸聞閭井安。豈伊循良化，賴此豐登年。", "案牘既簡少，池館亦清閒。秋雨簷果落，夕鐘林鳥還。", "南亭日瀟灑，偃臥恣疏頑。"]'),
('yuding-31','蚊蟆','白居易','唐','御定全唐诗','yuding','','[]','巴徼炎毒早，二月蚊蟆生。咂膚拂不去，繞耳薨薨聲。',72,'御定全唐詩/json/434.json','["巴徼炎毒早，二月蚊蟆生。咂膚拂不去，繞耳薨薨聲。", "斯物頗微細，中人初甚輕。如有膚受譖，久則瘡痏成。", "痏成無奈何，所要防其萌。么蟲何足道，潛喻儆人情。"]'),
('yuding-32','登龍昌上寺望江南山，懷錢舍人','白居易','唐','御定全唐诗','yuding','','[]','騎馬出西郭，悠悠欲何之。獨上高寺去，一與白雲期。',72,'御定全唐詩/json/434.json','["騎馬出西郭，悠悠欲何之。獨上高寺去，一與白雲期。", "虛檻晚瀟灑，前山碧參差。忽似青龍閣，同望玉峰時。", "因詠松雪句，永懷鸞鶴姿。六年不相見，況乃隔榮衰。"]'),
('yuding-33','郊下','白居易','唐','御定全唐诗','yuding','','[]','西日照高樹，樹頭子規鳴。東風吹野水，水畔江蘺生。',48,'御定全唐詩/json/434.json','["西日照高樹，樹頭子規鳴。東風吹野水，水畔江蘺生。", "盡日看山立，有時尋澗行。兀兀長如此，何許似專城。"]'),
('yuding-34','遣懷','白居易','唐','御定全唐诗','yuding','','[]','樂往必悲生，泰來由否極。誰言此數然，吾道何終塞。',96,'御定全唐詩/json/434.json','["樂往必悲生，泰來由否極。誰言此數然，吾道何終塞。", "嘗求詹尹蔔，拂龜竟默默。亦曾仰問天，天但蒼蒼色。", "自茲唯委命，名利心雙息。近日轉安閒，鄉園亦休憶。", "回看世間苦，苦在求不得。我今無所求，庶離憂悲域。"]'),
('yuding-35','歲晚','白居易','唐','御定全唐诗','yuding','','[]','霜降水返壑，風落木歸山。冉冉歲將宴，物皆複本源。',84,'御定全唐詩/json/434.json','["霜降水返壑，風落木歸山。冉冉歲將宴，物皆複本源。", "何此南遷客，五年獨未還。命屯分已定，日久心彌安。", "亦嘗心與口，靜念私自言。去國固非樂，歸鄉未必歡。", "何須自生苦，舍易求其難。"]'),
('yuding-36','負冬日','白居易','唐','御定全唐诗','yuding','','[]','杲杲冬日出，照我屋南隅。負暄閉目坐，和氣生肌膚。',60,'御定全唐詩/json/434.json','["杲杲冬日出，照我屋南隅。負暄閉目坐，和氣生肌膚。", "初似飲醇醪，又如蟄者蘇。外融百骸暢，中適一念無。", "曠然忘所在，心與虛空俱。"]'),
('yuding-37','委順','白居易','唐','御定全唐诗','yuding','','[]','山城雖荒蕪，竹樹有嘉色。郡俸誠不多，亦足充衣食。',72,'御定全唐詩/json/434.json','["山城雖荒蕪，竹樹有嘉色。郡俸誠不多，亦足充衣食。", "外累由心起，心寧累自息。尚欲忘家鄉，誰能算官職。", "宜懷齊遠近，委順隨南北。歸去誠可憐，天涯住亦得。"]'),
('yuding-38','宿溪翁','白居易','唐','御定全唐诗','yuding','','[]','眾心愛金玉，眾口貪酒肉。何如此溪翁，飲瓢亦自足。',96,'御定全唐詩/json/434.json','["眾心愛金玉，眾口貪酒肉。何如此溪翁，飲瓢亦自足。", "溪南刈薪草，溪北修牆屋。歲種一頃田，春驅兩黃犢。", "于中甚安適，此外無營欲。溪畔偶相逢，庵中遂同宿。", "醉翁向朝市，問我何官祿。虛言笑殺翁，郎官應列宿。"]'),
('yuding-39','重過壽泉，憶與楊九別時，因題店壁','白居易','唐','御定全唐诗','yuding','','[]','商州南十裏，有水名壽泉。湧出石崖下，流經山店前。',84,'御定全唐詩/json/434.json','["商州南十裏，有水名壽泉。湧出石崖下，流經山店前。", "憶昔相送日，我去君言還。寒波與老淚，此地共潺湲。", "一去曆萬里，再來經六年。形容已變改，處所猶依然。", "他日君過此，殷勤吟此篇。"]'),
('yuding-40','西掖早秋直夜書意','白居易','唐','御定全唐诗','yuding','','[]','涼風起禁掖，新月生宮沼。夜半秋暗來，萬年枝嫋嫋。',108,'御定全唐詩/json/434.json','["涼風起禁掖，新月生宮沼。夜半秋暗來，萬年枝嫋嫋。", "炎涼遞時節，鐘鼓交昏曉。遇聖惜年衰，報恩愁力小。", "素餐無補益，朱綬虛纏繞。冠蓋棲野雲，稻粱養山鳥。", "量能私自省，所得已非少。五品不為賤，五十不為夭。", "若無知足心，貪求何日了。"]'),
('yuding-41','庭松','白居易','唐','御定全唐诗','yuding','','[]','堂下何所有，十松當我階。亂立無行次，高下亦不齊。',192,'御定全唐詩/json/434.json','["堂下何所有，十松當我階。亂立無行次，高下亦不齊。", "高者三丈長，下者十尺低。有如野生物，不知何人栽。", "接以青瓦屋，承之白沙台。朝昏有風月，燥濕無塵泥。", "疏韻秋槭槭，涼陰夏淒淒。春深微雨夕，滿葉珠蓑蓑。", "歲暮大雪天，壓枝玉皚皚。四時各有趣，萬木非其儕。", "去年買此宅，多為人所咍。一家二十口，移轉就松來。", "移來有何得，但得煩襟開。即此是益友，豈必交賢才。", "顧我猶俗士，冠帶走塵埃。未稱為松主，時時一愧懷。"]'),
('yuding-42','竹窗','白居易','唐','御定全唐诗','yuding','','[]','常愛輞川寺，竹窗東北廊。一別十餘載，見竹未曾忘。',168,'御定全唐詩/json/434.json','["常愛輞川寺，竹窗東北廊。一別十餘載，見竹未曾忘。", "今春二月初，卜居在新昌。未暇作廄庫，且先營一堂。", "開窗不糊紙，種竹不依行。意取北簷下，窗與竹相當。", "繞屋聲淅淅，逼人色蒼蒼。煙通杳靄氣，月透玲瓏光。", "是時三伏天，天氣熱如湯。獨此竹窗下，朝回解衣裳。", "輕紗一幅巾，小簟六尺床。無客盡日靜，有風終夜涼。", "乃知前古人，言事頗諳詳。清風北窗臥，可以傲羲皇。"]'),
('yuding-43','同韓侍郎游鄭家池吟詩小飲','白居易','唐','御定全唐诗','yuding','','[]','野艇容三人，晚池流浼浼。悠然依棹坐，水思如江海。',96,'御定全唐詩/json/434.json','["野艇容三人，晚池流浼浼。悠然依棹坐，水思如江海。", "宿雨洗沙塵，晴風蕩煙靄。殘陽上竹樹，枝葉生光彩。", "我本偶然來，景物如相待。白鷗驚不起，綠芡行堪采。", "齒發雖已衰，性靈未雲改。逢詩遇杯酒，尚有心情在。"]'),
('yuding-44','晚歸有感','白居易','唐','御定全唐诗','yuding','','[]','朝吊李家孤，暮問崔家疾。回馬獨歸來，低眉心鬱鬱。',72,'御定全唐詩/json/434.json','["朝吊李家孤，暮問崔家疾。回馬獨歸來，低眉心鬱鬱。", "平生所善者，多不過六七。如何十年間，零落三無一。", "劉曾夢中見，元向花前失。漸老與誰遊，春城好風日。"]'),
('yuding-45','曲江感秋二首','白居易','唐','御定全唐诗','yuding','','[]','元和二年秋，我年三十七。長慶二年秋，我年五十一。',240,'御定全唐詩/json/434.json','["元和二年秋，我年三十七。長慶二年秋，我年五十一。", "中間十四年，六年居譴黜。窮通與榮悴，委運隨外物。", "遂師廬山遠，重吊湘江屈。夜聽竹枝愁，秋看灩堆沒。", "近辭巴郡印，又秉綸闈筆。晚遇何足言，白髮映朱紱。", "銷沉昔意氣，改換舊容質。獨有曲江秋，風煙如往日。", "疏蕪南岸草，蕭颯西風樹。秋到未幾時，蟬聲又無數。", "莎平綠茸合，蓮落青房露。今日臨望時，往年感秋處。", "池中水依舊，城上山如故。獨我鬢間毛，昔黑今垂素。", "榮名與壯齒，相避如朝暮。時命始欲來，年顏已先去。", "當春不歡樂，臨老徒驚誤。故作詠懷詩，題于曲江路。"]'),
('yuding-46','玩松竹二首','白居易','唐','御定全唐诗','yuding','','[]','龍蛇隱大澤，麋鹿游豐草。棲鳳安於梧，潛魚樂於藻。',120,'御定全唐詩/json/434.json','["龍蛇隱大澤，麋鹿游豐草。棲鳳安於梧，潛魚樂於藻。", "吾亦愛吾廬，廬中樂吾道。前松後修竹，偃臥可終老。", "各附其所安，不知他物好。", "坐愛前簷前，臥愛北窗北。窗竹多好風，簷松有嘉色。", "幽懷一以合，俗含隨緣息。在爾雖無情，於予即有得。", "乃知性相近，不必動與植。"]'),
('yuding-47','衰病無趣，因吟所懷','白居易','唐','御定全唐诗','yuding','','[]','朝餐多不飽，夜臥常少睡。自覺寢食間，多無少年味。',108,'御定全唐詩/json/434.json','["朝餐多不飽，夜臥常少睡。自覺寢食間，多無少年味。", "平生好詩酒，今亦將捨棄。酒唯下藥飲，無複曾歡醉。", "詩多聽人吟，自不題一字。病姿與衰相，日夜相繼至。", "況當尚少朝，彌慚居近侍。終當求一郡，聚少漁樵費。", "合口便歸山，不問人間事。"]'),
('yuding-48','逍遙詠','白居易','唐','御定全唐诗','yuding','','[]','亦莫戀此身，亦莫厭此身。此身何足戀，萬劫煩惱根。',48,'御定全唐詩/json/434.json','["亦莫戀此身，亦莫厭此身。此身何足戀，萬劫煩惱根。", "此身何足厭，一聚虛空塵。無戀亦無厭，始是逍遙人。"]'),
('yuding-0','短歌行','白居易','唐','御定全唐诗','yuding','','[]','曈曈太陽如火色，上行千里下一刻。出為白晝入為夜，',72,'御定全唐詩/json/435.json','["曈曈太陽如火色，上行千里下一刻。出為白晝入為夜，", "歌聲苦，詞亦苦，四座少年君聽取。今夕未竟明夕催，", "勸君且強笑一面，勸君且強飲一杯。人生不得長歡樂，"]'),
('yuding-1','生離別','白居易','唐','御定全唐诗','yuding','','[]','食檗不易食梅難，檗能苦兮梅能酸。未如生別之為難，',72,'御定全唐詩/json/435.json','["食檗不易食梅難，檗能苦兮梅能酸。未如生別之為難，", "回看骨肉哭一聲，梅酸檗苦甘如蜜。黃河水白黃雲秋，", "生離別，生離別，憂從中來無斷絕。憂極心勞血氣衰，"]'),
('yuding-2','浩歌行','白居易','唐','御定全唐诗','yuding','','[]','天長地久無終畢，昨夜今朝又明日。鬢髮蒼浪牙齒疏，',96,'御定全唐詩/json/435.json','["天長地久無終畢，昨夜今朝又明日。鬢髮蒼浪牙齒疏，", "既無長繩系白日，又無大藥駐朱顏。朱顏日漸不如故，", "去複去兮如長河，東流赴海無回波。賢愚貴賤同歸盡，", "顏回短命伯夷餓，我今所得亦已多。功名富貴須待命，"]'),
('yuding-3','王夫子','白居易','唐','御定全唐诗','yuding','','[]','王夫子，送君為一尉，東南三千五百里。道途雖遠位雖卑，',96,'御定全唐詩/json/435.json','["王夫子，送君為一尉，東南三千五百里。道途雖遠位雖卑，", "近將徇祿給一家，遠則行道佐時理，行道佐時須待命，", "男兒上既未能濟天下，下又不至饑寒死。吾觀九品至一品，", "王夫子，別有一事欲勸君，遇酒逢春且歡喜。"]'),
('yuding-4','江南遇天寶樂叟','白居易','唐','御定全唐诗','yuding','','[]','白頭病叟泣且言，祿山未亂入梨園。能彈琵琶和法曲，',136,'御定全唐詩/json/435.json','["白頭病叟泣且言，祿山未亂入梨園。能彈琵琶和法曲，", "千官起居環佩合，萬國會同車馬奔。金鈿照耀石甕寺，", "冬雪飄颻錦袍暖，春風蕩漾霓裳翻。歡娛未足燕寇至，", "從此漂淪落南土，萬人死盡一身存。秋風江上浪無限，", "我自秦來君莫問，驪山渭水如荒村。新豐樹老籠明月，", "唯有中官作宮使，每年寒食一開門。"]'),
('yuding-5','送張山人歸嵩陽','白居易','唐','御定全唐诗','yuding','','[]','黃昏慘慘天微雪，修行坊西鼓聲絕。張生馬瘦衣且單，',84,'御定全唐詩/json/435.json','["黃昏慘慘天微雪，修行坊西鼓聲絕。張生馬瘦衣且單，", "酒酣火暖與君言，何事入關又出關。答雲前年偶下山，", "朝遊九城陌，肥馬輕車欺殺客。暮宿五侯門，", "幸有雲泉容此身，明日辭君且歸去。"]'),
('yuding-6','醉後走筆酬劉五主簿長句之贈兼簡張大賈二十四先輩昆季','白居易','唐','御定全唐诗','yuding','','[]','劉兄文高行孤立，十五年前名翕習。是時相遇在符離，',395,'御定全唐詩/json/435.json','["劉兄文高行孤立，十五年前名翕習。是時相遇在符離，", "衡門寂寞朝尋我，古寺蕭條暮訪君。朝來暮去多攜手，", "陴湖綠愛白鷗飛，濉水清憐紅鯉肥。偶語閑攀芳樹立，", "問我棲棲何所適，鄉人薦為鹿鳴客。二千里別謝交遊，", "冬冬街鼓紅塵暗，晚到長安無主人。二賈二張與余弟，", "齊入文場同苦戰，五人十載九登科。二張得雋名居甲，", "唯有沅犀屈未伸，握中自謂駭雞珍。三年不鳴鳴必大，", "始辭秘閣吏王畿，遽列諫垣升禁闈。蹇步何堪鳴佩玉，", "步登龍尾上虛空，立去天顏無咫尺。宮花似雪從乘輿，", "晚松寒竹新昌第，職居密近門多閉。日暮銀台下直回，", "斂手炎涼敘未畢，先說舊山今悔出。岐陽旅宦少歡娛，", "歲月徒催白髮貌，泥塗不屈青雲心。誰會茫茫天地意，", "君同鸞鳳棲荊棘，猶著青袍作選人。惆悵知賢不能薦，", "大底浮榮何足道，幾度相逢即身老。且傾鬥酒慰羈愁，", "武裏村花落複開，流溝山色應如故。感此酬君千字詩，", "慷慨臨歧重相勉，殷勤別後加餐飯。", "君不見買臣衣錦還故鄉，五十身榮未為晚。"]'),
('yuding-7','和錢員外答盧員外早春獨游曲江見寄長句','白居易','唐','御定全唐诗','yuding','','[]','春來有色暗融融，先到詩情酒思中。柳岸霏微裛塵雨，',48,'御定全唐詩/json/435.json','["春來有色暗融融，先到詩情酒思中。柳岸霏微裛塵雨，", "醉思詩侶有同年，春歎翰林無暇日。雲夫首倡寒玉音，"]'),
('yuding-8','東墟晚歇','白居易','唐','御定全唐诗','yuding','','[]','涼風冷露蕭索天，黃蒿紫菊荒涼田。繞塚秋花少顏色，',48,'御定全唐詩/json/435.json','["涼風冷露蕭索天，黃蒿紫菊荒涼田。繞塚秋花少顏色，", "晚從南澗釣魚回，歇此墟中白楊下。褐衣半故白髮新，"]'),
('yuding-9','客中月','白居易','唐','御定全唐诗','yuding','','[]','客從江南來，來時月上弦。悠悠行旅中，三見清光圓。',72,'御定全唐詩/json/435.json','["客從江南來，來時月上弦。悠悠行旅中，三見清光圓。", "曉隨殘月行，夕與新月宿。誰謂月無情，千里遠相逐。", "朝發渭水橋，暮入長安陌。不知今夜月，又作誰家客。"]'),
('yuding-10','挽歌詞','白居易','唐','御定全唐诗','yuding','','[]','丹旐何飛揚，素驂亦悲鳴。晨光照閭巷，輀車儼欲行。',92,'御定全唐詩/json/435.json','["丹旐何飛揚，素驂亦悲鳴。晨光照閭巷，輀車儼欲行。", "蕭條九月天，哀挽出重城。借問送者誰，妻子與弟兄。", "蒼蒼上古原，峨峨開新塋。含酸一慟哭，異口同哀聲。", "舊隴轉蕪絕，新墳日羅列。春風草綠北邙山，"]'),
('yuding-11','長相思','白居易','唐','御定全唐诗','yuding','','[]','九月西風興，月冷露華凝。思君秋夜長，一夜魂九升。',132,'御定全唐詩/json/435.json','["九月西風興，月冷露華凝。思君秋夜長，一夜魂九升。", "二月東風來，草拆花心開。思君春日遲，一日腸九回。", "妾住洛橋北，君住洛橋南。十五即相識，今年二十三。", "有如女蘿草，生在松之側。蔓短枝苦高，縈回上不得。", "人言人有願，願至天必成。願作遠方獸，步步比肩行。", "願作深山木，枝枝連理生。"]'),
('yuding-12','山鷓鴣','白居易','唐','御定全唐诗','yuding','','[]','山鷓鴣，朝朝暮暮啼複啼，啼時露白風淒淒。',82,'御定全唐詩/json/435.json','["山鷓鴣，朝朝暮暮啼複啼，啼時露白風淒淒。", "黃茅岡頭秋日晚，苦竹嶺下寒月低。畬田有粟何不啄，", "夢鄉遷客輾轉臥，抱兒寡婦彷徨立。山鷓鴣，", "啼到曉，唯能愁北人，南人慣聞如不聞。"]'),
('yuding-13','放旅雁','白居易','唐','御定全唐诗','yuding','','[]','九江十年冬大雪，江水生冰樹枝折。百鳥無食東西飛，',88,'御定全唐詩/json/435.json','["九江十年冬大雪，江水生冰樹枝折。百鳥無食東西飛，", "江童持網捕將去，手攜入市生賣之。我本北人今譴謫，", "雁雁汝飛向何處，第一莫飛西北去。淮西有賊討未平，", "健兒饑餓射汝吃，拔汝翅翎為箭羽。"]'),
('yuding-14','送春歸','白居易','唐','御定全唐诗','yuding','','[]','送春歸，三月盡日日暮時。去年杏園花飛禦溝綠，',68,'御定全唐詩/json/435.json','["送春歸，三月盡日日暮時。去年杏園花飛禦溝綠，", "帝城送春猶怏怏，天涯送春能不加惆悵。莫惆悵，", "五年炎涼凡十變，又知此身健不健。好去今年江上春，"]'),
('yuding-15','山石榴寄元九','白居易','唐','御定全唐诗','yuding','','[]','山石榴，一名山躑躅，一名杜鵑花，杜鵑啼時花撲撲。',144,'御定全唐詩/json/435.json','["山石榴，一名山躑躅，一名杜鵑花，杜鵑啼時花撲撲。", "九江三月杜鵑來，一聲催得一枝開。江城上佐閑無事，", "千房萬葉一時新，嫩紫殷紅鮮麹塵。淚痕裛損燕支臉，", "日射血珠將滴地，風翻火焰欲燒人。閑折兩枝持在手，", "奇芳絕豔別者誰，通州遷客元拾遺。拾遺初貶江陵去，", "題詩報我何所雲，苦雲色似石榴裙。當時叢畔唯思我，"]'),
('yuding-16','畫竹歌','白居易','唐','御定全唐诗','yuding','','[]','植物之中竹難寫，古今雖畫無似者。蕭郎下筆獨逼真，',114,'御定全唐詩/json/435.json','["植物之中竹難寫，古今雖畫無似者。蕭郎下筆獨逼真，", "人畫竹梢死羸垂，蕭畫枝活葉葉動。不根而生從意生，", "嬋娟不失筠粉態，蕭颯盡得風煙情。舉頭忽看不似畫，", "東叢八莖疏且寒，憶曾湘妃廟裏雨中看。幽姿遠思少人別，", "自言便是絕筆時，從今此竹尤難得。"]'),
('yuding-17','真娘墓','白居易','唐','御定全唐诗','yuding','','[]','真娘墓，虎丘道。不識真娘鏡中面，唯見真娘墓頭草。',48,'御定全唐詩/json/435.json','["真娘墓，虎丘道。不識真娘鏡中面，唯見真娘墓頭草。", "霜摧桃李風折蓮，真娘死時猶少年。脂膚荑手不牢固，"]'),
('yuding-18','長恨歌','白居易','唐','御定全唐诗','yuding','','[]','漢皇重色思傾國，禦宇多年求不得。楊家有女初長成，',480,'御定全唐詩/json/435.json','["漢皇重色思傾國，禦宇多年求不得。楊家有女初長成，", "回眸一笑百媚生，六宮粉黛無顏色。春寒賜浴華清池，", "雲鬢花顏金步搖，芙蓉帳暖度春宵。春宵苦短日高起，", "後宮佳麗三千人，三千寵愛在一身。金屋妝成嬌侍夜，", "遂令天下父母心，不重生男重生女。驪宮高處入青雲，", "漁陽鞞鼓動地來，驚破霓裳羽衣曲。九重城闕煙塵生，", "六軍不發無奈何，宛轉蛾眉馬前死。花鈿委地無人收，", "黃埃散漫風蕭索，雲棧縈紆登劍閣。峨嵋山下少人行，", "行宮見月傷心色，夜雨聞鈴腸斷聲。天旋日轉回龍馭，", "君臣相顧盡沾衣，東望都門信馬歸。歸來池苑皆依舊，", "春風桃李花開夜，秋雨梧桐葉落時。西宮南苑多秋草，", "夕殿螢飛思悄然，孤燈挑盡未成眠。遲遲鐘鼓初長夜，", "悠悠生死別經年，魂魄不曾來入夢。臨邛道士鴻都客，", "排空馭氣奔如電，升天入地求之遍。上窮碧落下黃泉，", "樓閣玲瓏五雲起，其中綽約多仙子。中有一人字太真，", "聞道漢家天子使，九華帳裏夢魂驚。攬衣推枕起裴回，", "風吹仙袂飄颻舉，猶似霓裳羽衣舞。玉容寂寞淚闌幹，", "昭陽殿裏恩愛絕，蓬萊宮中日月長。回頭下望人寰處，", "釵留一股合一扇，釵擘黃金合分鈿。但教心似金鈿堅，", "七月七日長生殿，夜半無人私語時。在天願作比翼鳥，"]'),
('yuding-19','婦人苦','白居易','唐','御定全唐诗','yuding','','[]','蟬鬢加意梳，蛾眉用心掃。幾度曉妝成，君看不言好。',192,'御定全唐詩/json/435.json','["蟬鬢加意梳，蛾眉用心掃。幾度曉妝成，君看不言好。", "妾身重同穴，君意輕偕老。惆悵去年來，心知未能道。", "今朝一開口，語少意何深。願引他時事，移君此日心。", "人言夫婦親，義合如一身。及至死生際，何曾苦樂均。", "婦人一喪夫，終身守孤孑。有如林中竹，忽被風吹折。", "一折不重生，枯死猶抱節。男兒若喪婦，能不暫傷情。", "應似門前柳，逢春易發榮。風吹一枝折，還有一枝生。", "為君委曲言，願君再三聽。須知婦人苦，從此莫相輕。"]'),
('yuding-20','長安道','白居易','唐','御定全唐诗','yuding','','[]','花枝缺處青樓開，豔歌一曲酒一杯。美人勸我急行樂，',24,'御定全唐詩/json/435.json','["花枝缺處青樓開，豔歌一曲酒一杯。美人勸我急行樂，"]'),
('yuding-21','潛別離','白居易','唐','御定全唐诗','yuding','','[]','不得哭，潛別離。不得語，暗相思。兩心之外無人知。',48,'御定全唐詩/json/435.json','["不得哭，潛別離。不得語，暗相思。兩心之外無人知。", "深籠夜鎖獨棲鳥，利劍春斷連理枝。河水雖濁有清日，"]'),
('yuding-22','隔浦蓮','白居易','唐','御定全唐诗','yuding','','[]','隔浦愛紅蓮，昨日看猶在。夜來風吹落，只得一回採。',40,'御定全唐詩/json/435.json','["隔浦愛紅蓮，昨日看猶在。夜來風吹落，只得一回採。", "花開雖有明年期，複愁明年還暫時。"]'),
('yuding-23','寒食野望吟','白居易','唐','御定全唐诗','yuding','','[]','丘墟郭門外，寒食誰家哭。風吹曠野紙錢飛，',36,'御定全唐詩/json/435.json','["丘墟郭門外，寒食誰家哭。風吹曠野紙錢飛，", "冥寞重泉哭不聞，蕭蕭墓雨人歸去。"]'),
('yuding-24','琵琶引','白居易','唐','御定全唐诗','yuding','','[]','潯陽江頭夜送客，楓葉荻花秋索索。主人下馬客在船，',360,'御定全唐詩/json/435.json','["潯陽江頭夜送客，楓葉荻花秋索索。主人下馬客在船，", "忽聞水上琵琶聲，主人忘歸客不發。尋聲暗問彈者誰，", "千呼萬喚始出來，猶抱琵琶半遮面。轉軸撥弦三兩聲，", "低眉信手續續彈，說盡心中無限事。輕攏慢撚抹複挑，", "嘈嘈切切錯雜彈，大珠小珠落玉盤。間關鶯語花底滑，", "別有幽愁暗恨生，此時無聲勝有聲。銀瓶乍破水漿迸，", "東舟西舫悄無言，唯見江心秋月白。沉吟放撥插弦中，", "十三學得琵琶成，名屬教坊第一部。曲罷曾教善才伏，", "鈿頭雲篦擊節碎，血色羅裙翻酒汙。今年歡笑複明年，", "門前冷落鞍馬稀，老大嫁作商人婦。商人重利輕別離，", "夜深忽夢少年事，夢啼妝淚紅闌幹。我聞琵琶已歎息，", "我從去年辭帝京，謫居臥病潯陽城。潯陽小處無音樂，", "其間旦暮聞何物，杜鵑啼血猿哀鳴。春江花朝秋月夜，", "今夜聞君琵琶語，如聽仙樂耳暫明。莫辭更坐彈一曲，", "淒淒不似向前聲，滿座重聞皆掩泣。座中泣下誰最多，"]'),
('yuding-25','簡簡吟','白居易','唐','御定全唐诗','yuding','','[]','蘇家小女名簡簡，芙蓉花腮柳葉眼。十一把鏡學點妝，',72,'御定全唐詩/json/435.json','["蘇家小女名簡簡，芙蓉花腮柳葉眼。十一把鏡學點妝，", "玲瓏雲髻生花樣，飄颻風袖薔薇香。殊姿異態不可狀，", "丈人阿母勿悲啼，此女不是凡夫妻。恐是天仙謫人世，"]'),
('yuding-26','花非花','白居易','唐','御定全唐诗','yuding','','[]','花非花，霧非霧。夜半來，天明去。來如春夢幾多時，',24,'御定全唐詩/json/435.json','["花非花，霧非霧。夜半來，天明去。來如春夢幾多時，"]'),
('yuding-27','醉後狂言，酬贈蕭、殷二協律','白居易','唐','御定全唐诗','yuding','','[]','餘杭邑客多羈貧，其間甚者蕭與殷。天寒身上猶衣葛，',96,'御定全唐詩/json/435.json','["餘杭邑客多羈貧，其間甚者蕭與殷。天寒身上猶衣葛，", "賓客不見綈袍惠，黎庶未沾襦袴恩。此時太守自慚愧，", "吳綿細軟桂布密，柔如狐腋白似雲。勞將詩書投贈我，", "此裘非繒亦非纊，裁以法度絮以仁。刀尺鈍拙制未畢，"]'),
('yuding-28','醉歌','白居易','唐','御定全唐诗','yuding','','[]','罷胡琴，掩秦瑟，玲瓏再拜歌初畢。誰道使君不解歌，',48,'御定全唐詩/json/435.json','["罷胡琴，掩秦瑟，玲瓏再拜歌初畢。誰道使君不解歌，", "腰間紅綬系未穩，鏡裏朱顏看已失。玲瓏玲瓏奈老何，"]'),
('yuding-0','代書詩一百韻寄微之','白居易','唐','御定全唐诗','yuding','','[]','憶在貞元歲，初登典校司。身名同日授，心事一言知。',576,'御定全唐詩/json/436.json','["憶在貞元歲，初登典校司。身名同日授，心事一言知。", "肺腑都無隔，形骸兩不羈。疏狂屬年少，閒散為官卑。", "分定金蘭契，言通藥石規。交賢方汲汲，友直每偲偲。", "有月多同賞，無杯不共持。秋風拂琴匣，夜雪卷書帷。", "高上慈恩塔，幽尋皇子陂。唐昌玉蕊會，崇敬牡丹期。", "笑勸迂辛酒，閑吟短李詩。儒風愛敦質，佛理賞玄師。", "度日曾無悶，通宵靡不為。雙聲聯律句，八面對宮棋。", "往往遊三省，騰騰出九逵。寒銷直城路，春到曲江池。", "樹暖枝條弱，山晴彩翠奇。峰攢石綠點，柳宛麹塵絲。", "岸草煙鋪地，園花雪壓枝。早光紅照耀，新溜碧逶迤。", "幄幕侵堤布，盤筵占地施。征伶皆絕藝，選伎悉名姬。", "粉黛凝春態，金鈿耀水嬉。風流誇墮髻，時世鬥啼眉。", "密坐隨歡促，華尊逐勝移。香飄歌袂動，翠落舞釵遺。", "籌插紅螺碗，觥飛白玉卮。打嫌調笑易，飲訝卷波遲。", "殘席喧嘩散，歸鞍酩酊騎。酡顏烏帽側，醉袖玉鞭垂。", "紫陌傳鐘鼓，紅塵塞路岐。幾時曾暫別，何處不相隨。", "荏苒星霜換，回環節候催。兩衙多請告，三考欲成資。", "運啟千年聖，天成萬物宜。皆當少壯日，同惜盛明時。", "光景嗟虛擲，雲霄竊暗窺。攻文朝矻矻，講學夜孜孜。", "策目穿如劄，鋒毫銳若錐。繁張獲鳥網，堅守釣魚坻。", "並受夔龍薦，齊陳晁董詞。萬言經濟略，三策太平基。", "中第爭無敵，專場戰不疲。輔車排勝陣，掎角搴降旗。", "雙闕紛容衛，千僚儼等衰。恩隨紫泥降，名向白麻披。", "既在高科選，還從好爵縻。東垣君諫諍，西邑我驅馳。"]'),
('yuding-1','和鄭元及第後秋歸洛下閒居','白居易','唐','御定全唐诗','yuding','','[]','勤苦成名後，優遊得意間。玉憐同匠琢，桂恨來年攀。',72,'御定全唐詩/json/436.json','["勤苦成名後，優遊得意間。玉憐同匠琢，桂恨來年攀。", "山靜豹難隱，穀幽鶯暫還。微吟詩引步，淺酌酒開顏。", "門迥暮臨水，窗深朝對山。雲衢日相待，莫誤許身閑。"]'),
('yuding-2','與諸同年賀座主侍郎新拜太常，同宴蕭尚書亭子','白居易','唐','御定全唐诗','yuding','','[]','寵新卿典禮，會盛客徵文。不失遷鶯侶，因成賀燕群。',48,'御定全唐詩/json/436.json','["寵新卿典禮，會盛客徵文。不失遷鶯侶，因成賀燕群。", "池台晴間雪，冠蓋暮和雲。共仰曾攀處，年深桂尚熏。"]'),
('yuding-3','東都冬日會諸同年宴鄭家林亭','白居易','唐','御定全唐诗','yuding','','[]','盛時陪上第，暇日會群賢。桂折因同樹，鶯遷各異年。',72,'御定全唐詩/json/436.json','["盛時陪上第，暇日會群賢。桂折因同樹，鶯遷各異年。", "賓階紛組佩，妓席儼花鈿。促膝齊榮賤，差肩次後先。", "助歌林下水，銷酒雪中天。他日升沉者，無忘共此筵。"]'),
('yuding-4','敘德書情四十韻，上宣歙翟中丞','白居易','唐','御定全唐诗','yuding','','[]','元聖生乘運，忠賢出應期。還將稽古力，助立太平基。',480,'御定全唐詩/json/436.json','["元聖生乘運，忠賢出應期。還將稽古力，助立太平基。", "土控吳兼越，州連歙與池。山河地襟帶，軍鎮國藩維。", "廉察安江甸，澄清肅海夷。股肱分外守，耳目付中司。", "楚老歌來暮，秦人詠去思。望如時雨至，福是歲星移。", "政靜民無訟，刑行吏不欺。撝謙驚主寵，陰德畏人知。", "白玉慚溫色，朱繩讓直辭。行為時領袖，言作世蓍龜。", "盛幕招賢士，連營訓銳師。光華下鵷鷺，氣色動熊羆。", "出入麾幢引，登臨劍戟隨。好風迎解榻，美景待搴帷。", "晴野霞飛綺，春郊柳宛絲。城烏驚畫角，江雁避紅旗。", "藉草朱輪駐，攀花紫綬垂。山宜謝公屐，洲稱柳家詩。", "酒氣和芳杜，弦聲亂子規。分球齊馬首，列舞匝蛾眉。", "醉惜年光晚，歡憐日影遲。回塘排玉棹，歸路擁金羈。", "自顧龍鍾者，嘗蒙噢咻之。仰山塵不讓，涉海水難為。", "身忝鄉人薦，名因國士推。提攜增善價，拂拭長妍姿。", "射策端心術，遷喬整羽儀。幸穿楊遠葉，謬折桂高枝。", "佩德潛書帶，銘仁暗勒肌。飭躬趨館舍，拜手挹階墀。", "霄漢程雖在，風塵跡尚卑。敝衣羞布素，敗屋厭茅茨。", "養乏晨昏膳，居無伏臘資。盛時貧可恥，壯歲病堪嗤。", "擢第名方立，耽書力未疲。磨鉛重剸割，策蹇再賓士。", "相馬須憐瘦，呼鷹正及饑。扶搖重即事，會有答恩時。"]'),
('yuding-5','和渭北劉大夫借便秋遮虜，寄朝中親友','白居易','唐','御定全唐诗','yuding','','[]','巨鎮為邦屏，全材作國楨。韜鈐漢上將，文墨魯諸生。',120,'御定全唐詩/json/436.json','["巨鎮為邦屏，全材作國楨。韜鈐漢上將，文墨魯諸生。", "豹虎關西卒，金湯渭北城。寵深初受棨，威重正揚兵。", "陣占山河布，軍諳水草行。夏苗侵虎落，宵遁失蕃營。", "雲隊攢戈戟，風行卷旆旌。堠空烽火滅，氣勝鼓鼙鳴。", "胡馬辭南牧，周師罷北征。回頭問天下，何處有欃槍。"]'),
('yuding-6','題故曹王宅','白居易','唐','御定全唐诗','yuding','','[]','甲第何年置，朱門此地開。山當賓閣出，溪繞妓堂回。',72,'御定全唐詩/json/436.json','["甲第何年置，朱門此地開。山當賓閣出，溪繞妓堂回。", "覆井桐新長，陰窗竹舊栽。池荒紅菡萏，砌老綠莓苔。", "捐館梁王去，思人楚客來。西園飛蓋處，依舊月裴回。"]'),
('yuding-7','自江陵之徐州路上寄兄弟','白居易','唐','御定全唐诗','yuding','','[]','岐路南將北，離憂弟與兄。關河千里別，風雪一身行。',72,'御定全唐詩/json/436.json','["岐路南將北，離憂弟與兄。關河千里別，風雪一身行。", "夕宿勞鄉夢，晨裝慘旅情。家貧憂後事，日短念前程。", "煙雁翻寒渚，霜烏聚古城。誰憐陟岡者，西楚望南荊。"]'),
('yuding-8','酬哥舒大見贈','白居易','唐','御定全唐诗','yuding','','[]','去歲歡遊何處去，曲江西岸杏園東。花下忘歸因美景，',40,'御定全唐詩/json/436.json','["去歲歡遊何處去，曲江西岸杏園東。花下忘歸因美景，", "今日相逢愁又喜，八人分散兩人同。"]'),
('yuding-9','和談校書秋夜感懷，呈朝中親友','白居易','唐','御定全唐诗','yuding','','[]','遙夜涼風楚客悲，清砧繁漏月高時。秋霜似鬢年空長，',40,'御定全唐詩/json/436.json','["遙夜涼風楚客悲，清砧繁漏月高時。秋霜似鬢年空長，", "漢庭卿相皆知己，不薦揚雄欲薦誰。"]'),
('yuding-10','感秋寄遠','白居易','唐','御定全唐诗','yuding','','[]','惆悵時節晚，兩情千里同。離憂不散處，庭樹正秋風。',48,'御定全唐詩/json/436.json','["惆悵時節晚，兩情千里同。離憂不散處，庭樹正秋風。", "燕影動歸翼，蕙香銷故叢。佳期與芳歲，牢落兩成空。"]'),
('yuding-11','春題華陽觀','白居易','唐','御定全唐诗','yuding','','[]','帝子吹簫逐鳳凰，空留仙洞號華陽。',32,'御定全唐詩/json/436.json','["帝子吹簫逐鳳凰，空留仙洞號華陽。", "落花何處堪惆悵，頭白宮人掃影堂。"]'),
('yuding-12','秋雨中贈元九','白居易','唐','御定全唐诗','yuding','','[]','不堪紅葉青苔地，又是涼風暮雨天。',32,'御定全唐詩/json/436.json','["不堪紅葉青苔地，又是涼風暮雨天。", "莫怪獨吟秋思苦，比君校近二毛年。"]'),
('yuding-13','城東閒遊','白居易','唐','御定全唐诗','yuding','','[]','寵辱憂歡不到情，任他朝市自營營。',32,'御定全唐詩/json/436.json','["寵辱憂歡不到情，任他朝市自營營。", "獨尋秋景城東去，白鹿原頭信馬行。"]'),
('yuding-14','答韋八','白居易','唐','御定全唐诗','yuding','','[]','麗句勞相贈，佳期恨有違。早知留酒待，悔不趁花歸。',48,'御定全唐詩/json/436.json','["麗句勞相贈，佳期恨有違。早知留酒待，悔不趁花歸。", "春盡綠醅老，雨多紅萼稀。今朝如一醉，猶得及芳菲。"]'),
('yuding-15','華陽觀桃花時招李六拾遺飲','白居易','唐','御定全唐诗','yuding','','[]','華陽觀裏仙桃發，把酒看花心自知。',32,'御定全唐詩/json/436.json','["華陽觀裏仙桃發，把酒看花心自知。", "爭忍開時不同醉，明朝後日即空枝。"]'),
('yuding-16','和友人洛中春感','白居易','唐','御定全唐诗','yuding','','[]','莫悲金穀園中月，莫歎天津橋上春。',32,'御定全唐詩/json/436.json','["莫悲金穀園中月，莫歎天津橋上春。", "若學多情尋往事，人間何處不傷神。"]'),
('yuding-17','送張南簡入蜀','白居易','唐','御定全唐诗','yuding','','[]','昨日詔書下，求賢訪陸沉。無論能與否，皆起徇名心。',36,'御定全唐詩/json/436.json','["昨日詔書下，求賢訪陸沉。無論能與否，皆起徇名心。", "君獨南遊去，雲山蜀路深。"]'),
('yuding-18','寄陸補闕','白居易','唐','御定全唐诗','yuding','','[]','忽憶前年科第後，此時雞鶴暫同群。',32,'御定全唐詩/json/436.json','["忽憶前年科第後，此時雞鶴暫同群。", "秋風惆悵須吹散，雞在中庭鶴在雲。"]'),
('yuding-19','華陽觀中八月十五日夜招友玩月','白居易','唐','御定全唐诗','yuding','','[]','人道秋中明月好，欲邀同賞意如何。',32,'御定全唐詩/json/436.json','["人道秋中明月好，欲邀同賞意如何。", "華陽洞裏秋壇上，今夜清光此處多。"]'),
('yuding-20','曲江憶元九','白居易','唐','御定全唐诗','yuding','','[]','春來無伴閒遊少，行樂三分減二分。',32,'御定全唐詩/json/436.json','["春來無伴閒遊少，行樂三分減二分。", "何況今朝杏園裏，閒人逢盡不逢君。"]'),
('yuding-21','過劉三十二故宅','白居易','唐','御定全唐诗','yuding','','[]','不見劉君來近遠，門前兩度滿枝花。',32,'御定全唐詩/json/436.json','["不見劉君來近遠，門前兩度滿枝花。", "朝來惆悵宣平過，柳巷當頭第一家。"]'),
('yuding-22','下邽莊南桃花','白居易','唐','御定全唐诗','yuding','','[]','村南無限桃花發，唯我多情獨自來。',32,'御定全唐詩/json/436.json','["村南無限桃花發，唯我多情獨自來。", "日暮風吹紅滿地，無人解惜為誰開。"]'),
('yuding-23','三月三十日題慈恩寺','白居易','唐','御定全唐诗','yuding','','[]','慈恩春色今朝盡，盡日裴回倚寺門。',32,'御定全唐詩/json/436.json','["慈恩春色今朝盡，盡日裴回倚寺門。", "惆悵春歸留不得，紫藤花下漸黃昏。"]'),
('yuding-24','看惲家牡丹花戲贈李二十','白居易','唐','御定全唐诗','yuding','','[]','香勝燒蘭紅勝霞，城中最數令公家。',32,'御定全唐詩/json/436.json','["香勝燒蘭紅勝霞，城中最數令公家。", "人人散後君須看，歸到江南無此花。"]'),
('yuding-25','春中與盧四周諒華陽觀同居','白居易','唐','御定全唐诗','yuding','','[]','性情懶慢好相親，門巷蕭條稱作鄰。背燭共憐深夜月，',40,'御定全唐詩/json/436.json','["性情懶慢好相親，門巷蕭條稱作鄰。背燭共憐深夜月，", "文行如君尚憔悴，不知霄漢待何人。"]'),
('yuding-26','自城東至以詩代書，戲招李六拾遺、崔二十六先輩','白居易','唐','御定全唐诗','yuding','','[]','青門走馬趁心期，惆悵歸來已校遲。應過唐昌玉蕊後，',40,'御定全唐詩/json/436.json','["青門走馬趁心期，惆悵歸來已校遲。應過唐昌玉蕊後，", "尚殘半月芸香俸，不作歸糧作酒貲。"]'),
('yuding-27','盩厔縣北樓望山','白居易','唐','御定全唐诗','yuding','','[]','一為趨走吏，塵土不開顏。孤負平生眼，今朝始見山。',24,'御定全唐詩/json/436.json','["一為趨走吏，塵土不開顏。孤負平生眼，今朝始見山。"]'),
('yuding-28','縣西郊秋寄贈馬造','白居易','唐','御定全唐诗','yuding','','[]','紫閣峰西清渭東，野煙深處夕陽中。風荷老葉蕭條綠，',24,'御定全唐詩/json/436.json','["紫閣峰西清渭東，野煙深處夕陽中。風荷老葉蕭條綠，"]'),
('yuding-29','別韋蘇州','白居易','唐','御定全唐诗','yuding','','[]','百年愁裏過，萬感醉中來。惆悵城西別，愁眉兩不開。',24,'御定全唐詩/json/436.json','["百年愁裏過，萬感醉中來。惆悵城西別，愁眉兩不開。"]'),
('yuding-30','戲題新栽薔薇','白居易','唐','御定全唐诗','yuding','','[]','移根易地莫憔悴，野外庭前一種春。',32,'御定全唐詩/json/436.json','["移根易地莫憔悴，野外庭前一種春。", "少府無妻春寂寞，花開將爾當夫人。"]'),
('yuding-31','酬王十八、李大見招遊山','白居易','唐','御定全唐诗','yuding','','[]','自憐幽會心期阻，複愧嘉招書信頻。',32,'御定全唐詩/json/436.json','["自憐幽會心期阻，複愧嘉招書信頻。", "王事牽身去不得，滿山松雪屬他人。"]'),
('yuding-32','縣南花下醉中留劉五','白居易','唐','御定全唐诗','yuding','','[]','百歲幾回同酩酊，一年今日最芳菲。',32,'御定全唐詩/json/436.json','["百歲幾回同酩酊，一年今日最芳菲。", "願將花贈天臺女，留取劉郎到夜歸。"]'),
('yuding-33','宿楊家','白居易','唐','御定全唐诗','yuding','','[]','楊氏弟兄俱醉臥，披衣獨起下高齋。',32,'御定全唐詩/json/436.json','["楊氏弟兄俱醉臥，披衣獨起下高齋。", "夜深不語中庭立，月照藤花影上階。"]'),
('yuding-34','醉中留別楊六兄弟','白居易','唐','御定全唐诗','yuding','','[]','春初攜手春深散，無日花間不醉狂。',32,'御定全唐詩/json/436.json','["春初攜手春深散，無日花間不醉狂。", "別後何人堪共醉，猶殘十日好風光。"]'),
('yuding-35','醉中歸盩厔','白居易','唐','御定全唐诗','yuding','','[]','金光門外昆明路，半醉騰騰信馬回。',32,'御定全唐詩/json/436.json','["金光門外昆明路，半醉騰騰信馬回。", "數日非關王事系，牡丹花盡始歸來。"]'),
('yuding-36','游雲居寺，贈穆三十六地主','白居易','唐','御定全唐诗','yuding','','[]','亂峰深處雲居路，共蹋花行獨惜春。',32,'御定全唐詩/json/436.json','["亂峰深處雲居路，共蹋花行獨惜春。", "勝地本來無定主，大都山屬愛山人。"]'),
('yuding-37','和王十八薔薇澗花時有懷蕭侍禦兼見贈','白居易','唐','御定全唐诗','yuding','','[]','霄漢風塵俱是系，薔薇花委故山深。',32,'御定全唐詩/json/436.json','["霄漢風塵俱是系，薔薇花委故山深。", "憐君獨向澗中立，一把紅芳三處心。"]'),
('yuding-38','再因公事到駱口驛','白居易','唐','御定全唐诗','yuding','','[]','今年到時夏雲白，去年來時秋樹紅。',32,'御定全唐詩/json/436.json','["今年到時夏雲白，去年來時秋樹紅。", "兩度見山心有愧，皆因王事到山中。"]'),
('yuding-39','期李二十文略、王十八質夫不至，獨宿仙遊寺','白居易','唐','御定全唐诗','yuding','','[]','文略也從牽吏役，質夫何故戀囂塵。',32,'御定全唐詩/json/436.json','["文略也從牽吏役，質夫何故戀囂塵。", "始知解愛山中宿，千萬人中無一人。"]'),
('yuding-40','酬趙秀才贈新登科諸先輩','白居易','唐','御定全唐诗','yuding','','[]','莫羨蓬萊鸞鶴侶，道成羽翼自生身。',32,'御定全唐詩/json/436.json','["莫羨蓬萊鸞鶴侶，道成羽翼自生身。", "君看名在丹台者，儘是人間修道人。"]'),
('yuding-41','過天門街','白居易','唐','御定全唐诗','yuding','','[]','雪盡終南又欲春，遙憐翠色對紅塵。',32,'御定全唐詩/json/436.json','["雪盡終南又欲春，遙憐翠色對紅塵。", "千車萬馬九衢上，回首看山無一人。"]'),
('yuding-42','惜玉蕊花，有懷集賢王校書起','白居易','唐','御定全唐诗','yuding','','[]','芳意將闌風又吹，白雲離葉雪辭枝。',32,'御定全唐詩/json/436.json','["芳意將闌風又吹，白雲離葉雪辭枝。", "集賢讎校無閑日，落盡瑤花君不知。"]'),
('yuding-43','春送盧秀才下第游太原謁嚴尚書','白居易','唐','御定全唐诗','yuding','','[]','未將時會合，且與俗浮沉。鴻養青冥翮，蛟潛雲雨心。',48,'御定全唐詩/json/436.json','["未將時會合，且與俗浮沉。鴻養青冥翮，蛟潛雲雨心。", "煙郊春別遠，風磧暮程深。墨客投何處，並州舊翰林。"]'),
('yuding-44','長安送柳大東歸','白居易','唐','御定全唐诗','yuding','','[]','白社羈遊伴，青門遠別離。浮名相引住，歸路不同歸。',24,'御定全唐詩/json/436.json','["白社羈遊伴，青門遠別離。浮名相引住，歸路不同歸。"]'),
('yuding-45','送文暢上人東遊','白居易','唐','御定全唐诗','yuding','','[]','得道即無著，隨緣西複東。貌依年臘老，心到夜禪空。',48,'御定全唐詩/json/436.json','["得道即無著，隨緣西複東。貌依年臘老，心到夜禪空。", "山宿馴溪虎，江行濾水蟲。悠悠塵客思，春滿碧雲中。"]'),
('yuding-46','社日關路作','白居易','唐','御定全唐诗','yuding','','[]','晚景函關路，涼風社日天。青岩新有燕，紅樹欲無蟬。',48,'御定全唐詩/json/436.json','["晚景函關路，涼風社日天。青岩新有燕，紅樹欲無蟬。", "愁立驛樓上，厭行官堠前。蕭條秋興苦，漸近二毛年。"]'),
('yuding-47','重到毓村宅有感','白居易','唐','御定全唐诗','yuding','','[]','欲入中門淚滿巾，庭花無主兩回春。',32,'御定全唐詩/json/436.json','["欲入中門淚滿巾，庭花無主兩回春。", "軒窗簾幕皆依舊，只是堂前欠一人。"]'),
('yuding-48','亂後過流溝寺','白居易','唐','御定全唐诗','yuding','','[]','九月徐州新戰後，悲風殺氣滿山河。',32,'御定全唐詩/json/436.json','["九月徐州新戰後，悲風殺氣滿山河。", "唯有流溝山下寺，門前依舊白雲多。"]'),
('yuding-49','歎發落','白居易','唐','御定全唐诗','yuding','','[]','多病多愁心自知，行年未老發先衰。',32,'御定全唐詩/json/436.json','["多病多愁心自知，行年未老發先衰。", "隨梳落去何須惜，不落終須變作絲。"]'),
('yuding-50','留別吳七正字','白居易','唐','御定全唐诗','yuding','','[]','成名共記甲科上，署吏同登芸閣間。',32,'御定全唐詩/json/436.json','["成名共記甲科上，署吏同登芸閣間。", "唯是塵心殊道性，秋蓬常轉水長閑。"]'),
('yuding-51','除夜宿洺州','白居易','唐','御定全唐诗','yuding','','[]','家寄關西住，身為河北遊。蕭條歲除夜，旅泊在洺州。',24,'御定全唐詩/json/436.json','["家寄關西住，身為河北遊。蕭條歲除夜，旅泊在洺州。"]'),
('yuding-52','邯鄲冬至夜思家','白居易','唐','御定全唐诗','yuding','','[]','邯鄲驛裏逢冬至，抱膝燈前影伴身。',32,'御定全唐詩/json/436.json','["邯鄲驛裏逢冬至，抱膝燈前影伴身。", "想得家中夜深坐，還應說著遠行人。"]'),
('yuding-53','冬至夜懷湘靈','白居易','唐','御定全唐诗','yuding','','[]','豔質無由見，寒衾不可親。何堪最長夜，俱作獨眠人。',24,'御定全唐詩/json/436.json','["豔質無由見，寒衾不可親。何堪最長夜，俱作獨眠人。"]'),
('yuding-54','感故張僕射諸妓','白居易','唐','御定全唐诗','yuding','','[]','黃金不惜買蛾眉，揀得如花三四枝。',32,'御定全唐詩/json/436.json','["黃金不惜買蛾眉，揀得如花三四枝。", "歌舞教成心力盡，一朝身去不相隨。"]'),
('yuding-55','游仙遊山','白居易','唐','御定全唐诗','yuding','','[]','暗將心地出人間，五六年來人怪閑。',32,'御定全唐詩/json/436.json','["暗將心地出人間，五六年來人怪閑。", "自嫌戀著未全盡，猶愛雲泉多在山。"]'),
('yuding-56','見尹公亮新詩，偶贈絕句','白居易','唐','御定全唐诗','yuding','','[]','袖裏新詩十首餘，吟看句句是瓊琚。',32,'御定全唐詩/json/436.json','["袖裏新詩十首餘，吟看句句是瓊琚。", "如何持此將幹謁，不及公卿一字書。"]'),
('yuding-57','長安閒居','白居易','唐','御定全唐诗','yuding','','[]','風竹松煙晝掩關，意中長似在深山。',32,'御定全唐詩/json/436.json','["風竹松煙晝掩關，意中長似在深山。", "無人不怪長安住，何獨朝朝暮暮間。"]'),
('yuding-58','早春獨游曲江','白居易','唐','御定全唐诗','yuding','','[]','散職無羈束，羸驂少送迎。朝從直城出，春傍曲江行。',120,'御定全唐詩/json/436.json','["散職無羈束，羸驂少送迎。朝從直城出，春傍曲江行。", "風起池東暖，雲開山北晴。冰銷泉脈動，雪盡草芽生。", "露杏紅初坼，煙楊綠未成。影遲新度雁，聲澀欲啼鶯。", "閑地心俱靜，韶光眼共明。酒狂憐性逸，藥效喜身輕。", "慵慢疏人事，幽棲逐野情。回看芸閣笑，不似有浮名。"]'),
('yuding-59','秘書省中憶舊山','白居易','唐','御定全唐诗','yuding','','[]','厭從薄宦校青簡，悔別故山思白雲。',32,'御定全唐詩/json/436.json','["厭從薄宦校青簡，悔別故山思白雲。", "猶喜蘭台非傲吏，歸時應免動移文。"]'),
('yuding-60','涼夜有懷','白居易','唐','御定全唐诗','yuding','','[]','清風吹枕席，白露濕衣裳。好是相親夜，漏遲天氣涼。',24,'御定全唐詩/json/436.json','["清風吹枕席，白露濕衣裳。好是相親夜，漏遲天氣涼。"]'),
('yuding-61','送武士曹歸蜀','白居易','唐','御定全唐诗','yuding','','[]','花落鳥嚶嚶，南歸稱野情。月宜秦嶺宿，春好蜀江行。',48,'御定全唐詩/json/436.json','["花落鳥嚶嚶，南歸稱野情。月宜秦嶺宿，春好蜀江行。", "鄉路通雲棧，郊扉近錦城。烏台陟岡送，人羨別時榮。"]'),
('yuding-62','江南送北客，因憑寄徐州兄弟書','白居易','唐','御定全唐诗','yuding','','[]','故園望斷欲何如，楚水吳山萬里餘。',32,'御定全唐詩/json/436.json','["故園望斷欲何如，楚水吳山萬里餘。", "今日因君訪兄弟，數行鄉淚一封書。"]'),
('yuding-63','賦得古原草送別','白居易','唐','御定全唐诗','yuding','','[]','離離原上草，一歲一枯榮。野火燒不盡，春風吹又生。',48,'御定全唐詩/json/436.json','["離離原上草，一歲一枯榮。野火燒不盡，春風吹又生。", "遠芳侵古道，晴翠接荒城。又送王孫去，萋萋滿別情。"]'),
('yuding-64','夜哭李夷道','白居易','唐','御定全唐诗','yuding','','[]','逝者絕影響，空庭朝複昏。家人哀臨畢，夜鎖壽堂門。',40,'御定全唐詩/json/436.json','["逝者絕影響，空庭朝複昏。家人哀臨畢，夜鎖壽堂門。", "無妻無子何人葬，空見銘旌向月翻。"]'),
('yuding-65','病中作','白居易','唐','御定全唐诗','yuding','','[]','久為勞生事，不學攝生道。年少已多病，此身豈堪老。',24,'御定全唐詩/json/436.json','["久為勞生事，不學攝生道。年少已多病，此身豈堪老。"]'),
('yuding-66','秋江晚泊','白居易','唐','御定全唐诗','yuding','','[]','扁舟泊雲島，倚棹念鄉國。四望不見人，煙江澹秋色。',36,'御定全唐詩/json/436.json','["扁舟泊雲島，倚棹念鄉國。四望不見人，煙江澹秋色。", "客心貧易動，日入愁未息。"]'),
('yuding-67','旅次景空寺宿幽上人院','白居易','唐','御定全唐诗','yuding','','[]','不與人境接，寺門開向山。暮鐘寒鳥聚，秋雨病僧閑。',48,'御定全唐詩/json/436.json','["不與人境接，寺門開向山。暮鐘寒鳥聚，秋雨病僧閑。", "月隱雲樹外，螢飛廊宇間。幸投花界宿，暫得靜心顏。"]'),
('yuding-68','長安正月十五日','白居易','唐','御定全唐诗','yuding','','[]','喧喧車騎帝王州，羈病無心逐勝遊。',32,'御定全唐詩/json/436.json','["喧喧車騎帝王州，羈病無心逐勝遊。", "明月春風三五夜，萬人行樂一人愁。"]'),
('yuding-69','過高將軍墓','白居易','唐','御定全唐诗','yuding','','[]','原上新墳委一身，城中舊宅有何人。妓堂賓閣無歸日，',24,'御定全唐詩/json/436.json','["原上新墳委一身，城中舊宅有何人。妓堂賓閣無歸日，"]'),
('yuding-70','寒食臥病','白居易','唐','御定全唐诗','yuding','','[]','病逢佳節長歎息，春雨濛濛榆柳色。羸坐全非舊日容，',24,'御定全唐詩/json/436.json','["病逢佳節長歎息，春雨濛濛榆柳色。羸坐全非舊日容，"]'),
('yuding-71','宿桐廬館，同崔存度醉後作','白居易','唐','御定全唐诗','yuding','','[]','江海漂漂共旅遊，一尊相勸散窮愁。',32,'御定全唐詩/json/436.json','["江海漂漂共旅遊，一尊相勸散窮愁。", "夜深醒後愁還在，雨滴梧桐山館秋。"]'),
('yuding-72','江樓望歸','白居易','唐','御定全唐诗','yuding','','[]','滿眼雲水色，月明樓上人。旅愁春入越，鄉夢夜歸秦。',48,'御定全唐詩/json/436.json','["滿眼雲水色，月明樓上人。旅愁春入越，鄉夢夜歸秦。", "道路通荒服，田園隔虜塵。悠悠滄海畔，十載避黃巾。"]'),
('yuding-73','除夜寄弟妹','白居易','唐','御定全唐诗','yuding','','[]','感時思弟妹，不寐百憂生。萬里經年別，孤燈此夜情。',48,'御定全唐詩/json/436.json','["感時思弟妹，不寐百憂生。萬里經年別，孤燈此夜情。", "病容非舊日，歸思逼新正。早晚重歡會，羈離各長成。"]'),
('yuding-74','寒食月夜','白居易','唐','御定全唐诗','yuding','','[]','風香露重梨花濕，草舍無燈愁未入。',32,'御定全唐詩/json/436.json','["風香露重梨花濕，草舍無燈愁未入。", "南鄰北裏歌吹時，獨倚柴門月中立。"]'),
('yuding-75','感芍藥花，寄正一上人','白居易','唐','御定全唐诗','yuding','','[]','今日階前紅芍藥，幾花欲老幾花新。開時不解比色相，',24,'御定全唐詩/json/436.json','["今日階前紅芍藥，幾花欲老幾花新。開時不解比色相，"]'),
('yuding-76','晚秋閒居','白居易','唐','御定全唐诗','yuding','','[]','地僻門深少送迎，披衣閑坐養幽情。',32,'御定全唐詩/json/436.json','["地僻門深少送迎，披衣閑坐養幽情。", "秋庭不掃攜藤杖，閑蹋梧桐黃葉行。"]'),
('yuding-77','秋暮郊居書懷','白居易','唐','御定全唐诗','yuding','','[]','郊居人事少，晝臥對林巒。窮巷厭多雨，貧家愁早寒。',48,'御定全唐詩/json/436.json','["郊居人事少，晝臥對林巒。窮巷厭多雨，貧家愁早寒。", "葛衣秋未換，書卷病仍看。若問生涯計，前溪一釣竿。"]'),
('yuding-78','為薛台悼亡','白居易','唐','御定全唐诗','yuding','','[]','半死梧桐老病身，重泉一念一傷神。',32,'御定全唐詩/json/436.json','["半死梧桐老病身，重泉一念一傷神。", "手攜稚子夜歸院，月冷空房不見人。"]'),
('yuding-79','途中寒食','白居易','唐','御定全唐诗','yuding','','[]','路旁寒食行人盡，獨佔春愁在路旁。',32,'御定全唐詩/json/436.json','["路旁寒食行人盡，獨佔春愁在路旁。", "馬上垂鞭愁不語，風吹百草野田香。"]'),
('yuding-80','題流溝寺古松','白居易','唐','御定全唐诗','yuding','','[]','煙葉蔥蘢蒼麈尾，霜皮剝落紫龍鱗。',32,'御定全唐詩/json/436.json','["煙葉蔥蘢蒼麈尾，霜皮剝落紫龍鱗。", "欲知松老看塵壁，死卻題詩幾許人。"]'),
('yuding-81','感月悲逝者','白居易','唐','御定全唐诗','yuding','','[]','存亡感月一潸然，月色今宵似往年。',32,'御定全唐詩/json/436.json','["存亡感月一潸然，月色今宵似往年。", "何處曾經同望月，櫻桃樹下後堂前。"]'),
('yuding-82','代鄰叟言懷','白居易','唐','御定全唐诗','yuding','','[]','人生何事心無定，宿昔如今意不同。',32,'御定全唐詩/json/436.json','["人生何事心無定，宿昔如今意不同。", "宿昔愁身不得老，如今恨作白頭翁。"]'),
('yuding-83','自河南經亂關內阻飢兄弟離散各在一處因望月有感聊書所懷寄上浮梁大兄於潛七兄烏江十五兄兼示符離及下邽弟妹','白居易','唐','御定全唐诗','yuding','','[]','時難年饑世業空，弟兄羈旅各西東。田園寥落干戈後，',40,'御定全唐詩/json/436.json','["時難年饑世業空，弟兄羈旅各西東。田園寥落干戈後，", "共看明月應垂淚，一夜鄉心五處同。"]'),
('yuding-84','長安早春旅懷','白居易','唐','御定全唐诗','yuding','','[]','軒車歌吹喧都邑，中有一人向隅立。夜深明月捲簾愁，',40,'御定全唐詩/json/436.json','["軒車歌吹喧都邑，中有一人向隅立。夜深明月捲簾愁，", "此生知負少年春，不展愁眉欲三十。"]'),
('yuding-85','寒閨夜','白居易','唐','御定全唐诗','yuding','','[]','夜半衾裯冷，孤眠懶未能。籠香銷盡火，巾淚滴成冰。',36,'御定全唐詩/json/436.json','["夜半衾裯冷，孤眠懶未能。籠香銷盡火，巾淚滴成冰。", "為惜影相伴，通宵不滅燈。"]'),
('yuding-86','寄湘靈','白居易','唐','御定全唐诗','yuding','','[]','淚眼淩寒凍不流，每經高處即回頭。',32,'御定全唐詩/json/436.json','["淚眼淩寒凍不流，每經高處即回頭。", "遙知別後西樓上，應憑欄幹獨自愁。"]'),
('yuding-87','冬至宿楊梅館','白居易','唐','御定全唐诗','yuding','','[]','十一月中長至夜，三千裏外遠行人。',32,'御定全唐詩/json/436.json','["十一月中長至夜，三千裏外遠行人。", "若為獨宿楊梅館，冷枕單床一病身。"]'),
('yuding-88','臨江送夏瞻','白居易','唐','御定全唐诗','yuding','','[]','悲君老別我沾巾，七十無家萬里身。',32,'御定全唐詩/json/436.json','["悲君老別我沾巾，七十無家萬里身。", "愁見舟行風又起，白頭浪裏白頭人。"]'),
('yuding-89','冬夜示敏巢','白居易','唐','御定全唐诗','yuding','','[]','爐火欲銷燈欲盡，夜長相對百憂生。',32,'御定全唐詩/json/436.json','["爐火欲銷燈欲盡，夜長相對百憂生。", "他時諸處重相見，莫忘今宵燈下情。"]'),
('yuding-90','客中守歲','白居易','唐','御定全唐诗','yuding','','[]','守歲尊無酒，思鄉淚滿巾。始知為客苦，不及在家貧。',48,'御定全唐詩/json/436.json','["守歲尊無酒，思鄉淚滿巾。始知為客苦，不及在家貧。", "畏老偏驚節，防愁預惡春。故園今夜裏，應念未歸人。"]'),
('yuding-91','問淮水','白居易','唐','御定全唐诗','yuding','','[]','自嗟名利客，擾擾在人間。何事長淮水，東流亦不閑。',24,'御定全唐詩/json/436.json','["自嗟名利客，擾擾在人間。何事長淮水，東流亦不閑。"]'),
('yuding-92','宿樟亭驛','白居易','唐','御定全唐诗','yuding','','[]','夜半樟亭驛，愁人起望鄉。月明何所見，潮水白茫茫。',24,'御定全唐詩/json/436.json','["夜半樟亭驛，愁人起望鄉。月明何所見，潮水白茫茫。"]'),
('yuding-93','及第後憶舊山','白居易','唐','御定全唐诗','yuding','','[]','偶獻子虛登上第，卻吟招隱憶中林。',32,'御定全唐詩/json/436.json','["偶獻子虛登上第，卻吟招隱憶中林。", "春蘿秋桂莫惆悵，縱有浮名不系心。"]'),
('yuding-94','題李次雲窗竹','白居易','唐','御定全唐诗','yuding','','[]','不用裁為鳴鳳管，不須截作釣魚竿。',32,'御定全唐詩/json/436.json','["不用裁為鳴鳳管，不須截作釣魚竿。", "千花百草凋零後，留向紛紛雪裏看。"]'),
('yuding-95','花下自勸酒','白居易','唐','御定全唐诗','yuding','','[]','酒盞酌來須滿滿，花枝看即落紛紛。',32,'御定全唐詩/json/436.json','["酒盞酌來須滿滿，花枝看即落紛紛。", "莫言三十是年少，百歲三分已一分。"]'),
('yuding-96','題李十一東亭','白居易','唐','御定全唐诗','yuding','','[]','相思夕上松台立，蛩思蟬聲滿耳秋。',32,'御定全唐詩/json/436.json','["相思夕上松台立，蛩思蟬聲滿耳秋。", "惆悵東亭風月好，主人今夜在鄜州。"]'),
('yuding-97','春村','白居易','唐','御定全唐诗','yuding','','[]','二月村園暖，桑間戴勝飛。農夫舂舊谷，蠶妾搗新衣。',48,'御定全唐詩/json/436.json','["二月村園暖，桑間戴勝飛。農夫舂舊谷，蠶妾搗新衣。", "牛馬因風遠，雞豚過社稀。黃昏林下路，鼓笛賽神歸。"]'),
('yuding-98','題施山人野居','白居易','唐','御定全唐诗','yuding','','[]','得道應無著，謀生亦不妨。春泥秧稻暖，夜火焙茶香。',48,'御定全唐詩/json/436.json','["得道應無著，謀生亦不妨。春泥秧稻暖，夜火焙茶香。", "水巷風塵少，松齋日月長。高閑真是貴，何處覓侯王。"]'),
('yuding-0','翰林中送獨孤二十七起居罷職出院','白居易','唐','御定全唐诗','yuding','','[]','碧落留雲住，青冥放鶴還。銀台向南路，從此到人間。',24,'御定全唐詩/json/437.json','["碧落留雲住，青冥放鶴還。銀台向南路，從此到人間。"]'),
('yuding-1','重尋杏園','白居易','唐','御定全唐诗','yuding','','[]','忽憶芳時頻酩酊，卻尋醉處重裴回。',32,'御定全唐詩/json/437.json','["忽憶芳時頻酩酊，卻尋醉處重裴回。", "杏花結子春深後，誰解多情又獨來。"]'),
('yuding-2','曲江獨行','白居易','唐','御定全唐诗','yuding','','[]','獨來獨去何人識，廄馬朝衣野客心。',32,'御定全唐詩/json/437.json','["獨來獨去何人識，廄馬朝衣野客心。", "閑愛無風水邊坐，楊花不動樹陰陰。"]'),
('yuding-3','同李十一醉憶元九','白居易','唐','御定全唐诗','yuding','','[]','花時同醉破春愁，醉折花枝當酒籌。',32,'御定全唐詩/json/437.json','["花時同醉破春愁，醉折花枝當酒籌。", "忽憶故人天際去，計程今日到涼州。"]'),
('yuding-4','同錢員外題絕糧僧巨川','白居易','唐','御定全唐诗','yuding','','[]','三十年來坐對山，唯將無事化人間。',32,'御定全唐詩/json/437.json','["三十年來坐對山，唯將無事化人間。", "齋時往往聞鐘笑，一食何如不食閑。"]'),
('yuding-5','絕句代書贈錢員外','白居易','唐','御定全唐诗','yuding','','[]','欲尋秋景閑行去，君病多慵我興孤。',32,'御定全唐詩/json/437.json','["欲尋秋景閑行去，君病多慵我興孤。", "可惜今朝山最好，強能騎馬出來無。"]'),
('yuding-6','晚秋有懷鄭中舊隱','白居易','唐','御定全唐诗','yuding','','[]','天高風嫋嫋，鄉思繞關河。寥落歸山夢，殷勤采蕨歌。',72,'御定全唐詩/json/437.json','["天高風嫋嫋，鄉思繞關河。寥落歸山夢，殷勤采蕨歌。", "病添心寂寞，愁入鬢蹉跎。晚樹蟬鳴少，秋階日上多。", "長閑羨雲鶴，久別愧煙蘿。其奈丹墀上，君恩未報何。"]'),
('yuding-7','禁中九日對菊花酒憶元九','白居易','唐','御定全唐诗','yuding','','[]','賜酒盈杯誰共持，宮花滿把獨相思。',32,'御定全唐詩/json/437.json','["賜酒盈杯誰共持，宮花滿把獨相思。", "相思只傍花邊立，盡日吟君詠菊詩。"]'),
('yuding-8','送王十八歸山，寄題仙遊寺','白居易','唐','御定全唐诗','yuding','','[]','曾于太白峰前住，數到仙遊寺裏來。黑水澄時潭底出，',40,'御定全唐詩/json/437.json','["曾于太白峰前住，數到仙遊寺裏來。黑水澄時潭底出，", "惆悵舊遊那複到，菊花時節羨君回。"]'),
('yuding-9','答張籍，因以代書','白居易','唐','御定全唐诗','yuding','','[]','憐君馬瘦衣裘薄，許到江東訪鄙夫。',32,'御定全唐詩/json/437.json','["憐君馬瘦衣裘薄，許到江東訪鄙夫。", "今日正閑天又暖，可能扶病暫來無。"]'),
('yuding-10','曲江早春','白居易','唐','御定全唐诗','yuding','','[]','曲江柳條漸無力，杏園伯勞初有聲。',32,'御定全唐詩/json/437.json','["曲江柳條漸無力，杏園伯勞初有聲。", "可憐春淺遊人少，好傍池邊下馬行。"]'),
('yuding-11','見元九悼亡詩，因以此寄','白居易','唐','御定全唐诗','yuding','','[]','夜淚暗銷明月幌，春腸遙斷牡丹庭。',32,'御定全唐詩/json/437.json','["夜淚暗銷明月幌，春腸遙斷牡丹庭。", "人間此病治無藥，唯有楞伽四卷經。"]'),
('yuding-12','寒食夜','白居易','唐','御定全唐诗','yuding','','[]','無月無燈寒食夜，夜深猶立暗花前。',32,'御定全唐詩/json/437.json','["無月無燈寒食夜，夜深猶立暗花前。", "忽因時節驚年幾，四十如今欠一年。"]'),
('yuding-13','杏園花落時招錢員外同醉','白居易','唐','御定全唐诗','yuding','','[]','花園欲去去應遲，正是風吹狼藉時。',32,'御定全唐詩/json/437.json','["花園欲去去應遲，正是風吹狼藉時。", "近西數樹猶堪醉，半落春風半在枝。"]'),
('yuding-14','重題西明寺牡丹','白居易','唐','御定全唐诗','yuding','','[]','往年君向東都去，曾歎花時君未回。今年況作江陵別，',24,'御定全唐詩/json/437.json','["往年君向東都去，曾歎花時君未回。今年況作江陵別，"]'),
('yuding-15','同錢員外禁中夜直','白居易','唐','御定全唐诗','yuding','','[]','宮漏三聲知半夜，好風涼月滿松筠。',32,'御定全唐詩/json/437.json','["宮漏三聲知半夜，好風涼月滿松筠。", "此時閑坐寂無語，藥樹影中唯兩人。"]'),
('yuding-16','禁中夜作，書與元九','白居易','唐','御定全唐诗','yuding','','[]','心緒萬端書兩紙，欲封重讀意遲遲。',32,'御定全唐詩/json/437.json','["心緒萬端書兩紙，欲封重讀意遲遲。", "五聲宮漏初鳴夜，一點窗燈欲滅時。"]'),
('yuding-17','八月十五日夜禁中獨直，對月憶元九','白居易','唐','御定全唐诗','yuding','','[]','銀台金闕夕沉沉，獨宿相思在翰林。三五夜中新月色，',40,'御定全唐詩/json/437.json','["銀台金闕夕沉沉，獨宿相思在翰林。三五夜中新月色，", "猶恐清光不同見，江陵卑濕足秋陰。"]'),
('yuding-18','寄陳式五兄','白居易','唐','御定全唐诗','yuding','','[]','年來白髮兩三莖，憶別君時髭未生。',32,'御定全唐詩/json/437.json','["年來白髮兩三莖，憶別君時髭未生。", "惆悵料君應滿鬢，當初是我十年兄。"]'),
('yuding-19','庾順之以紫霞綺遠贈，以詩答之','白居易','唐','御定全唐诗','yuding','','[]','千里故人心鄭重，一端香綺紫氛氳。開緘日映晚霞色，',40,'御定全唐詩/json/437.json','["千里故人心鄭重，一端香綺紫氛氳。開緘日映晚霞色，", "不如縫作合歡被，寤寐相思如對君。"]'),
('yuding-20','送元八歸鳳翔','白居易','唐','御定全唐诗','yuding','','[]','莫道岐州三日程，其如風雪一身行。',32,'御定全唐詩/json/437.json','["莫道岐州三日程，其如風雪一身行。", "與君況是經年別，暫到城來又出城。"]'),
('yuding-21','雨雪放朝，因懷微之','白居易','唐','御定全唐诗','yuding','','[]','歸騎紛紛滿九衢，放朝三日為泥塗。',32,'御定全唐詩/json/437.json','["歸騎紛紛滿九衢，放朝三日為泥塗。", "不知雨雪江陵府，今日排衙得免無。"]'),
('yuding-22','詠懷','白居易','唐','御定全唐诗','yuding','','[]','歲去年來塵土中，眼看變作白頭翁。',32,'御定全唐詩/json/437.json','["歲去年來塵土中，眼看變作白頭翁。", "如何辦得歸山計，兩頃村田一畝宮。"]'),
('yuding-23','聞微之江陵臥病以大通中散碧腴垂雲膏寄之因題四韻','白居易','唐','御定全唐诗','yuding','','[]','已題一帖紅消散，又封一合碧雲英。憑人寄向江陵去，',40,'御定全唐詩/json/437.json','["已題一帖紅消散，又封一合碧雲英。憑人寄向江陵去，", "到時想得君拈得，枕上開看眼暫明。"]'),
('yuding-24','酬錢員外雪中見寄','白居易','唐','御定全唐诗','yuding','','[]','松雪無塵小院寒，閉門不似住長安。',32,'御定全唐詩/json/437.json','["松雪無塵小院寒，閉門不似住長安。", "煩君想我看心坐，報導心空無可看。"]'),
('yuding-25','重酬錢員外','白居易','唐','御定全唐诗','yuding','','[]','雪中重寄雪山偈，問答殷勤四句中。',32,'御定全唐詩/json/437.json','["雪中重寄雪山偈，問答殷勤四句中。", "本立空名緣破妄，若能無妄亦無空。"]'),
('yuding-26','獨酌憶微之','白居易','唐','御定全唐诗','yuding','','[]','獨酌花前醉憶君，與君春別又逢春。',32,'御定全唐詩/json/437.json','["獨酌花前醉憶君，與君春別又逢春。", "惆悵銀盃來處重，不曾盛酒勸閒人。"]'),
('yuding-27','微之宅殘牡丹','白居易','唐','御定全唐诗','yuding','','[]','殘紅零落無人賞，雨打風摧花不全。',32,'御定全唐詩/json/437.json','["殘紅零落無人賞，雨打風摧花不全。", "諸處見時猶悵望，況當元九小亭前。"]'),
('yuding-28','新磨鏡','白居易','唐','御定全唐诗','yuding','','[]','衰容常晚櫛，秋鏡偶新磨。一與清光對，方知白髮多。',48,'御定全唐詩/json/437.json','["衰容常晚櫛，秋鏡偶新磨。一與清光對，方知白髮多。", "鬢毛從幻化，心地付頭陀。任意渾成雪，其如似夢何。"]'),
('yuding-29','感發落','白居易','唐','御定全唐诗','yuding','','[]','昔日愁頭白，誰知未白衰。眼看應落盡，無可變成絲。',24,'御定全唐詩/json/437.json','["昔日愁頭白，誰知未白衰。眼看應落盡，無可變成絲。"]'),
('yuding-30','八月十五日夜聞崔大員外翰林獨直對酒玩月因懷禁中清景偶題是詩','白居易','唐','御定全唐诗','yuding','','[]','秋月高懸空碧外，仙郎靜玩禁闈間。歲中唯有今宵好，',40,'御定全唐詩/json/437.json','["秋月高懸空碧外，仙郎靜玩禁闈間。歲中唯有今宵好，", "遙聞獨醉還惆悵，不見金波照玉山。"]'),
('yuding-31','酬王十八見寄','白居易','唐','御定全唐诗','yuding','','[]','秋思太白峰頭雪，晴憶仙遊洞口雲。',32,'御定全唐詩/json/437.json','["秋思太白峰頭雪，晴憶仙遊洞口雲。", "未報皇恩歸未得，慚君為寄北山文。"]'),
('yuding-32','立春日酬錢員外曲江同行見贈','白居易','唐','御定全唐诗','yuding','','[]','下直遇春日，垂鞭出禁闈。兩人攜手語，十裏看山歸。',60,'御定全唐詩/json/437.json','["下直遇春日，垂鞭出禁闈。兩人攜手語，十裏看山歸。", "柳色早黃淺，水文新綠微。風光向晚好，車馬近南稀。", "機盡笑相顧，不驚鷗鷺飛。"]'),
('yuding-33','和錢員外青龍寺上方望舊山','白居易','唐','御定全唐诗','yuding','','[]','舊峰松雪舊溪雲，悵望今朝遙屬君。',32,'御定全唐詩/json/437.json','["舊峰松雪舊溪雲，悵望今朝遙屬君。", "共道使臣非俗吏，南山莫動北山文。"]'),
('yuding-34','宴周皓大夫光福宅','白居易','唐','御定全唐诗','yuding','','[]','何處風光最可憐，妓堂階下砌台前。軒車擁路光照地，',40,'御定全唐詩/json/437.json','["何處風光最可憐，妓堂階下砌台前。軒車擁路光照地，", "野人不敢求他事，唯借泉聲伴醉眠。"]'),
('yuding-35','晚秋夜','白居易','唐','御定全唐诗','yuding','','[]','碧空溶溶月華靜，月裏愁人吊孤影。花開殘菊傍疏籬，',40,'御定全唐詩/json/437.json','["碧空溶溶月華靜，月裏愁人吊孤影。花開殘菊傍疏籬，", "凝情不語空所思，風吹白露衣裳冷。"]'),
('yuding-36','惜牡丹花二首','白居易','唐','御定全唐诗','yuding','','[]','惆悵階前紅牡丹，晚來唯有兩枝殘。',64,'御定全唐詩/json/437.json','["惆悵階前紅牡丹，晚來唯有兩枝殘。", "明朝風起應吹盡，夜惜衰紅把火看。", "寂寞萎紅低向雨，離披破豔散隨風。", "晴明落地猶惆悵，何況飄零泥土中。"]'),
('yuding-37','答元奉禮同宿見贈','白居易','唐','御定全唐诗','yuding','','[]','相逢俱歎不閑身，直日常多齋日頻。',32,'御定全唐詩/json/437.json','["相逢俱歎不閑身，直日常多齋日頻。", "曉鼓一聲分散去，明朝風景屬何人。"]'),
('yuding-38','答馬侍禦見贈','白居易','唐','御定全唐诗','yuding','','[]','謬入金門侍玉除，煩君問我意何如。蟠木詎堪明主用，',40,'御定全唐詩/json/437.json','["謬入金門侍玉除，煩君問我意何如。蟠木詎堪明主用，", "淺薄求賢思自代，嵇康莫寄絕交書。"]'),
('yuding-39','上巳日恩賜曲江宴會即事','白居易','唐','御定全唐诗','yuding','','[]','賜歡仍許醉，此會興如何。翰苑主恩重，曲江春意多。',48,'御定全唐詩/json/437.json','["賜歡仍許醉，此會興如何。翰苑主恩重，曲江春意多。", "花低羞豔妓，鶯散讓清歌。共道升平樂，元和勝永和。"]'),
('yuding-40','夜惜禁中桃花，因懷錢員外','白居易','唐','御定全唐诗','yuding','','[]','前日歸時花正紅，今夜宿時枝半空。',32,'御定全唐詩/json/437.json','["前日歸時花正紅，今夜宿時枝半空。", "坐惜殘芳君不見，風吹狼藉月明中。"]'),
('yuding-41','和錢員外早冬玩禁中新菊','白居易','唐','御定全唐诗','yuding','','[]','禁署寒氣遲，孟冬菊初坼。新黃間繁綠，爛若金照碧。',120,'御定全唐詩/json/437.json','["禁署寒氣遲，孟冬菊初坼。新黃間繁綠，爛若金照碧。", "仙郎小隱日，心似陶彭澤。秋憐潭上看，日慣籬邊摘。", "今來此地賞，野意潛自適。金馬門內花，玉山峰下客。", "寒芳引清句，吟玩煙景夕。賜酒色偏宜，握蘭香不敵。", "淒淒百卉死，歲晚冰霜積。唯有此花開，殷勤助君惜。"]'),
('yuding-42','答劉戒之早秋別墅見寄','白居易','唐','御定全唐诗','yuding','','[]','涼風木槿籬，暮雨槐花枝。並起新秋思，為得故人詩。',48,'御定全唐詩/json/437.json','["涼風木槿籬，暮雨槐花枝。並起新秋思，為得故人詩。", "避地鳥擇木，升朝魚在池。城中與山下，喧靜暗相思。"]'),
('yuding-43','涼夜有懷','白居易','唐','御定全唐诗','yuding','','[]','念別感時節，早蛩聞一聲。風簾夜涼入，露簟秋意生。',48,'御定全唐詩/json/437.json','["念別感時節，早蛩聞一聲。風簾夜涼入，露簟秋意生。", "燈盡夢初罷，月斜天未明。暗凝無限思，起傍藥闌行。"]'),
('yuding-44','秋思','白居易','唐','御定全唐诗','yuding','','[]','病眠夜少夢，閑立秋多思。寂寞餘雨晴，蕭條早寒至。',48,'御定全唐詩/json/437.json','["病眠夜少夢，閑立秋多思。寂寞餘雨晴，蕭條早寒至。", "鳥棲紅葉樹，月照青苔地。何況鏡中年，又過三十二。"]'),
('yuding-45','禁中聞蛩','白居易','唐','御定全唐诗','yuding','','[]','悄悄禁門閉，夜深無月明。西窗獨暗坐，滿耳新蛩聲。',24,'御定全唐詩/json/437.json','["悄悄禁門閉，夜深無月明。西窗獨暗坐，滿耳新蛩聲。"]'),
('yuding-46','秋蟲','白居易','唐','御定全唐诗','yuding','','[]','切切暗窗下，喓喓深草裏。秋天思婦心，雨夜愁人耳。',24,'御定全唐詩/json/437.json','["切切暗窗下，喓喓深草裏。秋天思婦心，雨夜愁人耳。"]'),
('yuding-47','贈別宣上人','白居易','唐','御定全唐诗','yuding','','[]','上人處世界，清淨何所似。似彼白蓮花，在水不著水。',72,'御定全唐詩/json/437.json','["上人處世界，清淨何所似。似彼白蓮花，在水不著水。", "性真悟泡幻，行潔離塵滓。修道來幾時，身心俱到此。", "嗟餘牽世網，不得長依止。離念與碧雲，秋來朝夕起。"]'),
('yuding-48','春夜喜雪，有懷王二十二','白居易','唐','御定全唐诗','yuding','','[]','夜雪有佳趣，幽人出書帷。微寒生枕席，輕素對階墀。',72,'御定全唐詩/json/437.json','["夜雪有佳趣，幽人出書帷。微寒生枕席，輕素對階墀。", "坐罷楚弦曲，起吟班扇詩。明宜滅燭後，淨愛褰簾時。", "窗引曙色早，庭銷春氣遲。山陰應有興，不臥待徽之。"]'),
('yuding-49','酬和元九東川路詩十二首：駱口驛舊題詩','白居易','唐','御定全唐诗','yuding','','[]','拙詩在壁無人愛，鳥汙苔侵文字殘。',32,'御定全唐詩/json/437.json','["拙詩在壁無人愛，鳥汙苔侵文字殘。", "唯有多情元侍禦，繡衣不惜拂塵看。"]'),
('yuding-50','酬和元九東川路詩十二首：南秦雪','白居易','唐','御定全唐诗','yuding','','[]','往歲曾為西邑吏，慣從駱口到南秦。三時雲冷多飛雪，',40,'御定全唐詩/json/437.json','["往歲曾為西邑吏，慣從駱口到南秦。三時雲冷多飛雪，", "仍賴愁猿寒不叫，若聞猿叫更愁人。"]'),
('yuding-51','酬和元九東川路詩十二首：山枇杷花二首','白居易','唐','御定全唐诗','yuding','','[]','萬重青嶂蜀門口，一樹紅花山頂頭。',64,'御定全唐詩/json/437.json','["萬重青嶂蜀門口，一樹紅花山頂頭。", "春盡憶家歸未得，低紅如解替君愁。", "葉如裙色碧綃淺，花似芙蓉紅粉輕。", "若使此花兼解語，推囚禦史定違程。"]'),
('yuding-52','酬和元九東川路詩十二首：江樓月','白居易','唐','御定全唐诗','yuding','','[]','嘉陵江曲曲江池，明月雖同人別離。一宵光景潛相憶，',40,'御定全唐詩/json/437.json','["嘉陵江曲曲江池，明月雖同人別離。一宵光景潛相憶，", "今朝共語方同悔，不解多情先寄詩。"]'),
('yuding-53','酬和元九東川路詩十二首：亞枝花','白居易','唐','御定全唐诗','yuding','','[]','山郵花木似平陽，愁殺多情驄馬郎。',32,'御定全唐詩/json/437.json','["山郵花木似平陽，愁殺多情驄馬郎。", "還似升平池畔坐，低頭向水自看妝。"]'),
('yuding-54','酬和元九東川路詩十二首：江上笛','白居易','唐','御定全唐诗','yuding','','[]','江上何人夜吹笛，聲聲似憶故園春。',32,'御定全唐詩/json/437.json','["江上何人夜吹笛，聲聲似憶故園春。", "此時聞者堪頭白，況是多愁少睡人。"]'),
('yuding-55','酬和元九東川路詩十二首：嘉陵夜有懷二首','白居易','唐','御定全唐诗','yuding','','[]','露濕牆花春意深，西廊月上半床陰。',64,'御定全唐詩/json/437.json','["露濕牆花春意深，西廊月上半床陰。", "憐君獨臥無言語，唯我知君此夜心。", "不明不暗朧朧月，不暖不寒慢慢風。", "獨臥空床好天氣，平明閒事到心中。"]'),
('yuding-56','酬和元九東川路詩十二首：夜深行','白居易','唐','御定全唐诗','yuding','','[]','百牢關外夜行客，三殿角頭宵直人。',32,'御定全唐詩/json/437.json','["百牢關外夜行客，三殿角頭宵直人。", "莫道近臣勝遠使，其如同是不閑身。"]'),
('yuding-57','酬和元九東川路詩十二首：望驛台','白居易','唐','御定全唐诗','yuding','','[]','靖安宅裏當窗柳，望驛台前撲地花。',32,'御定全唐詩/json/437.json','["靖安宅裏當窗柳，望驛台前撲地花。", "兩處春光同日盡，居人思客客思家。"]'),
('yuding-58','酬和元九東川路詩十二首：江岸梨花','白居易','唐','御定全唐诗','yuding','','[]','梨花有思緣和葉，一樹江頭惱殺君。',32,'御定全唐詩/json/437.json','["梨花有思緣和葉，一樹江頭惱殺君。", "最似孀閨少年婦，白妝素袖碧紗裙。"]'),
('yuding-59','答謝家最小偏憐女','白居易','唐','御定全唐诗','yuding','','[]','嫁得梁鴻六七年，耽書愛酒日高眠。雨荒春圃唯生草，',40,'御定全唐詩/json/437.json','["嫁得梁鴻六七年，耽書愛酒日高眠。雨荒春圃唯生草，", "誰知厚俸今無分，枉向秋風吹紙錢。"]'),
('yuding-60','答騎馬入空台','白居易','唐','御定全唐诗','yuding','','[]','君入空台去，朝往暮還來。我入泉台去，泉門無複開。',48,'御定全唐詩/json/437.json','["君入空台去，朝往暮還來。我入泉台去，泉門無複開。", "鰥夫仍系職，稚女未勝哀。寂寞咸陽道，家人覆墓回。"]'),
('yuding-61','答山驛夢','白居易','唐','御定全唐诗','yuding','','[]','入君旅夢來千里，閉我幽魂欲二年。',32,'御定全唐詩/json/437.json','["入君旅夢來千里，閉我幽魂欲二年。", "莫忘平生行坐處，後堂階下竹叢前。"]'),
('yuding-62','和元九與呂二同宿話舊感贈','白居易','唐','御定全唐诗','yuding','','[]','見君新贈呂君詩，憶得同年行樂時。爭入杏園齊馬首，',40,'御定全唐詩/json/437.json','["見君新贈呂君詩，憶得同年行樂時。爭入杏園齊馬首，", "聞道秋娘猶且在，至今時複問微之。"]'),
('yuding-63','憶元九','白居易','唐','御定全唐诗','yuding','','[]','渺渺江陵道，相思遠不知。近來文卷裏，半是憶君詩。',24,'御定全唐詩/json/437.json','["渺渺江陵道，相思遠不知。近來文卷裏，半是憶君詩。"]'),
('yuding-64','蕭員外寄新蜀茶','白居易','唐','御定全唐诗','yuding','','[]','蜀茶寄到但驚新，渭水煎來始覺珍。',32,'御定全唐詩/json/437.json','["蜀茶寄到但驚新，渭水煎來始覺珍。", "滿甌似乳堪持玩，況是春深酒渴人。"]'),
('yuding-65','寄上大兄','白居易','唐','御定全唐诗','yuding','','[]','秋鴻過盡無書信，病戴紗巾強出門。',32,'御定全唐詩/json/437.json','["秋鴻過盡無書信，病戴紗巾強出門。", "獨上荒台東北望，日西愁立到黃昏。"]'),
('yuding-66','病中哭金鑾子','白居易','唐','御定全唐诗','yuding','','[]','豈料吾方病，翻悲汝不全。臥驚從枕上，扶哭就燈前。',96,'御定全唐詩/json/437.json','["豈料吾方病，翻悲汝不全。臥驚從枕上，扶哭就燈前。", "有女誠為累，無兒豈免憐。病來才十日，養得已三年。", "慈淚隨聲迸，悲腸遇物牽。故衣猶架上，殘藥尚頭邊。", "送出深村巷，看封小墓田。莫言三裏地，此別是終天。"]'),
('yuding-67','寄內','白居易','唐','御定全唐诗','yuding','','[]','條桑初綠即為別，柿葉半紅猶未歸。',32,'御定全唐詩/json/437.json','["條桑初綠即為別，柿葉半紅猶未歸。", "不如村婦知時節，解為田夫秋擣衣。"]'),
('yuding-68','病氣','白居易','唐','御定全唐诗','yuding','','[]','自知氣發每因情，情在何由氣得平。',32,'御定全唐詩/json/437.json','["自知氣發每因情，情在何由氣得平。", "若問病根深與淺，此身應與病齊生。"]'),
('yuding-69','歎元九','白居易','唐','御定全唐诗','yuding','','[]','不入城門來五載，同時班列盡官高。',32,'御定全唐詩/json/437.json','["不入城門來五載，同時班列盡官高。", "何人牢落猶依舊，唯有江陵元士曹。"]'),
('yuding-70','眼暗','白居易','唐','御定全唐诗','yuding','','[]','早年勤倦看書苦，晚歲悲傷出淚多。眼損不知都自取，',40,'御定全唐詩/json/437.json','["早年勤倦看書苦，晚歲悲傷出淚多。眼損不知都自取，", "千藥萬方治不得，唯應閉目學頭陀。"]'),
('yuding-71','得袁相書','白居易','唐','御定全唐诗','yuding','','[]','穀苗深處一農夫，面黑頭斑手把鋤。',32,'御定全唐詩/json/437.json','["穀苗深處一農夫，面黑頭斑手把鋤。", "何意使人猶識我，就田來送相公書。"]'),
('yuding-72','病中作','白居易','唐','御定全唐诗','yuding','','[]','病來城裏諸親故，厚薄親疏心總知。',32,'御定全唐詩/json/437.json','["病來城裏諸親故，厚薄親疏心總知。", "唯有蔚章於我分，深于同在翰林時。"]'),
('yuding-73','感化寺見元九、劉三十二題名處','白居易','唐','御定全唐诗','yuding','','[]','微之謫去千餘裏，太白無來十一年。',32,'御定全唐詩/json/437.json','["微之謫去千餘裏，太白無來十一年。", "今日見名如見面，塵埃壁上破窗前。"]'),
('yuding-74','遊悟貞寺回山下別張殷衡','白居易','唐','御定全唐诗','yuding','','[]','世緣未了治不得，孤負青山心共知。',32,'御定全唐詩/json/437.json','["世緣未了治不得，孤負青山心共知。", "愁君又入都門去，即是紅塵滿眼時。"]'),
('yuding-75','村居寄張殷衡','白居易','唐','御定全唐诗','yuding','','[]','金氏村中一病夫，生涯濩落性靈迂。唯看老子五千字，',40,'御定全唐詩/json/437.json','["金氏村中一病夫，生涯濩落性靈迂。唯看老子五千字，", "聞君欲發江東去，能到茅庵訪別無。"]'),
('yuding-76','病中得樊大書','白居易','唐','御定全唐诗','yuding','','[]','荒村破屋經年臥，寂絕無人問病身。',32,'御定全唐詩/json/437.json','["荒村破屋經年臥，寂絕無人問病身。", "唯有東都樊著作，至今書信尚殷勤。"]'),
('yuding-77','開元九詩書卷','白居易','唐','御定全唐诗','yuding','','[]','紅箋白紙兩三束，半是君詩半是書。',32,'御定全唐詩/json/437.json','["紅箋白紙兩三束，半是君詩半是書。", "經年不展緣身病，今日開看生蠹魚。"]'),
('yuding-78','晝臥','白居易','唐','御定全唐诗','yuding','','[]','抱枕無言語，空房獨悄然。誰知盡日臥，非病亦非眠。',24,'御定全唐詩/json/437.json','["抱枕無言語，空房獨悄然。誰知盡日臥，非病亦非眠。"]'),
('yuding-79','夜坐','白居易','唐','御定全唐诗','yuding','','[]','庭前盡日立到夜，燈下有時坐徹明。',32,'御定全唐詩/json/437.json','["庭前盡日立到夜，燈下有時坐徹明。", "此情不語何人會，時複長籲一兩聲。"]'),
('yuding-80','暮立','白居易','唐','御定全唐诗','yuding','','[]','黃昏獨立佛堂前，滿地槐花滿樹蟬。',32,'御定全唐詩/json/437.json','["黃昏獨立佛堂前，滿地槐花滿樹蟬。", "大抵四時心總苦，就中腸斷是秋天。"]'),
('yuding-81','有感','白居易','唐','御定全唐诗','yuding','','[]','絕弦與斷絲，猶有卻續時。唯有衷腸斷，應無續得期。',24,'御定全唐詩/json/437.json','["絕弦與斷絲，猶有卻續時。唯有衷腸斷，應無續得期。"]'),
('yuding-82','答友問','白居易','唐','御定全唐诗','yuding','','[]','似玉童顏盡，如霜病鬢新。莫驚身頓老，心更老於身。',24,'御定全唐詩/json/437.json','["似玉童顏盡，如霜病鬢新。莫驚身頓老，心更老於身。"]'),
('yuding-83','村夜','白居易','唐','御定全唐诗','yuding','','[]','霜草蒼蒼蟲切切，村南村北行人絕。',32,'御定全唐詩/json/437.json','["霜草蒼蒼蟲切切，村南村北行人絕。", "獨出前門望野田，月明蕎麥花如雪。"]'),
('yuding-84','聞蟲','白居易','唐','御定全唐诗','yuding','','[]','暗蟲唧唧夜綿綿，況是秋陰欲雨天。',32,'御定全唐詩/json/437.json','["暗蟲唧唧夜綿綿，況是秋陰欲雨天。", "猶恐愁人暫得睡，聲聲移近臥床前。"]'),
('yuding-85','寒食夜有懷','白居易','唐','御定全唐诗','yuding','','[]','寒食非長非短夜，春風不熱不寒天。',32,'御定全唐詩/json/437.json','["寒食非長非短夜，春風不熱不寒天。", "可憐時節堪相憶，何況無燈各早眠。"]'),
('yuding-86','贈內','白居易','唐','御定全唐诗','yuding','','[]','漠漠暗苔新雨地，微微涼露欲秋天。',32,'御定全唐詩/json/437.json','["漠漠暗苔新雨地，微微涼露欲秋天。", "莫對月明思往事，損君顏色減君年。"]'),
('yuding-87','得錢舍人書問眼疾','白居易','唐','御定全唐诗','yuding','','[]','春來眼暗少心情，點盡黃連尚未平。',32,'御定全唐詩/json/437.json','["春來眼暗少心情，點盡黃連尚未平。", "唯得君書勝得藥，開緘未讀眼先明。"]'),
('yuding-88','還李十一馬','白居易','唐','御定全唐诗','yuding','','[]','傳語李君勞寄馬，病來唯著杖扶身。',32,'御定全唐詩/json/437.json','["傳語李君勞寄馬，病來唯著杖扶身。", "縱擬強騎無出處，卻將牽與趁朝人。"]'),
('yuding-89','九日寄行簡','白居易','唐','御定全唐诗','yuding','','[]','摘得菊花攜得酒，繞村騎馬思悠悠。',32,'御定全唐詩/json/437.json','["摘得菊花攜得酒，繞村騎馬思悠悠。", "下邽田地平如掌，何處登高望梓州。"]'),
('yuding-90','夜坐','白居易','唐','御定全唐诗','yuding','','[]','斜月入前楹，迢迢夜坐情。梧桐上階影，蟋蟀近床聲。',48,'御定全唐詩/json/437.json','["斜月入前楹，迢迢夜坐情。梧桐上階影，蟋蟀近床聲。", "曙傍窗間至，秋從簟上生。感時因憶事，不寢到雞鳴。"]'),
('yuding-91','村居二首','白居易','唐','御定全唐诗','yuding','','[]','田園莽蒼經春早，籬落蕭條盡日風。',56,'御定全唐詩/json/437.json','["田園莽蒼經春早，籬落蕭條盡日風。", "若問經過談笑者，不過田舍白頭翁。", "門閉仍逢雪，廚寒未起煙。貧家重寥落，半為日高眠。"]'),
('yuding-92','早春','白居易','唐','御定全唐诗','yuding','','[]','雪散因和氣，冰開得暖光。春銷不得處，唯有鬢邊霜。',24,'御定全唐詩/json/437.json','["雪散因和氣，冰開得暖光。春銷不得處，唯有鬢邊霜。"]'),
('yuding-93','和夢遊春詩一百韻','白居易','唐','御定全唐诗','yuding','','[]','昔君夢遊春，夢游仙山曲。怳若有所遇，似愜平生欲。',576,'御定全唐詩/json/437.json','["昔君夢遊春，夢游仙山曲。怳若有所遇，似愜平生欲。", "因尋菖蒲水，漸入桃花穀。到一紅樓家，愛之看不足。", "池流渡清泚，草嫩蹋綠蓐。門柳暗全低，簷櫻紅半熟。", "轉行深深院，過盡重重屋。烏龍臥不驚，青鳥飛相逐。", "漸聞玉佩響，始辨珠履躅。遙見窗下人，娉婷十五六。", "霞光抱明月，蓮豔開初旭。縹緲雲雨仙，氛氳蘭麝馥。", "風流薄梳洗，時世寬妝束。袖軟異文綾，裾輕單絲縠。", "裙腰銀線壓，梳掌金筐蹙。帶襭紫蒲萄，袴花紅石竹。", "凝情都未語，付意微相矚。眉斂遠山青，鬟低片雲綠。", "帳牽翡翠帶，被解鴛鴦襆。秀色似堪餐，穠華如可掬。", "半卷錦頭席，斜鋪繡腰褥。朱唇素指勻，粉汗紅綿撲。", "心驚睡易覺，夢斷魂難續。籠委獨棲禽，劍分連理木。", "存誠期有感，誓志貞無黷。京洛八九春，未曾花裏宿。", "壯年徒自棄，佳會應無複。鸞歌不重聞，鳳兆從茲蔔。", "韋門女清貴，裴氏甥賢淑。羅扇夾花燈，金鞍攢繡轂。", "既傾南國貌，遂坦東床腹。劉阮心漸忘，潘楊意方睦。", "新修履信第，初食尚書祿。九醞備聖賢，八珍窮水陸。", "秦家重蕭史，彥輔憐衛叔。朝饌饋獨盤，夜醪傾百斛。", "親賓盛輝赫，妓樂紛曄煜。宿醉才解酲，朝歡俄枕麹。", "飲過君子爭，令甚將軍酷。酩酊歌鷓鴣，顛狂舞鴝鵒。", "月流春夜短，日下秋天速。謝傅隙過駒，蕭娘風過燭。", "全凋蕣花折，半死梧桐禿。暗鏡對孤鸞，哀弦留寡鵠。", "淒淒隔幽顯，冉冉移寒燠。萬事此時休，百身何處贖。", "提攜小兒女，將領舊姻族。再入朱門行，一傍青樓哭。"]'),
('yuding-94','王昭君二首','白居易','唐','御定全唐诗','yuding','','[]','滿面胡沙滿鬢風，眉銷殘黛臉銷紅。',64,'御定全唐詩/json/437.json','["滿面胡沙滿鬢風，眉銷殘黛臉銷紅。", "愁苦辛勤憔悴盡，如今卻似畫圖中。", "漢使卻回憑寄語，黃金何日贖蛾眉。", "君王若問妾顏色，莫道不如宮裏時。"]'),
('yuding-0','渭村退居，寄禮部崔侍郎、翰林錢舍人詩一百韻','白居易','唐','御定全唐诗','yuding','','[]','聖代元和歲，閒居渭水陽。不才甘命舛，多幸遇時康。',576,'御定全唐詩/json/438.json','["聖代元和歲，閒居渭水陽。不才甘命舛，多幸遇時康。", "朝野分倫序，賢愚定否臧。重文疏卜式，尚少棄馮唐。", "由是推天運，從茲樂性場。籠禽放高翥，霧豹得深藏。", "世慮休相擾，身謀且自強。猶須務衣食，未免事農桑。", "薙草通三徑，開田占一坊。晝扉扃白版，夜碓掃黃粱。", "隙地治場圃，閒時糞土疆。枳籬編刺夾，薤壟擘科秧。", "穡力嫌身病，農心願歲穰。朝衣典杯酒，佩劍博牛羊。", "困倚栽松鍤，饑提采蕨筐。引泉來後澗，移竹下前岡。", "生計雖勤苦，家資甚渺茫。塵埃常滿甑，錢帛少盈囊。", "弟病仍扶杖，妻愁不出房。傳衣念藍縷，舉案笑糟糠。", "犬吠村胥鬧，蟬鳴織婦忙。納租看縣帖，輸粟問軍倉。", "夕歇攀村樹，秋行繞野塘。雲容陰慘澹，月色冷悠揚。", "蕎麥鋪花白，棠梨間葉黃。早寒風摵摵，新霽月蒼蒼。", "園菜迎霜死，庭蕪過雨荒。簷空愁宿燕，壁暗思啼螿。", "眼為看書損，肱因運甓傷。病骸渾似木，老鬢欲成霜。", "少睡知年長，端憂覺夜長。舊遊多廢忘，往事偶思量。", "忽憶煙霄路，常陪劍履行。登朝思檢束，入閣學趨蹌。", "命偶風雲會，恩覃雨露霶。沾枯發枝葉，磨鈍起鋒鋩。", "崔閣連鑣騖，錢兄接翼翔。齊竽混韶夏，燕石廁琳琅。", "同日升金馬，分宵直未央。共詞加寵命，合表謝恩光。", "廄馬驕初跨，天廚味始嘗。朝晡頒餅餌，寒暑賜衣裳。", "對秉鵝毛筆，俱含雞舌香。青縑衾薄絮，朱裏幕高張。", "晝食恒連案，宵眠每並床。差肩承詔旨，連署進封章。", "起草偏同視，疑文最共詳。滅私容點竄，窮理析毫芒。"]'),
('yuding-1','酬盧秘書二十韻','白居易','唐','御定全唐诗','yuding','','[]','謬曆文場選，慚非翰苑才。雲霄高暫致，毛羽弱先摧。',240,'御定全唐詩/json/438.json','["謬曆文場選，慚非翰苑才。雲霄高暫致，毛羽弱先摧。", "識分忘軒冕，知歸返草萊。杜陵書積蠹，豐獄劍生苔。", "晦厭鳴雞雨，春驚震蟄雷。舊恩收墜履，新律動寒灰。", "鳳詔容徐起，鵷行許重陪。衰顏雖拂拭，蹇步尚低徊。", "睡少鐘偏警，行遲漏苦摧。風霜趁朝去，泥雪拜陵回。", "上感君猶念，傍慚友或推。石頑鐫費匠，女醜嫁勞媒。", "倏忽青春度，奔波白日頹。性將時共背，病與老俱來。", "聞有蓬壺客，知懷杞梓材。世家標甲第，官職滯麟台。", "筆盡鉛黃點，詩成錦繡堆。嘗思豁雲霧，忽喜訪塵埃。", "心為論文合，眉因勸善開。不勝珍重意，滿袖寫瓊瑰。"]'),
('yuding-2','題盧秘書夏日新栽竹二十韻','白居易','唐','御定全唐诗','yuding','','[]','湘竹初封植，盧生此考盤。久持霜節苦，新托露根難。',240,'御定全唐詩/json/438.json','["湘竹初封植，盧生此考盤。久持霜節苦，新托露根難。", "等度須當砌，疏稠要滿闌。買憐分薄俸，栽稱作閑官。", "葉翦藍羅碎，莖抽玉管端。幾聲清淅瀝，一簇綠檀欒。", "未夜青嵐入，先秋白露團。拂肩搖翡翠，熨手弄琅玕。", "韻透窗風起，陰鋪砌月殘。炎天聞覺冷，窄地見疑寬。", "梢動勝搖扇，枝低好掛冠。碧籠煙幕幕，珠灑雨珊珊。", "晚籜晴雲展，陰芽蟄虺蟠。愛從抽馬策，惜未截魚竿。", "松韻徒煩聽，桃夭不足觀。梁慚當家杏，台陋本司蘭。", "撐撥詩人興，勾牽酒客歡。靜連蘆簟滑，涼拂葛衣單。", "豈止消時暑，應能保歲寒。莫同凡草木，一種夏中看。"]'),
('yuding-3','渭村酬李二十見寄','白居易','唐','御定全唐诗','yuding','','[]','百里音書何太遲，暮秋把得暮春詩。柳條綠日君相憶，',40,'御定全唐詩/json/438.json','["百里音書何太遲，暮秋把得暮春詩。柳條綠日君相憶，", "形容意緒遙看取，不似華陽觀裏時。"]'),
('yuding-4','初授贊善大夫早朝，寄李二十助教','白居易','唐','御定全唐诗','yuding','','[]','病身初謁青宮日，衰貌新垂白髮年。寂寞曹司非熱地，',40,'御定全唐詩/json/438.json','["病身初謁青宮日，衰貌新垂白髮年。寂寞曹司非熱地，", "一種共君官職冷，不如猶得日高眠。"]'),
('yuding-5','欲與元八卜鄰，先有是贈','白居易','唐','御定全唐诗','yuding','','[]','平生心跡最相親，欲隱牆東不為身。明月好同三徑夜，',40,'御定全唐詩/json/438.json','["平生心跡最相親，欲隱牆東不為身。明月好同三徑夜，", "何獨終身數相見，子孫長作隔牆人。"]'),
('yuding-6','游城南，留元九、李二十晚歸','白居易','唐','御定全唐诗','yuding','','[]','老游春飲莫相違，不獨花稀人亦稀。',32,'御定全唐詩/json/438.json','["老游春飲莫相違，不獨花稀人亦稀。", "更勸殘杯看日影，猶應趁得鼓聲歸。"]'),
('yuding-7','廣宣上人以應制詩見示因以贈之詔許上人居安國寺紅樓院以詩供奉','白居易','唐','御定全唐诗','yuding','','[]','道林談論惠休詩，一到人天便作師。香積筵承紫泥詔，',40,'御定全唐詩/json/438.json','["道林談論惠休詩，一到人天便作師。香積筵承紫泥詔，", "惆悵甘泉曾侍從，與君前後不同時。"]'),
('yuding-8','重過秘書舊房，因題長句','白居易','唐','御定全唐诗','yuding','','[]','閣前下馬思裴回，第二房門手自開，昔為白麵書郎去，',40,'御定全唐詩/json/438.json','["閣前下馬思裴回，第二房門手自開，昔為白麵書郎去，", "應有題牆名姓在，試將衫袖拂塵埃。"]'),
('yuding-9','重到城七絕句：見元九','白居易','唐','御定全唐诗','yuding','','[]','容貌一日減一日，心情十分無九分。',32,'御定全唐詩/json/438.json','["容貌一日減一日，心情十分無九分。", "每逢陌路猶嗟歎，何況今朝是見君。"]'),
('yuding-10','重到城七絕句：高相宅','白居易','唐','御定全唐诗','yuding','','[]','青苔故里懷恩地，白髮新生抱病身。',32,'御定全唐詩/json/438.json','["青苔故里懷恩地，白髮新生抱病身。", "涕淚雖多無哭處，永寧門館屬他人。"]'),
('yuding-11','重到城七絕句：張十八','白居易','唐','御定全唐诗','yuding','','[]','諫垣幾見遷遺補，憲府頻聞轉殿監。',32,'御定全唐詩/json/438.json','["諫垣幾見遷遺補，憲府頻聞轉殿監。", "獨有詠詩張太祝，十年不改舊官銜。"]'),
('yuding-12','重到城七絕句：劉家花','白居易','唐','御定全唐诗','yuding','','[]','劉家牆上花還發，李十門前草又春。',32,'御定全唐詩/json/438.json','["劉家牆上花還發，李十門前草又春。", "處處傷心心始悟，多情不及少情人。"]'),
('yuding-13','重到城七絕句：裴五','白居易','唐','御定全唐诗','yuding','','[]','莫怪相逢無笑語，感今思舊戟門前。',32,'御定全唐詩/json/438.json','["莫怪相逢無笑語，感今思舊戟門前。", "張家伯仲偏相似，每見清揚一惘然。"]'),
('yuding-14','重到城七絕句：仇家酒','白居易','唐','御定全唐诗','yuding','','[]','年年老去歡情少，處處春來感事深。',32,'御定全唐詩/json/438.json','["年年老去歡情少，處處春來感事深。", "時到仇家非愛酒，醉時心勝醒時心。"]'),
('yuding-15','重到城七絕句：恒寂師','白居易','唐','御定全唐诗','yuding','','[]','舊遊分散人零落，如此傷心事幾條。',32,'御定全唐詩/json/438.json','["舊遊分散人零落，如此傷心事幾條。", "會逐禪師坐禪去，一時滅盡定中消。"]'),
('yuding-16','靖安北街贈李二十','白居易','唐','御定全唐诗','yuding','','[]','榆莢拋錢柳展眉，兩人並馬語行遲。',32,'御定全唐詩/json/438.json','["榆莢拋錢柳展眉，兩人並馬語行遲。", "還似往年安福寺，共君私試卻回時。"]'),
('yuding-17','重傷小女子','白居易','唐','御定全唐诗','yuding','','[]','學人言語憑床行，嫩似花房脆似瓊。才知恩愛迎三歲，',40,'御定全唐詩/json/438.json','["學人言語憑床行，嫩似花房脆似瓊。才知恩愛迎三歲，", "傷心自歎鳩巢拙，長墮春雛養不成。"]'),
('yuding-18','過顏處士墓','白居易','唐','御定全唐诗','yuding','','[]','向墳道徑沒荒榛，滿室詩書積暗塵。長夜肯教黃壤曉，',40,'御定全唐詩/json/438.json','["向墳道徑沒荒榛，滿室詩書積暗塵。長夜肯教黃壤曉，", "未會悠悠上天意，惜將富壽與何人。"]'),
('yuding-19','題周皓大夫新亭子二十二韻','白居易','唐','御定全唐诗','yuding','','[]','東道常為主，南亭別待賓。規模何日創，景致一時新。',264,'御定全唐詩/json/438.json','["東道常為主，南亭別待賓。規模何日創，景致一時新。", "廣砌羅紅藥，疏窗蔭綠筠。鎖開賓閣曉，梯上妓樓春。", "置醴寧三爵，加籩過八珍。茶香飄紫筍，膾縷落紅鱗。", "輝赫車輿鬧，珍奇鳥獸馴。獼猴看櫪馬，鸚鵡喚家人。", "錦額簾高卷，銀花醆慢巡。勸嘗光祿酒，許看洛川神。", "斂翠凝歌黛，流香動舞巾。裙翻繡鸂鶒，梳陷鈿麒麟。", "笛怨音含楚，箏嬌語帶秦。侍兒催畫燭，醉客吐文茵。", "投轄多連夜，鳴珂便達晨。入朝紆紫綬，待漏擁朱輪。", "貴介交三事，光榮照四鄰。甘濃將奉客，穩暖不緣身。", "十載歌鐘地，三朝節鉞臣。愛才心倜儻，敦舊禮殷勤。", "門以招賢盛，家因好事貧。始知豪傑意，富貴為交親。"]'),
('yuding-20','賦得聽邊鴻','白居易','唐','御定全唐诗','yuding','','[]','驚風吹起塞鴻群，半拂平沙半入雲。',32,'御定全唐詩/json/438.json','["驚風吹起塞鴻群，半拂平沙半入雲。", "為問昭君月下聽，何如蘇武雪中聞。"]'),
('yuding-21','見楊弘貞詩賦，因題絕句以自諭','白居易','唐','御定全唐诗','yuding','','[]','賦句詩章妙入神，未年三十即無身。',32,'御定全唐詩/json/438.json','["賦句詩章妙入神，未年三十即無身。", "常嗟薄命形憔悴，若比弘貞是幸人。"]'),
('yuding-22','病中早春','白居易','唐','御定全唐诗','yuding','','[]','今朝枕上覺頭輕，強起階前試腳行。膻膩斷來無氣力，',40,'御定全唐詩/json/438.json','["今朝枕上覺頭輕，強起階前試腳行。膻膩斷來無氣力，", "唯有愁人鬢間雪，不隨春盡逐春生。"]'),
('yuding-23','送人貶信州判官','白居易','唐','御定全唐诗','yuding','','[]','地僻山深古上饒，土風貧薄道程遙。不唯遷客須恓屑，',40,'御定全唐詩/json/438.json','["地僻山深古上饒，土風貧薄道程遙。不唯遷客須恓屑，", "若於此郡為卑吏，刺史廳前又折腰。"]'),
('yuding-24','曲江醉後贈諸親故','白居易','唐','御定全唐诗','yuding','','[]','郭東丘墓何年客，江畔風光幾日春。只合殷勤逐杯酒，',40,'御定全唐詩/json/438.json','["郭東丘墓何年客，江畔風光幾日春。只合殷勤逐杯酒，", "除卻醉來開口笑，世間何事更關身。"]'),
('yuding-25','和元八侍禦升平新居四絕句：看花屋','白居易','唐','御定全唐诗','yuding','','[]','忽驚映樹新開屋，卻似當簷故種花。',32,'御定全唐詩/json/438.json','["忽驚映樹新開屋，卻似當簷故種花。", "可惜年年紅似火，今春始得屬元家。"]'),
('yuding-26','和元八侍禦升平新居四絕句：累土山','白居易','唐','御定全唐诗','yuding','','[]','堆土漸高山意出，終南移入戶庭間。',32,'御定全唐詩/json/438.json','["堆土漸高山意出，終南移入戶庭間。", "玉峰藍水應惆悵，恐見新山望舊山。"]'),
('yuding-27','和元八侍禦升平新居四絕句：高亭','白居易','唐','御定全唐诗','yuding','','[]','亭脊太高君莫拆，東家留取當西山。',32,'御定全唐詩/json/438.json','["亭脊太高君莫拆，東家留取當西山。", "好看落日斜銜處，一片春嵐映半環。"]'),
('yuding-28','和元八侍禦升平新居四絕句：松樹','白居易','唐','御定全唐诗','yuding','','[]','白金換得青松樹，君既先栽我不栽。',32,'御定全唐詩/json/438.json','["白金換得青松樹，君既先栽我不栽。", "幸有西風易憑仗，夜深偷送好聲來。"]'),
('yuding-29','醉後卻寄元九','白居易','唐','御定全唐诗','yuding','','[]','蒲池村裏匆匆別，灃水橋邊兀兀回。',32,'御定全唐詩/json/438.json','["蒲池村裏匆匆別，灃水橋邊兀兀回。", "行到城門殘酒醒，萬重離恨一時來。"]'),
('yuding-30','重寄','白居易','唐','御定全唐诗','yuding','','[]','蕭散弓驚雁，分飛劍化龍。悠悠天地內，不死會相逢。',24,'御定全唐詩/json/438.json','["蕭散弓驚雁，分飛劍化龍。悠悠天地內，不死會相逢。"]'),
('yuding-31','李十一舍人松園飲小酎酒得元八侍御詩敘云在臺中推院有鞫獄之苦即事書懷因酬四韻','白居易','唐','御定全唐诗','yuding','','[]','愛酒舍人開小酌，能文禦史寄新詩。亂松園裏醉相憶，',40,'御定全唐詩/json/438.json','["愛酒舍人開小酌，能文禦史寄新詩。亂松園裏醉相憶，", "唯應清夜無公事，新草亭中好一期。"]'),
('yuding-32','重到華陽觀舊居','白居易','唐','御定全唐诗','yuding','','[]','憶昔初年三十二，當時秋思已難堪。',32,'御定全唐詩/json/438.json','["憶昔初年三十二，當時秋思已難堪。", "若為重入華陽院，病鬢愁心四十三。"]'),
('yuding-33','答勸酒','白居易','唐','御定全唐诗','yuding','','[]','莫怪近來都不飲，幾回因醉卻沾巾。',32,'御定全唐詩/json/438.json','["莫怪近來都不飲，幾回因醉卻沾巾。", "誰料平生狂酒客，如今變作酒悲人。"]'),
('yuding-34','題王侍禦池亭','白居易','唐','御定全唐诗','yuding','','[]','朱門深鎖春池滿，岸落薔薇水浸莎。',32,'御定全唐詩/json/438.json','["朱門深鎖春池滿，岸落薔薇水浸莎。", "畢竟林塘誰是主，主人來少客來多。"]'),
('yuding-35','聽水部吳員外新詩，因贈絕句','白居易','唐','御定全唐诗','yuding','','[]','朱紱仙郎白雪歌，和人雖少愛人多。',32,'御定全唐詩/json/438.json','["朱紱仙郎白雪歌，和人雖少愛人多。", "明朝說與詩人道，水部如今不姓何。"]'),
('yuding-36','雨夜憶元九','白居易','唐','御定全唐诗','yuding','','[]','天陰一日便堪愁，何況連宵雨不休。',32,'御定全唐詩/json/438.json','["天陰一日便堪愁，何況連宵雨不休。", "一種雨中君最苦，偏梁閣道向通州。"]'),
('yuding-37','雨中攜元九詩訪元八侍禦','白居易','唐','御定全唐诗','yuding','','[]','微之詩卷憶同開，假日多應不入台。',32,'御定全唐詩/json/438.json','["微之詩卷憶同開，假日多應不入台。", "好句無人堪共詠，沖泥蹋水就君來。"]'),
('yuding-38','贈楊秘書巨源','白居易','唐','御定全唐诗','yuding','','[]','早聞一箭取遼城，相識雖新有故情。清句三朝誰是敵，',40,'御定全唐詩/json/438.json','["早聞一箭取遼城，相識雖新有故情。清句三朝誰是敵，", "不用更教詩過好，折君官職是聲名。"]'),
('yuding-39','和武相公感韋令公舊池孔雀','白居易','唐','御定全唐诗','yuding','','[]','索莫少顏色，池邊無主禽。難收帶泥翅，易結著人心。',48,'御定全唐詩/json/438.json','["索莫少顏色，池邊無主禽。難收帶泥翅，易結著人心。", "頂毳落殘碧，尾花銷暗金。放歸飛不得，雲海故巢深。"]'),
('yuding-40','寄生衣與微之，因題封上','白居易','唐','御定全唐诗','yuding','','[]','淺色縠衫輕似霧，紡花紗袴薄於雲。',32,'御定全唐詩/json/438.json','["淺色縠衫輕似霧，紡花紗袴薄於雲。", "莫嫌輕薄但知著，猶恐通州熱殺君。"]'),
('yuding-41','白牡丹','白居易','唐','御定全唐诗','yuding','','[]','白花冷澹無人愛，亦占芳名道牡丹。',32,'御定全唐詩/json/438.json','["白花冷澹無人愛，亦占芳名道牡丹。", "應似東宮白贊善，被人還喚作朝官。"]'),
('yuding-42','夢舊','白居易','唐','御定全唐诗','yuding','','[]','別來老大苦修道，煉得離心成死灰。',32,'御定全唐詩/json/438.json','["別來老大苦修道，煉得離心成死灰。", "平生憶念消磨盡，昨夜因何入夢來。"]'),
('yuding-43','戲題盧秘書新移薔薇','白居易','唐','御定全唐诗','yuding','','[]','風動翠條腰嫋娜，露垂紅萼淚闌幹。',32,'御定全唐詩/json/438.json','["風動翠條腰嫋娜，露垂紅萼淚闌幹。", "移他到此須為主，不別花人莫使看。"]'),
('yuding-44','曲江夜歸，聞元八見訪','白居易','唐','御定全唐诗','yuding','','[]','自入台來見面稀，班中遙得揖容輝。',32,'御定全唐詩/json/438.json','["自入台來見面稀，班中遙得揖容輝。", "早知相憶來相訪，悔待江頭明月歸。"]'),
('yuding-45','苦熱題恒寂師禪室','白居易','唐','御定全唐诗','yuding','','[]','人人避暑走如狂，獨有禪師不出房。',32,'御定全唐詩/json/438.json','["人人避暑走如狂，獨有禪師不出房。", "可是禪房無熱到，但能心靜即身涼。"]'),
('yuding-46','微之到通州日，授館未安，見塵壁間有數行字，讀之，即僕舊詩，其落句云：淥水紅蓮一朵開，千花百草無顏色然，不知題者何人也。微之吟歎不足，因綴一章，兼錄僕詩本同寄。省其詩，乃十五年前初及第時，贈長安妓人阿軟絕句。緬思往事，杳若夢中，懷舊感今，因酬長句','白居易','唐','御定全唐诗','yuding','','[]','十五年前似夢游，曾將詩句結風流。偶助笑歌嘲阿軟，',40,'御定全唐詩/json/438.json','["十五年前似夢游，曾將詩句結風流。偶助笑歌嘲阿軟，", "惆悵又聞題處所，雨淋江館破牆頭。"]'),
('yuding-47','得微之到官後書備知通州之事悵然有感因成四章','白居易','唐','御定全唐诗','yuding','','[]','來書子細說通州，州在山根峽岸頭。四面千重火雲合，',160,'御定全唐詩/json/438.json','["來書子細說通州，州在山根峽岸頭。四面千重火雲合，", "何罪遣君居此地，天高無處問來由。", "匼匝巔山萬仞餘，人家應似甑中居。寅年籬下多逢虎，", "努力安心過三考，已曾愁殺李尚書。", "人稀地僻醫巫少，夏旱秋霖瘴瘧多。老去一身須愛惜，", "莫遣沉愁結成病，時時一唱濯纓歌。", "通州海內恓惶地，司馬人間冗長官。傷鳥有弦驚不定，", "舉目爭能不惆悵，高車大馬滿長安。"]'),
('yuding-48','病中答招飲者','白居易','唐','御定全唐诗','yuding','','[]','顧我鏡中悲白髮，盡君花下醉青春。',32,'御定全唐詩/json/438.json','["顧我鏡中悲白髮，盡君花下醉青春。", "不緣眼痛兼身病，可是尊前第二人。"]'),
('yuding-49','燕子樓三首','白居易','唐','御定全唐诗','yuding','','[]','滿窗明月滿簾霜，被冷燈殘拂臥床。',96,'御定全唐詩/json/438.json','["滿窗明月滿簾霜，被冷燈殘拂臥床。", "燕子樓中霜月夜，秋來隻為一人長。", "鈿暈羅衫色似煙，幾回欲著即潸然。", "自從不舞霓裳曲，疊在空箱十一年。", "今春有客洛陽回，曾到尚書墓上來。", "見說白楊堪作柱，爭教紅粉不成灰。"]'),
('yuding-50','初貶官過望秦嶺','白居易','唐','御定全唐诗','yuding','','[]','草草辭家憂後事，遲遲去國問前途。',32,'御定全唐詩/json/438.json','["草草辭家憂後事，遲遲去國問前途。", "望秦嶺上回頭立，無限秋風吹白須。"]'),
('yuding-51','藍橋驛見元九詩','白居易','唐','御定全唐诗','yuding','','[]','藍橋春雪君歸日，秦嶺秋風我去時。',32,'御定全唐詩/json/438.json','["藍橋春雪君歸日，秦嶺秋風我去時。", "每到驛亭先下馬，循牆繞柱覓君詩。"]'),
('yuding-52','韓公堆寄元九','白居易','唐','御定全唐诗','yuding','','[]','韓公堆北澗西頭，冷雨涼風拂面秋。',32,'御定全唐詩/json/438.json','["韓公堆北澗西頭，冷雨涼風拂面秋。", "努力南行少惆悵，江州猶似勝通州。"]'),
('yuding-53','發商州','白居易','唐','御定全唐诗','yuding','','[]','商州館裏停三日，待得妻孥相逐行。',32,'御定全唐詩/json/438.json','["商州館裏停三日，待得妻孥相逐行。", "若比李三猶自勝，兒啼婦哭不聞聲。"]'),
('yuding-54','武關南見元九題山石榴花見寄','白居易','唐','御定全唐诗','yuding','','[]','往來同路不同時，前後相思兩不知。',32,'御定全唐詩/json/438.json','["往來同路不同時，前後相思兩不知。", "行過關門三四裏，榴花不見見君詩。"]'),
('yuding-55','紅鸚鵡','白居易','唐','御定全唐诗','yuding','','[]','安南遠進紅鸚鵡，色似桃花語似人。',32,'御定全唐詩/json/438.json','["安南遠進紅鸚鵡，色似桃花語似人。", "文章辯慧皆如此，籠檻何年出得身。"]'),
('yuding-56','題四皓廟','白居易','唐','御定全唐诗','yuding','','[]','臥逃秦亂起安劉，舒卷如雲得自由。',32,'御定全唐詩/json/438.json','["臥逃秦亂起安劉，舒卷如雲得自由。", "若有精靈應笑我，不成一事謫江州。"]'),
('yuding-57','罷藥','白居易','唐','御定全唐诗','yuding','','[]','自學坐禪休服藥，從他時複病沉沉。',32,'御定全唐詩/json/438.json','["自學坐禪休服藥，從他時複病沉沉。", "此身不要全強健，強健多生人我心。"]'),
('yuding-58','白鷺','白居易','唐','御定全唐诗','yuding','','[]','人生四十未全衰，我為愁多白髮垂。',32,'御定全唐詩/json/438.json','["人生四十未全衰，我為愁多白髮垂。", "何故水邊雙白鷺，無愁頭上亦垂絲。"]'),
('yuding-59','襄陽舟夜','白居易','唐','御定全唐诗','yuding','','[]','下馬襄陽郭，移舟漢陰驛。秋風截江起，寒浪連天白。',36,'御定全唐詩/json/438.json','["下馬襄陽郭，移舟漢陰驛。秋風截江起，寒浪連天白。", "本是多愁人，複此風波夕。"]'),
('yuding-60','江夜舟行','白居易','唐','御定全唐诗','yuding','','[]','煙淡月濛濛，舟行夜色中。江鋪滿槽水，帆展半檣風。',48,'御定全唐詩/json/438.json','["煙淡月濛濛，舟行夜色中。江鋪滿槽水，帆展半檣風。", "叫曙嗷嗷雁，啼秋唧唧蟲。只應催北客，早作白須翁。"]'),
('yuding-61','紅藤杖','白居易','唐','御定全唐诗','yuding','','[]','交親過滻別，車馬到江回。唯有紅藤杖，相隨萬里來。',24,'御定全唐詩/json/438.json','["交親過滻別，車馬到江回。唯有紅藤杖，相隨萬里來。"]'),
('yuding-62','江上吟元八絕句','白居易','唐','御定全唐诗','yuding','','[]','大江深處月明時，一夜吟君小律詩。',32,'御定全唐詩/json/438.json','["大江深處月明時，一夜吟君小律詩。", "應有水仙潛出聽，翻將唱作步虛詞。"]'),
('yuding-63','途中感秋','白居易','唐','御定全唐诗','yuding','','[]','節物行搖落，年顏坐變衰。樹初黃葉日，人欲白頭時。',48,'御定全唐詩/json/438.json','["節物行搖落，年顏坐變衰。樹初黃葉日，人欲白頭時。", "鄉國程程遠，親朋處處辭。唯殘病與老，一步不相離。"]'),
('yuding-64','登郢州白雪樓','白居易','唐','御定全唐诗','yuding','','[]','白雪樓中一望鄉，青山蔟蔟水茫茫。',32,'御定全唐詩/json/438.json','["白雪樓中一望鄉，青山蔟蔟水茫茫。", "朝來渡口逢京使，說道煙塵近洛陽。"]'),
('yuding-65','舟夜贈內','白居易','唐','御定全唐诗','yuding','','[]','三聲猿後垂鄉淚，一葉舟中載病身。',32,'御定全唐詩/json/438.json','["三聲猿後垂鄉淚，一葉舟中載病身。", "莫憑水窗南北望，月明月暗總愁人。"]'),
('yuding-66','逢舊','白居易','唐','御定全唐诗','yuding','','[]','我梳白髮添新恨，君掃青蛾減舊容。',32,'御定全唐詩/json/438.json','["我梳白髮添新恨，君掃青蛾減舊容。", "應被傍人怪惆悵，少年離別老相逢。"]'),
('yuding-67','臼口阻風十日','白居易','唐','御定全唐诗','yuding','','[]','洪濤白浪塞江津，處處邅回事事迍。世上方為失途客，',40,'御定全唐詩/json/438.json','["洪濤白浪塞江津，處處邅回事事迍。世上方為失途客，", "老大光陰能幾日，等閒臼口坐經旬。"]'),
('yuding-68','浦中夜泊','白居易','唐','御定全唐诗','yuding','','[]','暗上江堤還獨立，水風霜氣夜棱棱。',32,'御定全唐詩/json/438.json','["暗上江堤還獨立，水風霜氣夜棱棱。", "回看深浦停舟處，蘆荻花中一點燈。"]'),
('yuding-69','盧侍禦與崔評事為予于黃鶴樓置宴，宴罷同望','白居易','唐','御定全唐诗','yuding','','[]','江邊黃鶴古時樓，勞置華筵待我遊。楚思淼茫雲水冷，',40,'御定全唐詩/json/438.json','["江邊黃鶴古時樓，勞置華筵待我遊。楚思淼茫雲水冷，", "總是平生未行處，醉來堪賞醒堪愁。"]'),
('yuding-70','舟中讀元九詩','白居易','唐','御定全唐诗','yuding','','[]','把君詩卷燈前讀，詩盡燈殘天未明。',32,'御定全唐詩/json/438.json','["把君詩卷燈前讀，詩盡燈殘天未明。", "眼痛滅燈猶暗坐，逆風吹浪打船聲。"]'),
('yuding-71','舟行阻風，寄李十一舍人','白居易','唐','御定全唐诗','yuding','','[]','扁舟厭泊煙波上，輕策閑尋浦嶼間。虎蹋青泥稠似印，',40,'御定全唐詩/json/438.json','["扁舟厭泊煙波上，輕策閑尋浦嶼間。虎蹋青泥稠似印，", "今日料君朝退後，迎寒新酎暖開顏。"]'),
('yuding-72','雨中題衰柳','白居易','唐','御定全唐诗','yuding','','[]','濕屈青條折，寒飄黃葉多。不知秋雨意，更遣欲如何。',24,'御定全唐詩/json/438.json','["濕屈青條折，寒飄黃葉多。不知秋雨意，更遣欲如何。"]'),
('yuding-73','題王處士郊居','白居易','唐','御定全唐诗','yuding','','[]','半依雲渚半依山，愛此令人不欲還。負郭田園九八頃，',40,'御定全唐詩/json/438.json','["半依雲渚半依山，愛此令人不欲還。負郭田園九八頃，", "一臥江村來早晚，著書盈帙鬢毛斑。"]'),
('yuding-74','歲晚旅望','白居易','唐','御定全唐诗','yuding','','[]','朝來暮去星霜換，陰慘陽舒氣序牽。萬物秋霜能壞色，',40,'御定全唐詩/json/438.json','["朝來暮去星霜換，陰慘陽舒氣序牽。萬物秋霜能壞色，", "向晚蒼蒼南北望，窮陰旅思兩無邊。"]'),
('yuding-75','晏坐閑吟','白居易','唐','御定全唐诗','yuding','','[]','昔為京洛聲華客，今作江湖潦倒翁。意氣銷磨群動裏，',40,'御定全唐詩/json/438.json','["昔為京洛聲華客，今作江湖潦倒翁。意氣銷磨群動裏，", "願學禪門非想定，千愁萬念一時空。"]'),
('yuding-76','題李山人','白居易','唐','御定全唐诗','yuding','','[]','廚無煙火室無妻，籬落蕭條屋舍低。',32,'御定全唐詩/json/438.json','["廚無煙火室無妻，籬落蕭條屋舍低。", "每日將何療饑渴，井華雲粉一刀圭。"]'),
('yuding-77','讀莊子','白居易','唐','御定全唐诗','yuding','','[]','去國辭家謫異方，中心自怪少憂傷。',32,'御定全唐詩/json/438.json','["去國辭家謫異方，中心自怪少憂傷。", "為尋莊子知歸處，認得無何是本鄉。"]'),
('yuding-78','江樓偶宴贈同座','白居易','唐','御定全唐诗','yuding','','[]','南浦閑行罷，西樓小宴時。望湖憑檻久，待月放杯遲。',48,'御定全唐詩/json/438.json','["南浦閑行罷，西樓小宴時。望湖憑檻久，待月放杯遲。", "江果嘗盧橘，山歌聽竹枝。相逢且同樂，何必舊相知。"]'),
('yuding-79','放言五首','白居易','唐','御定全唐诗','yuding','','[]','朝真暮偽何人辨，古往今來底事無。但愛臧生能詐聖，',200,'御定全唐詩/json/438.json','["朝真暮偽何人辨，古往今來底事無。但愛臧生能詐聖，", "不取燔柴兼照乘，可憐光彩亦何殊。", "世途倚伏都無定，塵網牽纏卒未休。禍福回還車轉轂，", "不信君看弈棋者，輸贏須待局終頭。", "贈君一法決狐疑，不用鑽龜與祝蓍。試玉要燒三日滿，", "向使當初身便死，一生真偽複誰知。", "誰家第宅成還破，何處親賓哭複歌。昨日屋頭堪炙手，", "莫笑賤貧誇富貴，共成枯骨兩如何。", "泰山不要欺毫末，顏子無心羨老彭。松樹千年終是朽，", "生去死來都是幻，幻人哀樂系何情。"]'),
('yuding-80','歲暮道情二首','白居易','唐','御定全唐诗','yuding','','[]','壯日苦曾驚歲月，長年都不惜光陰。',64,'御定全唐詩/json/438.json','["壯日苦曾驚歲月，長年都不惜光陰。", "為學空門平等法，先齊老少死生心。", "半故青衫半白頭，雪風吹面上江樓。", "禪功自見無人覺，合是愁時亦不愁。"]'),
('yuding-81','讀李杜詩集，因題卷後','白居易','唐','御定全唐诗','yuding','','[]','翰林江左日，員外劍南時。不得高官職，仍逢苦亂離。',72,'御定全唐詩/json/438.json','["翰林江左日，員外劍南時。不得高官職，仍逢苦亂離。", "暮年逋客恨，浮世謫仙悲。吟詠留千古，聲名動四夷。", "文場供秀句，樂府待新詞。天意君須會，人間要好詩。"]'),
('yuding-82','強酒','白居易','唐','御定全唐诗','yuding','','[]','若不坐禪銷妄想，即須行醉放狂歌。',32,'御定全唐詩/json/438.json','["若不坐禪銷妄想，即須行醉放狂歌。", "不然秋月春風夜，爭那閑思往事何。"]'),
('yuding-83','獨樹浦雨夜寄李六郎中','白居易','唐','御定全唐诗','yuding','','[]','忽憶兩家同裏巷，何曾一處不追隨。閒遊預算分朝日，',40,'御定全唐詩/json/438.json','["忽憶兩家同裏巷，何曾一處不追隨。閒遊預算分朝日，", "可知風雨孤舟夜，蘆葦叢中作此詩。"]'),
('yuding-84','聽崔七妓人箏','白居易','唐','御定全唐诗','yuding','','[]','花臉雲鬟坐玉樓，十三弦裏一時愁。',32,'御定全唐詩/json/438.json','["花臉雲鬟坐玉樓，十三弦裏一時愁。", "憑君向道休彈去，白盡江州司馬頭。"]'),
('yuding-85','望江州','白居易','唐','御定全唐诗','yuding','','[]','江回望見雙華表，知是潯陽西郭門。',32,'御定全唐詩/json/438.json','["江回望見雙華表，知是潯陽西郭門。", "猶去孤舟三四裏，水煙沙雨欲黃昏。"]'),
('yuding-86','初到江州','白居易','唐','御定全唐诗','yuding','','[]','潯陽欲到思無窮，庾亮樓南湓口東。樹木凋疏山雨後，',40,'御定全唐詩/json/438.json','["潯陽欲到思無窮，庾亮樓南湓口東。樹木凋疏山雨後，", "遙見朱輪來出郭，相迎勞動使君公。"]'),
('yuding-87','醉後題李、馬二妓','白居易','唐','御定全唐诗','yuding','','[]','行搖雲髻花鈿節，應似霓裳趁管弦。豔動舞裙渾是火，',40,'御定全唐詩/json/438.json','["行搖雲髻花鈿節，應似霓裳趁管弦。豔動舞裙渾是火，", "疑是兩般心未決，雨中神女月中仙。"]'),
('yuding-88','盧侍禦小妓乞詩，座上留贈','白居易','唐','御定全唐诗','yuding','','[]','鬱金香汗裛歌巾，山石榴花染舞裙。好似文君還對酒，',24,'御定全唐詩/json/438.json','["鬱金香汗裛歌巾，山石榴花染舞裙。好似文君還對酒，"]'),
('yuding-0','東南行一百韻寄通州元九侍御澧州李十一舍人果州崔二十二使君開州韋大員外庾三十二補闕杜十四拾遺李二十助教員外竇七校書','白居易','唐','御定全唐诗','yuding','','[]','南去經三楚，東來過五湖。山頭看候館，水面問征途。',576,'御定全唐詩/json/439.json','["南去經三楚，東來過五湖。山頭看候館，水面問征途。", "地遠窮江界，天低極海隅。飄零同落葉，浩蕩似乘桴。", "漸覺鄉原異，深知土產殊。夷音語嘲哳，蠻態笑睢盱。", "水市通闤闠，煙村混舳艫。吏征漁戶稅，人納火田租。", "亥日饒蝦蟹，寅年足虎貙。成人男作丱，事鬼女為巫。", "樓暗攢倡婦，堤長簇販夫。夜船論鋪賃，春酒斷瓶酤。", "見果皆盧橘，聞禽悉鷓鴣。山歌猿獨叫，野哭鳥相呼。", "嶺徼雲成棧，江郊水當郛。月移翹柱鶴，風泛颭檣烏。", "鼇礙潮無信，蛟驚浪不虞。鼉鳴江擂鼓，蜃氣海浮圖。", "樹裂山魈穴，沙含水弩樞。喘牛犁紫芋，羸馬放青菰。", "繡面誰家婢，鴉頭幾歲奴。泥中采菱芡，燒後拾樵蘇。", "鼎膩愁烹鱉，盤腥厭膾鱸。鐘儀徒戀楚，張翰浪思吳。", "氣序涼還熱，光陰旦複晡。身方逐萍梗，年欲近桑榆。", "渭北田園廢，江西歲月徂。憶歸恒慘澹，懷舊忽踟躕。", "自念咸秦客，嘗為鄒魯儒。蘊藏經國術，輕棄度關繻。", "賦力淩鸚鵡，詞鋒敵轆轤。戰文重掉鞅，射策一彎弧。", "崔杜鞭齊下，元韋轡並驅。名聲逼揚馬，交分過蕭朱。", "世務輕摩揣，周行竊覬覦。風雲皆會合，雨露各沾濡。", "共遇升平代，偏慚固陋軀。承明連夜直，建禮拂晨趨。", "美服頒王府，珍羞降禦廚。議高通白虎，諫切伏青蒲。", "柏殿行陪宴，花樓走看酺。神旗張鳥獸，天籟動笙竽。", "戈劍星芒耀，魚龍電策驅。定場排越伎，促坐進吳歈。", "縹緲疑仙樂，嬋娟勝畫圖。歌鬟低翠羽，舞汗墮紅珠。", "別選閒遊伴，潛招小飲徒。一杯愁已破，三醆氣彌粗。"]'),
('yuding-1','謫居','白居易','唐','御定全唐诗','yuding','','[]','面瘦頭斑四十四，遠謫江州為郡吏。逢時棄置從不才，',40,'御定全唐詩/json/439.json','["面瘦頭斑四十四，遠謫江州為郡吏。逢時棄置從不才，", "遭時榮悴一時間，豈是昭昭上天意。"]'),
('yuding-2','初到江州寄翰林張、李、杜三學士','白居易','唐','御定全唐诗','yuding','','[]','早攀霄漢上天衢，晚落風波委世途。雨露施恩無厚薄，',40,'御定全唐詩/json/439.json','["早攀霄漢上天衢，晚落風波委世途。雨露施恩無厚薄，", "碧落三仙曾識面，年深記得姓名無。"]'),
('yuding-3','庾樓曉望','白居易','唐','御定全唐诗','yuding','','[]','獨憑朱檻立淩晨，山色初明水色新。竹霧曉籠銜嶺月，',40,'御定全唐詩/json/439.json','["獨憑朱檻立淩晨，山色初明水色新。竹霧曉籠銜嶺月，", "三百年來庾樓上，曾經多少望鄉人。"]'),
('yuding-4','宿西林寺','白居易','唐','御定全唐诗','yuding','','[]','木落天晴山翠開，愛山騎馬入山來。',32,'御定全唐詩/json/439.json','["木落天晴山翠開，愛山騎馬入山來。", "心知不及柴桑令，一宿西林便卻回。"]'),
('yuding-5','江樓宴別','白居易','唐','御定全唐诗','yuding','','[]','樓中別曲催離酌，燈下紅裙間綠袍。縹緲楚風羅綺薄，',40,'御定全唐詩/json/439.json','["樓中別曲催離酌，燈下紅裙間綠袍。縹緲楚風羅綺薄，", "尊酒未空歡未盡，舞腰歌袖莫辭勞。"]'),
('yuding-6','題山石榴花','白居易','唐','御定全唐诗','yuding','','[]','一叢千朵壓闌幹，翦碎紅綃卻作團。風嫋舞腰香不盡，',40,'御定全唐詩/json/439.json','["一叢千朵壓闌幹，翦碎紅綃卻作團。風嫋舞腰香不盡，", "爭及此花簷戶下，任人采弄盡人看。"]'),
('yuding-7','代春贈','白居易','唐','御定全唐诗','yuding','','[]','山吐晴嵐水放光，辛夷花白柳梢黃。',32,'御定全唐詩/json/439.json','["山吐晴嵐水放光，辛夷花白柳梢黃。", "但知莫作江西意，風景何曾異帝鄉。"]'),
('yuding-8','答春','白居易','唐','御定全唐诗','yuding','','[]','草煙低重水花明，從道風光似帝京。',32,'御定全唐詩/json/439.json','["草煙低重水花明，從道風光似帝京。", "其奈山猿江上叫，故鄉無此斷腸聲。"]'),
('yuding-9','櫻桃花下歎白髮','白居易','唐','御定全唐诗','yuding','','[]','逐處花皆好，隨年貌自衰。紅櫻滿眼日，白髮半頭時。',48,'御定全唐詩/json/439.json','["逐處花皆好，隨年貌自衰。紅櫻滿眼日，白髮半頭時。", "倚樹無言久，攀條欲放遲。臨風兩堪歎，如雪複如絲。"]'),
('yuding-10','惜落花，贈崔二十四','白居易','唐','御定全唐诗','yuding','','[]','漠漠紛紛不奈何，狂風急雨兩相和。',32,'御定全唐詩/json/439.json','["漠漠紛紛不奈何，狂風急雨兩相和。", "晚來悵望君知否，枝上稀疏地上多。"]'),
('yuding-11','移山櫻桃','白居易','唐','御定全唐诗','yuding','','[]','亦知官舍非吾宅，且劚山櫻滿院栽。',32,'御定全唐詩/json/439.json','["亦知官舍非吾宅，且劚山櫻滿院栽。", "上佐近來多五考，少應四度見花開。"]'),
('yuding-12','官舍閑題','白居易','唐','御定全唐诗','yuding','','[]','職散優閑地，身慵老大時。送春唯有酒，銷日不過棋。',48,'御定全唐詩/json/439.json','["職散優閑地，身慵老大時。送春唯有酒，銷日不過棋。", "祿米獐牙稻，園蔬鴨腳葵。飽餐仍晏起，餘暇弄龜兒。"]'),
('yuding-13','晚春登大雲寺南樓，贈常禪師','白居易','唐','御定全唐诗','yuding','','[]','花盡頭新白，登樓意若何。歲時春日少，世界苦人多。',48,'御定全唐詩/json/439.json','["花盡頭新白，登樓意若何。歲時春日少，世界苦人多。", "愁醉非因酒，悲吟不是歌。求師治此病，唯勸讀楞伽。"]'),
('yuding-14','北樓送客歸上都','白居易','唐','御定全唐诗','yuding','','[]','憑高眺遠一淒淒，卻下朱闌即解攜。京路人歸天直北，',40,'御定全唐詩/json/439.json','["憑高眺遠一淒淒，卻下朱闌即解攜。京路人歸天直北，", "不獨別君須強飲，窮愁自要醉如泥。"]'),
('yuding-15','北亭招客','白居易','唐','御定全唐诗','yuding','','[]','疏散郡丞同野客，幽閒官舍抵山家。春風北戶千莖竹，',40,'御定全唐詩/json/439.json','["疏散郡丞同野客，幽閒官舍抵山家。春風北戶千莖竹，", "能來盡日觀棋否，太守知慵放晚衙。"]'),
('yuding-16','宿西林寺，早赴東林滿上人之會因寄崔二十二員外','白居易','唐','御定全唐诗','yuding','','[]','謫辭魏闕鵷鸞隔，老入廬山麋鹿隨。薄暮蕭條投寺宿，',40,'御定全唐詩/json/439.json','["謫辭魏闕鵷鸞隔，老入廬山麋鹿隨。薄暮蕭條投寺宿，", "鵬鷃高低分皆定，莫勞心力遠相思。"]'),
('yuding-17','遊寶稱寺','白居易','唐','御定全唐诗','yuding','','[]','竹寺初晴日，花塘欲曉春。野猿疑弄客，山鳥似呼人。',48,'御定全唐詩/json/439.json','["竹寺初晴日，花塘欲曉春。野猿疑弄客，山鳥似呼人。", "酒嫩傾金液，茶新碾玉塵。可憐幽靜地，堪寄老慵身。"]'),
('yuding-18','早春聞提壺鳥，因題鄰家','白居易','唐','御定全唐诗','yuding','','[]','厭聽秋猿催下淚，喜聞春鳥勸提壺。誰家紅樹先花發，',40,'御定全唐詩/json/439.json','["厭聽秋猿催下淚，喜聞春鳥勸提壺。誰家紅樹先花發，", "欲期明日東鄰醉，變作騰騰一俗夫。"]'),
('yuding-19','見紫薇花憶微之','白居易','唐','御定全唐诗','yuding','','[]','一叢暗淡將何比，淺碧籠裙襯紫巾。',32,'御定全唐詩/json/439.json','["一叢暗淡將何比，淺碧籠裙襯紫巾。", "除卻微之見應愛，人間少有別花人。"]'),
('yuding-20','薔薇花一叢獨死，不知其故，因有是篇','白居易','唐','御定全唐诗','yuding','','[]','柯條未嘗損，根蕟不曾移。同類今齊茂，孤芳忽獨萎。',72,'御定全唐詩/json/439.json','["柯條未嘗損，根蕟不曾移。同類今齊茂，孤芳忽獨萎。", "仍憐委地日，正是帶花時。碎碧初凋葉，燋紅尚戀枝。", "乾坤無厚薄，草木自榮衰。欲問因何事，春風亦不知。"]'),
('yuding-21','湖亭望水','白居易','唐','御定全唐诗','yuding','','[]','久雨南湖漲，新晴北客過。日沉紅有影，風定綠無波。',48,'御定全唐詩/json/439.json','["久雨南湖漲，新晴北客過。日沉紅有影，風定綠無波。", "岸沒閭閻少，灘平船舫多。可憐心賞處，其奈獨游何。"]'),
('yuding-22','閒遊','白居易','唐','御定全唐诗','yuding','','[]','外事因慵廢，中懷與靜期。尋泉上山遠，看筍出林遲。',48,'御定全唐詩/json/439.json','["外事因慵廢，中懷與靜期。尋泉上山遠，看筍出林遲。", "白石磨樵斧，青竿理釣絲。澄清深淺好，最愛夕陽時。"]'),
('yuding-23','憶微之傷仲遠','白居易','唐','御定全唐诗','yuding','','[]','幽獨辭群久，漂流去國賒。只將琴作伴，唯以酒為家。',72,'御定全唐詩/json/439.json','["幽獨辭群久，漂流去國賒。只將琴作伴，唯以酒為家。", "感逝因看水，傷離為見花。李三埋地底，元九謫天涯。", "舉眼青雲遠，回頭白日斜。可能勝賈誼，猶自滯長沙。"]'),
('yuding-24','過鄭處士','白居易','唐','御定全唐诗','yuding','','[]','聞道移居村塢間，竹林多處獨開關。',32,'御定全唐詩/json/439.json','["聞道移居村塢間，竹林多處獨開關。", "故來不是求他事，暫借南亭一望山。"]'),
('yuding-25','霖雨苦多，江湖暴漲，塊然獨望，因題北亭','白居易','唐','御定全唐诗','yuding','','[]','自作潯陽客，無如苦雨何。陰昏晴日少，閑悶睡時多。',72,'御定全唐詩/json/439.json','["自作潯陽客，無如苦雨何。陰昏晴日少，閑悶睡時多。", "湖闊將天合，雲低與水和。籬根舟子語，巷口釣人歌。", "霧島沉黃氣，風帆蹙白波。門前車馬道，一宿變江河。"]'),
('yuding-26','春末夏初閒遊江郭二首','白居易','唐','御定全唐诗','yuding','','[]','閑出乘輕屐，徐行蹋軟沙。觀魚傍湓浦，看竹入楊家。',144,'御定全唐詩/json/439.json','["閑出乘輕屐，徐行蹋軟沙。觀魚傍湓浦，看竹入楊家。", "林迸穿籬筍，藤飄落水花。雨埋釣舟小，風颺酒旗斜。", "嫩剝青菱角，濃煎白茗芽。淹留不知夕，城樹欲棲鴉。", "柳影繁初合，鶯聲澀漸稀。早梅迎夏結，殘絮送春飛。", "西日韶光盡，南風暑氣微。展張新小簟，熨帖舊生衣。", "綠蟻杯香嫩，紅絲膾縷肥。故園無此味，何必苦思歸。"]'),
('yuding-27','紅藤杖','白居易','唐','御定全唐诗','yuding','','[]','南詔紅藤杖，西江白首人。時時攜步月，處處把尋春。',72,'御定全唐詩/json/439.json','["南詔紅藤杖，西江白首人。時時攜步月，處處把尋春。", "勁健孤莖直，疏圓六節勻。火山生處遠，瀘水洗來新。", "粗細才盈手，高低僅過身。天邊望鄉客，何日拄歸秦。"]'),
('yuding-28','風雨中尋李十一，因題船上','白居易','唐','御定全唐诗','yuding','','[]','匹馬來郊外，扁舟在水濱。可憐沖雨客，來訪阻風人。',48,'御定全唐詩/json/439.json','["匹馬來郊外，扁舟在水濱。可憐沖雨客，來訪阻風人。", "小榼酤清醑，行廚煮白鱗。停杯看柳色，各憶故園春。"]'),
('yuding-29','題廬山山下湯泉','白居易','唐','御定全唐诗','yuding','','[]','一眼湯泉流向東，浸泥澆草暖無功。',32,'御定全唐詩/json/439.json','["一眼湯泉流向東，浸泥澆草暖無功。", "驪山溫水因何事，流入金鋪玉甃中。"]'),
('yuding-30','寄蘄州簟與元九，因題六韻','白居易','唐','御定全唐诗','yuding','','[]','笛竹出蘄春，霜刀劈翠筠。織成雙鎖簟，寄與獨眠人。',72,'御定全唐詩/json/439.json','["笛竹出蘄春，霜刀劈翠筠。織成雙鎖簟，寄與獨眠人。", "卷作筒中信，舒為席上珍。滑如鋪薤葉，冷似臥龍鱗。", "清潤宜乘露，鮮華不受塵。通州炎瘴地，此物最關身。"]'),
('yuding-31','秋熱','白居易','唐','御定全唐诗','yuding','','[]','西江風候接南威，暑氣常多秋氣微。',32,'御定全唐詩/json/439.json','["西江風候接南威，暑氣常多秋氣微。", "猶道江州最涼冷，至今九月著生衣。"]'),
('yuding-32','題元八溪居','白居易','唐','御定全唐诗','yuding','','[]','溪嵐漠漠樹重重，水檻山窗次第逢。晚葉尚開紅躑躅，',40,'御定全唐詩/json/439.json','["溪嵐漠漠樹重重，水檻山窗次第逢。晚葉尚開紅躑躅，", "更愧殷勤留客意，魚鮮飯細酒香濃。"]'),
('yuding-33','晚出西郊','白居易','唐','御定全唐诗','yuding','','[]','散吏閑如客，貧州冷似村。早涼湖北岸，殘照郭西門。',48,'御定全唐詩/json/439.json','["散吏閑如客，貧州冷似村。早涼湖北岸，殘照郭西門。", "懶鑷從須白，休治任眼昏。老來何所用，少興不多言。"]'),
('yuding-34','階下蓮','白居易','唐','御定全唐诗','yuding','','[]','葉展影翻當砌月，花開香散入簾風。',32,'御定全唐詩/json/439.json','["葉展影翻當砌月，花開香散入簾風。", "不如種在天池上，猶勝生於野水中。"]'),
('yuding-35','端居詠懷','白居易','唐','御定全唐诗','yuding','','[]','賈生俟罪心相似，張翰思歸事不如。斜日早知驚鵩鳥，',40,'御定全唐詩/json/439.json','["賈生俟罪心相似，張翰思歸事不如。斜日早知驚鵩鳥，", "從此萬緣都擺落，欲攜妻子買山居。"]'),
('yuding-36','夜宿江浦，聞元八改官，因寄此什','白居易','唐','御定全唐诗','yuding','','[]','君遊丹陛已三遷，我泛滄浪欲二年。劍佩曉趨雙鳳闕，',40,'御定全唐詩/json/439.json','["君遊丹陛已三遷，我泛滄浪欲二年。劍佩曉趨雙鳳闕，", "若報生涯應笑殺，結茅栽芋種畬田。"]'),
('yuding-37','百花亭','白居易','唐','御定全唐诗','yuding','','[]','朱檻在空虛，涼風八月初。山形如峴首，江色似桐廬。',48,'御定全唐詩/json/439.json','["朱檻在空虛，涼風八月初。山形如峴首，江色似桐廬。", "佛寺乘船入，人家枕水居。高亭仍有月，今夜宿何如。"]'),
('yuding-38','江樓早秋','白居易','唐','御定全唐诗','yuding','','[]','南國雖多熱，秋來亦不遲。湖光朝霽後，竹氣晚涼時。',72,'御定全唐詩/json/439.json','["南國雖多熱，秋來亦不遲。湖光朝霽後，竹氣晚涼時。", "樓閣宜佳客，江山入好詩。清風水蘋葉，白露木蘭枝。", "欲作雲泉計，須營伏臘資。匡廬一步地，官滿更何之。"]'),
('yuding-39','送客之湖南','白居易','唐','御定全唐诗','yuding','','[]','年年漸見南方物，事事堪傷北客情。山鬼趫跳唯一足，',40,'御定全唐詩/json/439.json','["年年漸見南方物，事事堪傷北客情。山鬼趫跳唯一足，", "別後雙魚難定寄，近來潮不到湓城。"]'),
('yuding-40','百花亭晚望夜歸','白居易','唐','御定全唐诗','yuding','','[]','百花亭上晚裴回，雲影陰晴掩複開。日色悠揚映山盡，',40,'御定全唐詩/json/439.json','["百花亭上晚裴回，雲影陰晴掩複開。日色悠揚映山盡，", "向夜欲歸愁未了，滿湖明月小船回。"]'),
('yuding-41','西樓','白居易','唐','御定全唐诗','yuding','','[]','小郡大江邊，危樓夕照前。青蕪卑濕地，白露泬寥天。',48,'御定全唐詩/json/439.json','["小郡大江邊，危樓夕照前。青蕪卑濕地，白露泬寥天。", "鄉國此時阻，家書何處傳。仍聞陳蔡戍，轉戰已三年。"]'),
('yuding-42','尋李道士山居，兼呈元明府','白居易','唐','御定全唐诗','yuding','','[]','盡日行還歇，遲遲獨上山。攀藤老筋力，照水病容顏。',48,'御定全唐詩/json/439.json','["盡日行還歇，遲遲獨上山。攀藤老筋力，照水病容顏。", "陶巷招居住，茅家許往還。飽諳榮辱事，無意戀人間。"]'),
('yuding-43','四十五','白居易','唐','御定全唐诗','yuding','','[]','行年四十五，兩鬢半蒼蒼。清瘦詩成癖，粗豪酒放狂。',48,'御定全唐詩/json/439.json','["行年四十五，兩鬢半蒼蒼。清瘦詩成癖，粗豪酒放狂。", "老來尤委命，安處即為鄉。或擬廬山下，來春結草堂。"]'),
('yuding-44','寄李相公、崔侍郎、錢舍人','白居易','唐','御定全唐诗','yuding','','[]','曾陪鶴馭兩三仙，親侍龍輿四五年。天上歡華春有限，',40,'御定全唐詩/json/439.json','["曾陪鶴馭兩三仙，親侍龍輿四五年。天上歡華春有限，", "官滿更歸何處去，香爐峰在宅門前。"]'),
('yuding-45','廳前桂','白居易','唐','御定全唐诗','yuding','','[]','天臺嶺上淩霜樹，司馬廳前委地叢。',32,'御定全唐詩/json/439.json','["天臺嶺上淩霜樹，司馬廳前委地叢。", "一種不生明月裏，山中猶校勝塵中。"]'),
('yuding-46','尋王道士藥堂，因有題贈','白居易','唐','御定全唐诗','yuding','','[]','行行覓路緣松嶠，步步尋花到杏壇。白石先生小有洞，',40,'御定全唐詩/json/439.json','["行行覓路緣松嶠，步步尋花到杏壇。白石先生小有洞，", "但恐長生須有籍，仙台試為檢名看。"]'),
('yuding-47','秋晚','白居易','唐','御定全唐诗','yuding','','[]','籬菊花稀砌桐落，樹陰離離日色薄。單幕疏簾貧寂寞，',40,'御定全唐詩/json/439.json','["籬菊花稀砌桐落，樹陰離離日色薄。單幕疏簾貧寂寞，", "萊妻臥病月明時，不搗寒衣空搗藥。"]'),
('yuding-48','南浦歲暮對酒，送王十五歸京','白居易','唐','御定全唐诗','yuding','','[]','臘後冰生覆湓水，夜來雲暗失廬山。風飄細雪落如米，',40,'御定全唐詩/json/439.json','["臘後冰生覆湓水，夜來雲暗失廬山。風飄細雪落如米，", "相看漸老無過醉，聚散窮通總是閑。"]'),
('yuding-49','除夜','白居易','唐','御定全唐诗','yuding','','[]','薄晚支頤坐，中宵枕臂眠。一從身去國，再見日周天。',48,'御定全唐詩/json/439.json','["薄晚支頤坐，中宵枕臂眠。一從身去國，再見日周天。", "老度江南歲，春拋渭北田。潯陽來早晚，明日是三年。"]'),
('yuding-50','聞李十一出牧澧州，崔二十二出牧果州，因寄絕句','白居易','唐','御定全唐诗','yuding','','[]','平生相見即眉開，靜念無如李與崔。',32,'御定全唐詩/json/439.json','["平生相見即眉開，靜念無如李與崔。", "各是天涯為刺史，緣何不覓九江來。"]'),
('yuding-51','元和十二年淮寇未平詔停歲仗憤然有感率爾成章','白居易','唐','御定全唐诗','yuding','','[]','聞停歲仗軫皇情，應為淮西寇未平。不分氣從歌裏發，',40,'御定全唐詩/json/439.json','["聞停歲仗軫皇情，應為淮西寇未平。不分氣從歌裏發，", "從來妄動多如此，自笑何曾得事成。"]'),
('yuding-52','庾樓新歲','白居易','唐','御定全唐诗','yuding','','[]','歲時銷旅貌，風景觸鄉愁。牢落江湖意，新年上庾樓。',24,'御定全唐詩/json/439.json','["歲時銷旅貌，風景觸鄉愁。牢落江湖意，新年上庾樓。"]'),
('yuding-53','上香爐峰','白居易','唐','御定全唐诗','yuding','','[]','倚石攀蘿歇病身，青筇竹杖白紗巾。',32,'御定全唐詩/json/439.json','["倚石攀蘿歇病身，青筇竹杖白紗巾。", "他時畫出廬山障，便是香爐峰上人。"]'),
('yuding-54','憶微之','白居易','唐','御定全唐诗','yuding','','[]','與君何日出屯蒙，魚戀江湖鳥厭籠。分手各拋滄海畔，',40,'御定全唐詩/json/439.json','["與君何日出屯蒙，魚戀江湖鳥厭籠。分手各拋滄海畔，", "又被新年勸相憶，柳條黃軟欲春風。"]'),
('yuding-55','雨夜贈元十八','白居易','唐','御定全唐诗','yuding','','[]','卑濕沙頭宅，連陰雨夜天。共聽簷溜滴，心事兩悠然。',48,'御定全唐詩/json/439.json','["卑濕沙頭宅，連陰雨夜天。共聽簷溜滴，心事兩悠然。", "把酒迴圈飲，移床曲尺眠。莫言非故舊，相識已三年。"]'),
('yuding-56','寒食江畔','白居易','唐','御定全唐诗','yuding','','[]','草香沙暖水雲晴，風景令人憶帝京。還似往年春氣味，',40,'御定全唐詩/json/439.json','["草香沙暖水雲晴，風景令人憶帝京。還似往年春氣味，", "忽見紫桐花悵望，下邽明日是清明。"]'),
('yuding-57','三月三日登庾樓寄庾三十二','白居易','唐','御定全唐诗','yuding','','[]','三日歡遊辭曲水，二年愁臥在長沙。',32,'御定全唐詩/json/439.json','["三日歡遊辭曲水，二年愁臥在長沙。", "每登高處長相憶，何況茲樓屬庾家。"]'),
('yuding-58','聞李六景儉自河東令授唐鄧行軍司馬，以詩賀之','白居易','唐','御定全唐诗','yuding','','[]','誰能淮上靜風波，聞道河東應此科。不獨文詞供奏記，',40,'御定全唐詩/json/439.json','["誰能淮上靜風波，聞道河東應此科。不獨文詞供奏記，", "四十著緋軍司馬，男兒官職未蹉跎。"]'),
('yuding-59','石榴樹','白居易','唐','御定全唐诗','yuding','','[]','可憐顏色好陰涼，葉翦紅箋花撲霜。傘蓋低垂金翡翠，',40,'御定全唐詩/json/439.json','["可憐顏色好陰涼，葉翦紅箋花撲霜。傘蓋低垂金翡翠，", "見說上林無此樹，只教桃柳占年芳。"]'),
('yuding-60','大林寺桃花','白居易','唐','御定全唐诗','yuding','','[]','人間四月芳菲盡，山寺桃花始盛開。',32,'御定全唐詩/json/439.json','["人間四月芳菲盡，山寺桃花始盛開。", "長恨春歸無覓處，不知轉入此中來。"]'),
('yuding-61','詠懷','白居易','唐','御定全唐诗','yuding','','[]','自從委順任浮沈，漸覺年多功用深。面上減除憂喜色，',40,'御定全唐詩/json/439.json','["自從委順任浮沈，漸覺年多功用深。面上減除憂喜色，", "長笑靈均不知命，江蘺叢畔苦悲吟。"]'),
('yuding-62','早發楚城驛','白居易','唐','御定全唐诗','yuding','','[]','雨過塵埃滅，沿江道徑平。月乘殘夜出，人趁早涼行。',72,'御定全唐詩/json/439.json','["雨過塵埃滅，沿江道徑平。月乘殘夜出，人趁早涼行。", "寂曆閑吟動，冥蒙暗思生。荷塘翻露氣，稻壟瀉泉聲。", "宿犬聞鈴起，棲禽見火驚。曨曨煙樹色，十裏始天明。"]'),
('yuding-63','箬峴東池','白居易','唐','御定全唐诗','yuding','','[]','箬峴亭東有小池，早荷新荇綠參差。',32,'御定全唐詩/json/439.json','["箬峴亭東有小池，早荷新荇綠參差。", "中宵把火行人發，驚起雙棲白鷺鷥。"]'),
('yuding-64','建昌江','白居易','唐','御定全唐诗','yuding','','[]','建昌江水縣門前，立馬教人喚渡船。',32,'御定全唐詩/json/439.json','["建昌江水縣門前，立馬教人喚渡船。", "忽似往年歸蔡渡，草風沙雨渭河邊。"]'),
('yuding-65','哭從弟','白居易','唐','御定全唐诗','yuding','','[]','傷心一尉便終身，叔母年高新婦貧。',32,'御定全唐詩/json/439.json','["傷心一尉便終身，叔母年高新婦貧。", "一片綠衫消不得，腰金拖紫是何人。"]'),
('yuding-66','香爐峰下新卜山居，草堂初成，偶題東壁','白居易','唐','御定全唐诗','yuding','','[]','五架三間新草堂，石階桂柱竹編牆。南簷納日冬天暖，',40,'御定全唐詩/json/439.json','["五架三間新草堂，石階桂柱竹編牆。南簷納日冬天暖，", "來春更葺東廂屋，紙閣蘆簾著孟光。"]'),
('yuding-67','重題','白居易','唐','御定全唐诗','yuding','','[]','喜入山林初息影，厭趨朝市久勞生。早年薄有煙霞志，',160,'御定全唐詩/json/439.json','["喜入山林初息影，厭趨朝市久勞生。早年薄有煙霞志，", "從茲耳界應清淨，免見啾啾毀譽聲。", "長松樹下小溪頭，班鹿胎巾白布裘。藥圃茶園為產業，", "最愛一泉新引得，清泠屈曲繞階流。", "日高睡足猶慵起，小閣重衾不怕寒。遺愛寺鐘欹枕聽，", "心泰身寧是歸處，故鄉何獨在長安。", "宦途自此心長別，世事從今口不言。豈止形骸同土木，", "還有一條遺恨事，高家門館未酬恩。"]'),
('yuding-68','山中問月','白居易','唐','御定全唐诗','yuding','','[]','為問長安月，誰教不相離。昔隨飛蓋處，今照入山時。',72,'御定全唐詩/json/439.json','["為問長安月，誰教不相離。昔隨飛蓋處，今照入山時。", "借助秋懷曠，留連夜臥遲。如歸舊鄉國，似對好親知。", "松下行為伴，溪頭坐有期。千岩將萬壑，無處不相隨。"]'),
('yuding-69','正月十五日夜東林寺學禪偶懷藍田楊主簿因呈智禪師','白居易','唐','御定全唐诗','yuding','','[]','新年三五東林夕，星漢迢迢鐘梵遲。花縣當君行樂夜，',40,'御定全唐詩/json/439.json','["新年三五東林夕，星漢迢迢鐘梵遲。花縣當君行樂夜，", "不覺定中微念起，明朝更問雁門師。"]'),
('yuding-70','臨水坐','白居易','唐','御定全唐诗','yuding','','[]','昔為東掖垣中客，今作西方社內人。',32,'御定全唐詩/json/439.json','["昔為東掖垣中客，今作西方社內人。", "手把楊枝臨水坐，閑思往事似前身。"]'),
('yuding-71','山居','白居易','唐','御定全唐诗','yuding','','[]','山齋方獨往，塵事莫相仍。藍輿辭鞍馬，緇徒換友朋。',48,'御定全唐詩/json/439.json','["山齋方獨往，塵事莫相仍。藍輿辭鞍馬，緇徒換友朋。", "朝餐唯藥菜，夜伴只紗燈。除卻青衫在，其餘便是僧。"]'),
('yuding-72','遺愛寺','白居易','唐','御定全唐诗','yuding','','[]','弄日臨溪坐，尋花繞寺行。時時聞鳥語，處處是泉聲。',24,'御定全唐詩/json/439.json','["弄日臨溪坐，尋花繞寺行。時時聞鳥語，處處是泉聲。"]'),
('yuding-73','山中與元九書，因題書後','白居易','唐','御定全唐诗','yuding','','[]','憶昔封書與君夜，金鑾殿后欲明天。今夜封書在何處，',24,'御定全唐詩/json/439.json','["憶昔封書與君夜，金鑾殿后欲明天。今夜封書在何處，"]'),
('yuding-74','黃石岩下作','白居易','唐','御定全唐诗','yuding','','[]','久別鵷鸞侶，深隨鳥獸群。教他遠親故，何處覓知聞。',36,'御定全唐詩/json/439.json','["久別鵷鸞侶，深隨鳥獸群。教他遠親故，何處覓知聞。", "昔日青雲意，今移向白雲。"]'),
('yuding-75','戲贈李十三判官','白居易','唐','御定全唐诗','yuding','','[]','垂鞭相送醉醺醺，遙見廬山指似君。',32,'御定全唐詩/json/439.json','["垂鞭相送醉醺醺，遙見廬山指似君。", "想君初覺從軍樂，未愛香爐峰上雲。"]'),
('yuding-76','醉中戲贈鄭使君','白居易','唐','御定全唐诗','yuding','','[]','密座移紅毯，酡顏照淥杯。雙娥留且住，五馬任先回。',48,'御定全唐詩/json/439.json','["密座移紅毯，酡顏照淥杯。雙娥留且住，五馬任先回。", "醉耳歌催醒，愁眉笑引開。平生少年興，臨老暫重來。"]'),
('yuding-77','江亭夕望','白居易','唐','御定全唐诗','yuding','','[]','憑高望遠思悠哉，晚上江亭夜未回。日欲沒時紅浪沸，',40,'御定全唐詩/json/439.json','["憑高望遠思悠哉，晚上江亭夜未回。日欲沒時紅浪沸，", "爭敢三年作歸計，心知不及賈生才。"]'),
('yuding-78','酬元員外三月三十日慈恩寺相憶見寄','白居易','唐','御定全唐诗','yuding','','[]','悵望慈恩三月盡，紫桐花落鳥關關。誠知曲水春相憶，',40,'御定全唐詩/json/439.json','["悵望慈恩三月盡，紫桐花落鳥關關。誠知曲水春相憶，", "誰言南國無霜雪，盡在愁人鬢髮間。"]'),
('yuding-79','偶然二首','白居易','唐','御定全唐诗','yuding','','[]','楚懷邪亂靈均直，放棄合宜何惻惻。漢文明聖賈生賢，',80,'御定全唐詩/json/439.json','["楚懷邪亂靈均直，放棄合宜何惻惻。漢文明聖賈生賢，", "月離于畢合滂沱，有時不雨何能測。", "火發城頭魚水裏，救火竭池魚失水。乖龍藏在牛領中，", "六十四卦七十鑽，畢竟不能知所以。"]'),
('yuding-80','中秋月','白居易','唐','御定全唐诗','yuding','','[]','萬里清光不可思，添愁益恨繞天涯，誰人隴外久征戍，',40,'御定全唐詩/json/439.json','["萬里清光不可思，添愁益恨繞天涯，誰人隴外久征戍，", "照他幾許人腸斷，玉兔銀蟾遠不知。"]'),
('yuding-81','謝李六郎中寄新蜀茶','白居易','唐','御定全唐诗','yuding','','[]','故情周匝向交親，新茗分張及病身。紅紙一封書後信，',40,'御定全唐詩/json/439.json','["故情周匝向交親，新茗分張及病身。紅紙一封書後信，", "不寄他人先寄我，應緣我是別茶人。"]'),
('yuding-82','攜諸山客同上香爐峰遇雨而還沾濡狼藉互相笑謔題此解嘲','白居易','唐','御定全唐诗','yuding','','[]','蕭灑登山去，龍鍾遇雨回。磴危攀薜荔，石滑踐莓苔。',48,'御定全唐詩/json/439.json','["蕭灑登山去，龍鍾遇雨回。磴危攀薜荔，石滑踐莓苔。", "襪汙君相謔，鞋穿我自咍。莫欺泥土腳，曾蹋玉階來。"]'),
('yuding-83','彭蠡湖晚歸','白居易','唐','御定全唐诗','yuding','','[]','彭蠡湖天晚，桃花水氣春。鳥飛千白點，日沒半紅輪。',48,'御定全唐詩/json/439.json','["彭蠡湖天晚，桃花水氣春。鳥飛千白點，日沒半紅輪。", "何必為遷客，無勞是病身。何來臨此望，少有不愁人。"]'),
('yuding-84','酬贈李煉師見招','白居易','唐','御定全唐诗','yuding','','[]','幾年司諫直承明，今日求真禮上清。曾犯龍鱗容不死，',40,'御定全唐詩/json/439.json','["幾年司諫直承明，今日求真禮上清。曾犯龍鱗容不死，", "若許移家相近住，便驅雞犬上層城。"]'),
('yuding-85','西河雨夜送客','白居易','唐','御定全唐诗','yuding','','[]','雲黑雨翛翛，江昏水暗流。有風催解纜，無月伴登樓。',48,'御定全唐詩/json/439.json','["雲黑雨翛翛，江昏水暗流。有風催解纜，無月伴登樓。", "酒罷無多興，帆開不少留。唯看一點火，遙認是行舟。"]'),
('yuding-86','登西樓憶行簡','白居易','唐','御定全唐诗','yuding','','[]','每因樓上西南望，始覺人間道路長。礙日暮山青蔟蔟，',40,'御定全唐詩/json/439.json','["每因樓上西南望，始覺人間道路長。礙日暮山青蔟蔟，", "早晚東歸來下峽，穩乘船舫過瞿唐。"]'),
('yuding-87','羅子','白居易','唐','御定全唐诗','yuding','','[]','有女名羅子，生來才兩春。我今年已長，日夜二毛新。',48,'御定全唐詩/json/439.json','["有女名羅子，生來才兩春。我今年已長，日夜二毛新。", "顧念嬌啼面，思量老病身。直應頭似雪，始得見成人。"]'),
('yuding-88','讀僧靈徹詩','白居易','唐','御定全唐诗','yuding','','[]','東林寺裏西廊下，石片鐫題數首詩。',32,'御定全唐詩/json/439.json','["東林寺裏西廊下，石片鐫題數首詩。", "言句怪來還校別，看名知是老湯師。"]'),
('yuding-89','聽李士良琵琶','白居易','唐','御定全唐诗','yuding','','[]','聲似胡兒彈舌語，愁如塞月恨邊雲。',32,'御定全唐詩/json/439.json','["聲似胡兒彈舌語，愁如塞月恨邊雲。", "閒人暫聽猶眉斂，可使和蕃公主聞。"]'),
('yuding-90','昭君怨','白居易','唐','御定全唐诗','yuding','','[]','明妃風貌最娉婷，合在椒房應四星。只得當年備宮掖，',40,'御定全唐詩/json/439.json','["明妃風貌最娉婷，合在椒房應四星。只得當年備宮掖，", "自是君恩薄如紙，不須一向恨丹青。"]'),
('yuding-91','閑吟','白居易','唐','御定全唐诗','yuding','','[]','自從苦學空門法，銷盡平生種種心。',32,'御定全唐詩/json/439.json','["自從苦學空門法，銷盡平生種種心。", "唯有詩魔降未得，每逢風月一閑吟。"]'),
('yuding-92','戲問山石榴','白居易','唐','御定全唐诗','yuding','','[]','小樹山榴近砌栽，半含紅萼帶花來。',32,'御定全唐詩/json/439.json','["小樹山榴近砌栽，半含紅萼帶花來。", "爭知司馬夫人妒，移到庭前便不開。"]'),
('yuding-93','編集拙詩成一十五卷因題卷末戲贈元九、李二十','白居易','唐','御定全唐诗','yuding','','[]','一篇長恨有風情，十首秦吟近正聲。每被老元偷格律，',40,'御定全唐詩/json/439.json','["一篇長恨有風情，十首秦吟近正聲。每被老元偷格律，", "莫怪氣粗言語大，新排十五卷詩成。"]'),
('yuding-94','湖上閑望','白居易','唐','御定全唐诗','yuding','','[]','藤花浪拂紫茸條，菰葉風翻綠剪刀。',32,'御定全唐詩/json/439.json','["藤花浪拂紫茸條，菰葉風翻綠剪刀。", "閑弄水芳生楚思，時時合眼詠離騷。"]'),
('yuding-0','江南謫居十韻','白居易','唐','御定全唐诗','yuding','','[]','自哂沉冥客，曾為獻納臣。壯心徒許國，薄命不如人。',120,'御定全唐詩/json/440.json','["自哂沉冥客，曾為獻納臣。壯心徒許國，薄命不如人。", "才展淩雲翅，俄成失水鱗。葵枯猶向日，蓬斷即辭春。", "澤畔長愁地，天邊欲老身。蕭條殘活計，冷落舊交親。", "草合門無徑，煙消甑有塵。憂方知酒聖，貧始覺錢神。", "虎尾難容足，羊腸易覆輪。行藏與通塞，一切任陶鈞。"]'),
('yuding-1','江樓夜吟元九律詩，成三十韻','白居易','唐','御定全唐诗','yuding','','[]','昨夜江樓上，吟君數十篇。詞飄朱檻底，韻墮淥江前。',360,'御定全唐詩/json/440.json','["昨夜江樓上，吟君數十篇。詞飄朱檻底，韻墮淥江前。", "清楚音諧律，精微思入玄。收將白雪麗，奪盡碧雲妍。", "寸截金為句，雙雕玉作聯。八風淒間發，五彩爛相宣。", "冰扣聲聲冷，珠排字字圓。文頭交比繡，筋骨軟於綿。", "澒湧同波浪，錚鏦過管弦。醴泉流出地，鈞樂下從天。", "神鬼聞如泣，魚龍聽似禪。星回疑聚集，月落為留連。", "雁感無鳴者，猿愁亦悄然。交流遷客淚，停住賈人船。", "暗被歌姬乞，潛聞思婦傳。斜行題粉壁，短卷寫紅箋。", "肉味經時忘，頭風當日痊。老張知定伏，短李愛應顛。", "道屈才方振，身閑業始專。天教聲烜赫，理合命迍邅。", "顧我文章劣，知他氣力全。工夫雖共到，巧拙尚相懸。", "各有詩千首，俱拋海一邊。白頭吟處變，青眼望中穿。", "酬答朝妨食，披尋夜廢眠。老償文債負，宿結字因緣。", "每歎陳夫子，常嗟李謫仙。名高折人爵，思苦減天年。", "不得當時遇，空令後代憐。相悲今若此，湓浦與通川。"]'),
('yuding-2','潯陽歲晚，寄元八郎中、庾三十二員外','白居易','唐','御定全唐诗','yuding','','[]','閱水年將暮，燒金道未成。丹砂不肯死，白髮自須生。',120,'御定全唐詩/json/440.json','["閱水年將暮，燒金道未成。丹砂不肯死，白髮自須生。", "病肺慚杯滿，衰顏忌鏡明。春深舊鄉夢，歲晚故交情。", "一別浮雲散，雙瞻列宿榮。螭頭階下立，龍尾道前行。", "封事頻聞奏，除書數見名。虛懷事僚友，平步取公卿。", "漏盡雞人報，朝回幼女迎。可憐白司馬，老大在湓城。"]'),
('yuding-3','元九以綠絲布白輕褣見寄製成衣服以詩報知','白居易','唐','御定全唐诗','yuding','','[]','綠絲文布素輕褣，珍重京華手自封。貧友遠勞君寄附，',40,'御定全唐詩/json/440.json','["綠絲文布素輕褣，珍重京華手自封。貧友遠勞君寄附，", "欲著卻休知不稱，折腰無復舊形容。"]'),
('yuding-4','清明日送韋侍禦貶虔州','白居易','唐','御定全唐诗','yuding','','[]','寂寞清明日，蕭條司馬家。留餳和冷粥，出火煮新茶。',48,'御定全唐詩/json/440.json','["寂寞清明日，蕭條司馬家。留餳和冷粥，出火煮新茶。", "欲別能無酒，相留亦有花。南遷更何處，此地已天涯。"]'),
('yuding-5','九江春望','白居易','唐','御定全唐诗','yuding','','[]','淼茫積水非吾土，飄泊浮萍自我身。身外信緣為活計，',40,'御定全唐詩/json/440.json','["淼茫積水非吾土，飄泊浮萍自我身。身外信緣為活計，", "此地何妨便終老，譬如元是九江人。"]'),
('yuding-6','晚題東林寺雙池','白居易','唐','御定全唐诗','yuding','','[]','向晚雙池好，初晴百物新。嫋枝翻翠羽，濺水躍紅鱗。',48,'御定全唐詩/json/440.json','["向晚雙池好，初晴百物新。嫋枝翻翠羽，濺水躍紅鱗。", "萍泛同遊子，蓮開當麗人。臨流一惆悵，還憶曲江春。"]'),
('yuding-7','贈內子','白居易','唐','御定全唐诗','yuding','','[]','白髮長興歎，青娥亦伴愁。寒衣補燈下，小女戲床頭。',48,'御定全唐詩/json/440.json','["白髮長興歎，青娥亦伴愁。寒衣補燈下，小女戲床頭。", "暗淡屏幃故，淒涼枕席秋。貧中有等級，猶勝嫁黔婁。"]'),
('yuding-8','送客春遊嶺南二十韻','白居易','唐','御定全唐诗','yuding','','[]','已訝游何遠，仍嗟別太頻。離容君蹙促，贈語我殷勤。',240,'御定全唐詩/json/440.json','["已訝游何遠，仍嗟別太頻。離容君蹙促，贈語我殷勤。", "迢遞天南面，蒼茫海北漘。訶陵國分界，交趾郡為鄰。", "蓊郁三光晦，溫暾四氣勻。陰晴變寒暑，昏曉錯星辰。", "瘴地難為老，蠻陬不易馴。土民稀白首，洞主盡黃巾。", "戰艦猶驚浪，戎車未息塵。紅旗圍卉服，紫綬裹文身。", "面苦桄榔裛，漿酸橄欖新。牙檣迎海舶，銅鼓賽江神。", "不凍貪泉暖，無霜毒草春。雲煙蟒蛇氣，刀劍鱷魚鱗。", "路足羈棲客，官多謫逐臣。天黃生颶母，雨黑長楓人。", "回使先傳語，征軒早返輪。須防杯裏蠱，莫愛橐中珍。", "北與南殊俗，身將貨孰親。嘗聞君子誡，憂道不憂貧。"]'),
('yuding-9','自題','白居易','唐','御定全唐诗','yuding','','[]','功名宿昔人多許，寵辱斯須自不知。一旦失恩先左降，',40,'御定全唐詩/json/440.json','["功名宿昔人多許，寵辱斯須自不知。一旦失恩先左降，", "前事是身俱若此，空門不去欲何之。"]'),
('yuding-10','自悲','白居易','唐','御定全唐诗','yuding','','[]','火宅煎熬地，霜松摧折身。因知群動內，易死不過人。',24,'御定全唐詩/json/440.json','["火宅煎熬地，霜松摧折身。因知群動內，易死不過人。"]'),
('yuding-11','尋郭道士不遇','白居易','唐','御定全唐诗','yuding','','[]','郡中乞假來相訪，洞裏朝元去不逢。看院只留雙白鶴，',40,'御定全唐詩/json/440.json','["郡中乞假來相訪，洞裏朝元去不逢。看院只留雙白鶴，", "欲問參同契中事，更期何日得從容。"]'),
('yuding-12','潯陽春三首：春生','白居易','唐','御定全唐诗','yuding','','[]','春生何處暗周遊，海角天涯遍始休。先遣和風報消息，',40,'御定全唐詩/json/440.json','["春生何處暗周遊，海角天涯遍始休。先遣和風報消息，", "若到故園應覓我，為傳淪落在江州。"]'),
('yuding-13','潯陽春三首：春來','白居易','唐','御定全唐诗','yuding','','[]','春來觸地故鄉情，忽見風光憶兩京。金穀踏花香騎入，',40,'御定全唐詩/json/440.json','["春來觸地故鄉情，忽見風光憶兩京。金穀踏花香騎入，", "獨有不眠不醉客，經春冷坐古湓城。"]'),
('yuding-14','潯陽春三首：春去','白居易','唐','御定全唐诗','yuding','','[]','一從澤畔為遷客，兩度江頭送暮春。白髮更添今日鬢，',40,'御定全唐詩/json/440.json','["一從澤畔為遷客，兩度江頭送暮春。白髮更添今日鬢，", "四十六時三月盡，送春爭得不殷勤。"]'),
('yuding-15','夢微之','白居易','唐','御定全唐诗','yuding','','[]','晨起臨風一惆悵，通川湓水斷相聞。',32,'御定全唐詩/json/440.json','["晨起臨風一惆悵，通川湓水斷相聞。", "不知憶我因何事，昨夜三回夢見君。"]'),
('yuding-16','贈韋煉師','白居易','唐','御定全唐诗','yuding','','[]','潯陽遷客為居士，身似浮雲心似灰。上界女仙無嗜欲，',24,'御定全唐詩/json/440.json','["潯陽遷客為居士，身似浮雲心似灰。上界女仙無嗜欲，"]'),
('yuding-17','問劉十九','白居易','唐','御定全唐诗','yuding','','[]','綠蟻新醅酒，紅泥小火壚。晚來天欲雪，能飲一杯無。',24,'御定全唐詩/json/440.json','["綠蟻新醅酒，紅泥小火壚。晚來天欲雪，能飲一杯無。"]'),
('yuding-18','得行簡書，聞欲下峽，先以詩寄','白居易','唐','御定全唐诗','yuding','','[]','朝來又得東川信，欲取春初發梓州。書報九江聞暫喜，',40,'御定全唐詩/json/440.json','["朝來又得東川信，欲取春初發梓州。書報九江聞暫喜，", "欲寄兩行迎爾淚，長江不肯向西流。"]'),
('yuding-19','南湖早春','白居易','唐','御定全唐诗','yuding','','[]','風回雲斷雨初晴，返照湖邊暖複明。亂點碎紅山杏發，',40,'御定全唐詩/json/440.json','["風回雲斷雨初晴，返照湖邊暖複明。亂點碎紅山杏發，", "不道江南春不好，年年衰病減心情。"]'),
('yuding-20','元十八從事南海欲出廬山臨別舊居有戀泉聲之什因以投和兼伸別情','白居易','唐','御定全唐诗','yuding','','[]','賢侯辟士禮從容，莫戀泉聲問所從。雨露初承黃紙詔，',40,'御定全唐詩/json/440.json','["賢侯辟士禮從容，莫戀泉聲問所從。雨露初承黃紙詔，", "我正退藏君變化，一杯可易得相逢。"]'),
('yuding-21','題韋家泉池','白居易','唐','御定全唐诗','yuding','','[]','泉落青山出白雲，縈村繞郭幾家分。',32,'御定全唐詩/json/440.json','["泉落青山出白雲，縈村繞郭幾家分。", "自從引作池中水，深淺方圓一任君。"]'),
('yuding-22','醉中對紅葉','白居易','唐','御定全唐诗','yuding','','[]','臨風杪秋樹，對酒長年人。醉貌如霜葉，雖紅不是春。',24,'御定全唐詩/json/440.json','["臨風杪秋樹，對酒長年人。醉貌如霜葉，雖紅不是春。"]'),
('yuding-23','遣懷','白居易','唐','御定全唐诗','yuding','','[]','羲和走馭趁年光，不許人間日月長。遂使四時都似電，',40,'御定全唐詩/json/440.json','["羲和走馭趁年光，不許人間日月長。遂使四時都似電，", "已共身心要約定，窮通生死不驚忙。"]'),
('yuding-24','點額魚','白居易','唐','御定全唐诗','yuding','','[]','龍門點額意何如，紅尾青鬐卻返初。',32,'御定全唐詩/json/440.json','["龍門點額意何如，紅尾青鬐卻返初。", "見說在天行雨苦，為龍未必勝為魚。"]'),
('yuding-25','聞龜兒詠詩','白居易','唐','御定全唐诗','yuding','','[]','憐渠已解詠詩章，搖膝支頤學二郎。',32,'御定全唐詩/json/440.json','["憐渠已解詠詩章，搖膝支頤學二郎。", "莫學二郎吟太苦，才年四十鬢如霜。"]'),
('yuding-26','對酒','白居易','唐','御定全唐诗','yuding','','[]','未濟卦中休蔔命，參同契裏莫勞心。',32,'御定全唐詩/json/440.json','["未濟卦中休蔔命，參同契裏莫勞心。", "無如飲此銷愁物，一餉愁消直萬金。"]'),
('yuding-27','東牆夜合樹去秋為風雨所摧，今年花時，悵然有感','白居易','唐','御定全唐诗','yuding','','[]','碧荑紅縷今何在，風雨飄將去不回。',32,'御定全唐詩/json/440.json','["碧荑紅縷今何在，風雨飄將去不回。", "惆悵去年牆下地，今春唯有薺花開。"]'),
('yuding-28','病起','白居易','唐','御定全唐诗','yuding','','[]','病不出門無限時，今朝強出與誰期。',32,'御定全唐詩/json/440.json','["病不出門無限時，今朝強出與誰期。", "經年不上江樓醉，勞動春風颺酒旗。"]'),
('yuding-29','夢亡友劉太白同遊彰敬寺','白居易','唐','御定全唐诗','yuding','','[]','三千裏外臥江州，十五年前哭老劉。',32,'御定全唐詩/json/440.json','["三千裏外臥江州，十五年前哭老劉。", "昨夜夢中彰敬寺，死生魂魄暫同遊。"]'),
('yuding-30','與果上人歿時題此訣別，兼簡二林僧社','白居易','唐','御定全唐诗','yuding','','[]','本結菩提香火社，為嫌煩惱電泡身。',32,'御定全唐詩/json/440.json','["本結菩提香火社，為嫌煩惱電泡身。", "不須惆悵從師去，先請西方作主人。"]'),
('yuding-31','贈寫真者','白居易','唐','御定全唐诗','yuding','','[]','子騁丹青日，予當醜老時。無勞役神思，更畫病容儀。',48,'御定全唐詩/json/440.json','["子騁丹青日，予當醜老時。無勞役神思，更畫病容儀。", "迢遞麒麟閣，圖功未有期。區區尺素上，焉用寫真為。"]'),
('yuding-32','劉十九同宿','白居易','唐','御定全唐诗','yuding','','[]','紅旗破賊非吾事，黃紙除書無我名。',32,'御定全唐詩/json/440.json','["紅旗破賊非吾事，黃紙除書無我名。", "唯共嵩陽劉處士，圍棋賭酒到天明。"]'),
('yuding-33','十二年冬江西溫暖，喜元八寄金石棱到，因題此詩','白居易','唐','御定全唐诗','yuding','','[]','今冬臘候不嚴凝，暖霧溫風氣上騰。山腳崦中才有雪，',24,'御定全唐詩/json/440.json','["今冬臘候不嚴凝，暖霧溫風氣上騰。山腳崦中才有雪，"]'),
('yuding-34','閑意','白居易','唐','御定全唐诗','yuding','','[]','不爭榮耀任沉淪，日與時疏共道親。北省朋僚音信斷，',40,'御定全唐詩/json/440.json','["不爭榮耀任沉淪，日與時疏共道親。北省朋僚音信斷，", "漸老漸諳閒氣味，終身不擬作忙人。"]'),
('yuding-35','送友人上峽赴東川辟命','白居易','唐','御定全唐诗','yuding','','[]','見說瞿塘峽，斜銜灩澦根。難於尋鳥路，險過上龍門。',72,'御定全唐詩/json/440.json','["見說瞿塘峽，斜銜灩澦根。難於尋鳥路，險過上龍門。", "羊角風頭急，桃花水色渾。山回若鼇轉，舟入似鯨吞。", "岸合愁天斷，波跳恐地翻。憐君經此去，為感主人恩。"]'),
('yuding-36','夜送孟司功','白居易','唐','御定全唐诗','yuding','','[]','潯陽白司馬，夜送孟功曹。江暗管弦急，樓明燈火高。',48,'御定全唐詩/json/440.json','["潯陽白司馬，夜送孟功曹。江暗管弦急，樓明燈火高。", "湖波翻似箭，霜草殺如刀。且莫開徵棹，陰風正怒號。"]'),
('yuding-37','衰病','白居易','唐','御定全唐诗','yuding','','[]','老辭遊冶尋花伴，病別荒狂舊酒徒。',32,'御定全唐詩/json/440.json','["老辭遊冶尋花伴，病別荒狂舊酒徒。", "更恐五年三歲後，些些譚笑亦應無。"]'),
('yuding-38','題詩屏風絕句','白居易','唐','御定全唐诗','yuding','','[]','相憶采君詩作障，自書自勘不辭勞。',32,'御定全唐詩/json/440.json','["相憶采君詩作障，自書自勘不辭勞。", "障成定被人爭寫，從此南中紙價高。"]'),
('yuding-39','答微之','白居易','唐','御定全唐诗','yuding','','[]','君寫我詩盈寺壁，我題君句滿屏風。',32,'御定全唐詩/json/440.json','["君寫我詩盈寺壁，我題君句滿屏風。", "與君相遇知何處，兩葉浮萍大海中。"]'),
('yuding-40','偶宴有懷','白居易','唐','御定全唐诗','yuding','','[]','遇興尋文客，因歡命酒徒。春遊憶親故，夜會似京都。',48,'御定全唐詩/json/440.json','["遇興尋文客，因歡命酒徒。春遊憶親故，夜會似京都。", "詩思閑仍在，鄉愁醉暫無。狂來欲起舞，慚見白髭須。"]'),
('yuding-41','山中酬江州崔使君見寄','白居易','唐','御定全唐诗','yuding','','[]','眷眄情無恨，優容禮有餘。三年為郡吏，一半許山居。',48,'御定全唐詩/json/440.json','["眷眄情無恨，優容禮有餘。三年為郡吏，一半許山居。", "酒熟心相待，詩來手自書。庾樓春好醉，明月且回車。"]'),
('yuding-42','山枇杷','白居易','唐','御定全唐诗','yuding','','[]','深山老去惜年華，況對東溪野枇杷。火樹風來翻絳焰，',40,'御定全唐詩/json/440.json','["深山老去惜年華，況對東溪野枇杷。火樹風來翻絳焰，", "爭奈結根深石底，無因移得到人家。"]'),
('yuding-43','聞李尚書拜相，因以長句寄賀微之','白居易','唐','御定全唐诗','yuding','','[]','憐君不久在通川，知已新提造化權。夔契定求才濟世，',40,'御定全唐詩/json/440.json','["憐君不久在通川，知已新提造化權。夔契定求才濟世，", "肯向泥中拋折劍，不收重鑄作龍泉。"]'),
('yuding-44','歲暮','白居易','唐','御定全唐诗','yuding','','[]','窮陰急景坐相催，壯齒韶顏去不回。舊病重因年老發，',40,'御定全唐詩/json/440.json','["窮陰急景坐相催，壯齒韶顏去不回。舊病重因年老發，", "禍福細尋無會處，不如且進手中杯。"]'),
('yuding-45','雨中赴劉十九二林之期及到寺劉已先去因以四韻寄之','白居易','唐','御定全唐诗','yuding','','[]','雲中台殿泥中路，既阻同遊懶卻還。將謂獨愁猶對雨，',40,'御定全唐詩/json/440.json','["雲中台殿泥中路，既阻同遊懶卻還。將謂獨愁猶對雨，", "最惜杜鵑花爛漫，春風吹盡不同攀。"]'),
('yuding-46','薔薇正開春酒初熟因招劉十九張大夫崔二十四同飲','白居易','唐','御定全唐诗','yuding','','[]','甕頭竹葉經春熟，階底薔薇入夏開。似火淺深紅壓架，',40,'御定全唐詩/json/440.json','["甕頭竹葉經春熟，階底薔薇入夏開。似火淺深紅壓架，", "明日早花應更好，心期同醉卯時杯。"]'),
('yuding-47','李白墓','白居易','唐','御定全唐诗','yuding','','[]','採石江邊李白墳，繞田無限草連雲。可憐荒壟窮泉骨，',24,'御定全唐詩/json/440.json','["採石江邊李白墳，繞田無限草連雲。可憐荒壟窮泉骨，"]'),
('yuding-48','對酒','白居易','唐','御定全唐诗','yuding','','[]','漫把參同契，難燒伏火砂。有時成白首，無處問黃芽。',48,'御定全唐詩/json/440.json','["漫把參同契，難燒伏火砂。有時成白首，無處問黃芽。", "幻世如泡影，浮生抵眼花。唯將綠醅酒，且替紫河車。"]'),
('yuding-49','戲答諸少年','白居易','唐','御定全唐诗','yuding','','[]','顧我長年頭似雪，饒君壯歲氣如雲。',32,'御定全唐詩/json/440.json','["顧我長年頭似雪，饒君壯歲氣如雲。", "朱顏今日雖欺我，白髮他時不放君。"]'),
('yuding-50','風雨晚泊','白居易','唐','御定全唐诗','yuding','','[]','苦竹林邊蘆葦叢，停舟一望思無窮。青苔撲地連春雨，',40,'御定全唐詩/json/440.json','["苦竹林邊蘆葦叢，停舟一望思無窮。青苔撲地連春雨，", "此生飄蕩何時定，一縷鴻毛天地中。"]'),
('yuding-51','題崔使君新樓','白居易','唐','御定全唐诗','yuding','','[]','憂人何處可銷憂，碧甕紅欄湓水頭。',32,'御定全唐詩/json/440.json','["憂人何處可銷憂，碧甕紅欄湓水頭。", "從此潯陽風月夜，崔公樓替庾公樓。"]'),
('yuding-52','山中戲問韋侍禦','白居易','唐','御定全唐诗','yuding','','[]','我抱棲雲志，君懷濟世才。常吟反招隱，那得入山來。',24,'御定全唐詩/json/440.json','["我抱棲雲志，君懷濟世才。常吟反招隱，那得入山來。"]'),
('yuding-53','贈曇禪師','白居易','唐','御定全唐诗','yuding','','[]','五年不入慈恩寺，今日尋師始一來。',32,'御定全唐詩/json/440.json','["五年不入慈恩寺，今日尋師始一來。", "欲知火宅焚燒苦，方寸如今化作灰。"]'),
('yuding-54','寄微之','白居易','唐','御定全唐诗','yuding','','[]','帝城行樂日紛紛，天畔窮愁我與君。秦女笑歌春不見，',40,'御定全唐詩/json/440.json','["帝城行樂日紛紛，天畔窮愁我與君。秦女笑歌春不見，", "人生多少歡娛事，那獨千分無一分。"]'),
('yuding-55','醉吟二首','白居易','唐','御定全唐诗','yuding','','[]','空王百法學未得，姹女丹砂燒即飛。',64,'御定全唐詩/json/440.json','["空王百法學未得，姹女丹砂燒即飛。", "事事無成身老也，醉鄉不去欲何歸。", "兩鬢千莖新似雪，十分一醆欲如泥。", "酒狂又引詩魔發，日午悲吟到日西。"]'),
('yuding-56','曉寢','白居易','唐','御定全唐诗','yuding','','[]','轉枕重安寢，回頭一欠伸。紙窗明覺曉，布被暖知春。',48,'御定全唐詩/json/440.json','["轉枕重安寢，回頭一欠伸。紙窗明覺曉，布被暖知春。", "莫強疏慵性，須安老大身。雞鳴一覺睡，不博早朝人。"]'),
('yuding-57','答元八郎中、楊十二博士','白居易','唐','御定全唐诗','yuding','','[]','身覺浮雲無所著，心同止水有何情。但知瀟灑疏朝市，',40,'御定全唐詩/json/440.json','["身覺浮雲無所著，心同止水有何情。但知瀟灑疏朝市，", "誰能拋得人間事，來共騰騰過此生。"]'),
('yuding-58','湖亭與行簡宿','白居易','唐','御定全唐诗','yuding','','[]','潯陽少有風情客，招宿湖亭盡卻回。',32,'御定全唐詩/json/440.json','["潯陽少有風情客，招宿湖亭盡卻回。", "水檻虛涼風月好，夜深誰共阿憐來。"]'),
('yuding-59','八月十五日夜湓亭望月','白居易','唐','御定全唐诗','yuding','','[]','昔年八月十五夜，曲江池畔杏園邊。今年八月十五夜，',40,'御定全唐詩/json/440.json','["昔年八月十五夜，曲江池畔杏園邊。今年八月十五夜，", "臨風一歎無人會，今夜清光似往年。"]'),
('yuding-60','贈江客','白居易','唐','御定全唐诗','yuding','','[]','江柳影寒新雨地，塞鴻聲急欲霜天。',32,'御定全唐詩/json/440.json','["江柳影寒新雨地，塞鴻聲急欲霜天。", "愁君獨向沙頭宿，水繞蘆花月滿船。"]'),
('yuding-61','殘暑招客','白居易','唐','御定全唐诗','yuding','','[]','雲截山腰斷，風驅雨腳回。早陰江上散，殘熱日中來。',48,'御定全唐詩/json/440.json','["雲截山腰斷，風驅雨腳回。早陰江上散，殘熱日中來。", "卻取生衣著，重拈竹簟開。誰能淘晚熱，閑飲兩三杯。"]'),
('yuding-62','潯陽秋懷，贈許明府','白居易','唐','御定全唐诗','yuding','','[]','霜紅二林葉，風白九江波。暝色投煙鳥，秋聲帶雨荷。',72,'御定全唐詩/json/440.json','["霜紅二林葉，風白九江波。暝色投煙鳥，秋聲帶雨荷。", "馬閑無處出，門冷少人過。鹵莽還鄉夢，依稀望闕歌。", "共思除醉外，無計奈愁何。試問陶家酒，新篘得幾多。"]'),
('yuding-63','九日醉吟','白居易','唐','御定全唐诗','yuding','','[]','有恨頭還白，無情菊自黃。一為州司馬，三見歲重陽。',96,'御定全唐詩/json/440.json','["有恨頭還白，無情菊自黃。一為州司馬，三見歲重陽。", "劍匣塵埃滿，籠禽日月長。身從漁父笑，門任雀羅張。", "問疾因留客，聽吟偶置觴。歎時論倚伏，懷舊數存亡。", "奈老應無計，治愁或有方。無過學王績，唯以醉為鄉。"]'),
('yuding-64','問韋山人山甫','白居易','唐','御定全唐诗','yuding','','[]','身名身事兩蹉跎，試就先生問若何。',32,'御定全唐詩/json/440.json','["身名身事兩蹉跎，試就先生問若何。", "從此神仙學得否，白須雖有未為多。"]'),
('yuding-65','送蕭煉師步虛詞十首，卷後以二絕繼之','白居易','唐','御定全唐诗','yuding','','[]','欲上瀛州臨別時，贈君十首步虛詞。',64,'御定全唐詩/json/440.json','["欲上瀛州臨別時，贈君十首步虛詞。", "天仙若愛應相問，可道江州司馬詩。", "花紙瑤緘松墨字，把將天上共誰開。", "試呈王母如堪唱，發遣雙成更取來。"]'),
('yuding-66','贈李兵馬使','白居易','唐','御定全唐诗','yuding','','[]','身得貳師餘氣概，家藏都尉舊詩章。',32,'御定全唐詩/json/440.json','["身得貳師餘氣概，家藏都尉舊詩章。", "江南別有樓船將，燕頷虯須不姓楊。"]'),
('yuding-67','題遺愛寺前溪松','白居易','唐','御定全唐诗','yuding','','[]','偃亞長松樹，侵臨小石溪。靜將流水對，高共遠峰齊。',96,'御定全唐詩/json/440.json','["偃亞長松樹，侵臨小石溪。靜將流水對，高共遠峰齊。", "翠蓋煙籠密，花幢雪壓低。與僧清影坐，借鶴穩枝棲。", "筆寫形難似，琴偷韻易迷。暑天風槭槭，晴夜露淒淒。", "獨契依為舍，閑行繞作蹊。棟樑君莫采，留著伴幽棲。"]'),
('yuding-68','廬山草堂夜雨獨宿寄牛二、李七、庾三十二員外','白居易','唐','御定全唐诗','yuding','','[]','丹霄攜手三君子，白髮垂頭一病翁。蘭省花時錦帳下，',40,'御定全唐詩/json/440.json','["丹霄攜手三君子，白髮垂頭一病翁。蘭省花時錦帳下，", "唯有無生三昧觀，榮枯一照兩成空。"]'),
('yuding-69','聞楊十二新拜省郎，遙以詩賀','白居易','唐','御定全唐诗','yuding','','[]','文昌新入有光輝，紫界宮牆白粉闈。曉日雞人傳漏箭，',40,'御定全唐詩/json/440.json','["文昌新入有光輝，紫界宮牆白粉闈。曉日雞人傳漏箭，", "官職聲名俱入手，近來詩客似君稀。"]'),
('yuding-70','三月三日懷微之','白居易','唐','御定全唐诗','yuding','','[]','良時光景長虛擲，壯歲風情已暗銷。',32,'御定全唐詩/json/440.json','["良時光景長虛擲，壯歲風情已暗銷。", "忽憶同為校書日，每年同醉是今朝。"]'),
('yuding-71','贈韋八','白居易','唐','御定全唐诗','yuding','','[]','辭君歲久見君初，白髮驚嗟兩有餘。容鬢別來今至此，',40,'御定全唐詩/json/440.json','["辭君歲久見君初，白髮驚嗟兩有餘。容鬢別來今至此，", "豈料天南相見夜，哀猿瘴霧宿匡廬。"]'),
('yuding-72','春江閒步，贈張山人','白居易','唐','御定全唐诗','yuding','','[]','江景又妍和，牽愁發浩歌。晴沙金屑色，春水麹塵波。',72,'御定全唐詩/json/440.json','["江景又妍和，牽愁發浩歌。晴沙金屑色，春水麹塵波。", "紅簇交枝杏，青含卷葉荷。藉莎憐軟暖，憩樹愛婆娑。", "書信朝賢斷，知音野老多。相逢不閑語，爭奈日長何。"]'),
('yuding-73','春聽琵琶，兼簡長孫司戶','白居易','唐','御定全唐诗','yuding','','[]','四弦不似琵琶聲，亂寫真珠細撼鈴。指底商風悲颯颯，',40,'御定全唐詩/json/440.json','["四弦不似琵琶聲，亂寫真珠細撼鈴。指底商風悲颯颯，", "遷客共君想勸諫，春腸易斷不須聽。"]'),
('yuding-74','吳宮辭','白居易','唐','御定全唐诗','yuding','','[]','一入吳王殿，無人睹翠娥。樓高時見舞，宮靜夜聞歌。',48,'御定全唐詩/json/440.json','["一入吳王殿，無人睹翠娥。樓高時見舞，宮靜夜聞歌。", "半露胸如雪，斜回臉似波。妍媸各有分，誰敢妒恩多。"]'),
('yuding-75','送韋侍禦量移金州司馬','白居易','唐','御定全唐诗','yuding','','[]','春歡雨露同沾澤，冬歎風霜獨滿衣。留滯多時如我少，',40,'御定全唐詩/json/440.json','["春歡雨露同沾澤，冬歎風霜獨滿衣。留滯多時如我少，", "莫恨東西溝水別，滄溟長短擬同歸。"]'),
('yuding-76','自到潯陽生三女子，因詮真理，用遣妄懷','白居易','唐','御定全唐诗','yuding','','[]','宦途本自安身拙，世累由來向老多。遠謫四年徒已矣，',40,'御定全唐詩/json/440.json','["宦途本自安身拙，世累由來向老多。遠謫四年徒已矣，", "賴學空王治苦法，須拋煩惱入頭陀。"]'),
('yuding-77','江西裴常侍以優禮見待又蒙贈詩輒敘鄙誠用伸感謝','白居易','唐','御定全唐诗','yuding','','[]','一從簪笏事金貂，每借溫顏放折腰。長覺身輕離泥滓，',40,'御定全唐詩/json/440.json','["一從簪笏事金貂，每借溫顏放折腰。長覺身輕離泥滓，", "他日秉鈞如見念，壯心直氣未全銷。"]'),
('yuding-78','自江州司馬授忠州刺史，仰荷聖澤，聊書鄙誠','白居易','唐','御定全唐诗','yuding','','[]','炎瘴拋身遠，泥塗索腳難。網初鱗撥剌，籠久翅摧殘。',72,'御定全唐詩/json/440.json','["炎瘴拋身遠，泥塗索腳難。網初鱗撥剌，籠久翅摧殘。", "雷電頒時令，陽和變歲寒。遺簪承舊念，剖竹授新官。", "鄉覺前程近，心隨外事寬。生還應有分，西笑問長安。"]'),
('yuding-79','除忠州，寄謝崔相公','白居易','唐','御定全唐诗','yuding','','[]','提拔出泥知力竭，吹噓生翅見情深。劍鋒缺折難沖鬥，',40,'御定全唐詩/json/440.json','["提拔出泥知力竭，吹噓生翅見情深。劍鋒缺折難沖鬥，", "忠州好惡何須問，鳥得辭籠不擇林。"]'),
('yuding-80','初除官蒙裴常侍贈鶻銜瑞草緋袍魚袋因謝惠貺兼抒離情','白居易','唐','御定全唐诗','yuding','','[]','新授銅符未著緋，因君裝束始光輝。惠深范叔綈袍贈，',40,'御定全唐詩/json/440.json','["新授銅符未著緋，因君裝束始光輝。惠深范叔綈袍贈，", "明朝戀別朱門淚，不敢多垂恐汙衣。"]'),
('yuding-81','洪州逢熊孺登','白居易','唐','御定全唐诗','yuding','','[]','靖安院裏辛夷下，醉笑狂吟氣最粗。',32,'御定全唐詩/json/440.json','["靖安院裏辛夷下，醉笑狂吟氣最粗。", "莫問別來多少苦，低頭看取白髭須。"]'),
('yuding-82','初著刺史緋，答友人見贈','白居易','唐','御定全唐诗','yuding','','[]','故人安慰善為辭，五十專城道未遲。徒使花袍紅似火，',40,'御定全唐詩/json/440.json','["故人安慰善為辭，五十專城道未遲。徒使花袍紅似火，", "銀印可憐將底用，只堪歸舍嚇妻兒。"]'),
('yuding-83','又答賀客','白居易','唐','御定全唐诗','yuding','','[]','銀章暫假為專城，賀客來多懶起迎。',32,'御定全唐詩/json/440.json','["銀章暫假為專城，賀客來多懶起迎。", "似掛緋衫衣架上，朽株枯竹有何榮。"]'),
('yuding-84','別草堂三絕句','白居易','唐','御定全唐诗','yuding','','[]','正聽山鳥向陽眠，黃紙除書落枕前。',96,'御定全唐詩/json/440.json','["正聽山鳥向陽眠，黃紙除書落枕前。", "為感君恩須暫起，爐峰不擬住多年。", "久眠褐被為居士，忽掛緋袍作使君。", "身出草堂心不出，廬山未要勒移文。", "三間茅舍向山開，一帶山泉繞舍回。", "山色泉聲莫惆悵，三年官滿卻歸來。"]'),
('yuding-85','鐘陵餞送','白居易','唐','御定全唐诗','yuding','','[]','翠幕紅筵高在雲，歌鐘一曲萬家聞。',32,'御定全唐詩/json/440.json','["翠幕紅筵高在雲，歌鐘一曲萬家聞。", "路人指點滕王閣，看送忠州白使君。"]'),
('yuding-86','潯陽宴別','白居易','唐','御定全唐诗','yuding','','[]','鞍馬軍城外，笙歌祖帳前。乘潮發湓口，帶雪別廬山。',48,'御定全唐詩/json/440.json','["鞍馬軍城外，笙歌祖帳前。乘潮發湓口，帶雪別廬山。", "暮景牽行色，春寒散醉顏。共嗟炎瘴地，盡室得生還。"]'),
('yuding-87','戲贈戶部李巡官','白居易','唐','御定全唐诗','yuding','','[]','好去民曹李判官，少貪公事且謀歡。',32,'御定全唐詩/json/440.json','["好去民曹李判官，少貪公事且謀歡。", "男兒未死爭能料，莫作忠州刺史看。"]'),
('yuding-88','行次夏口，先寄李大夫','白居易','唐','御定全唐诗','yuding','','[]','連山斷處大江流，紅旆逶迤鎮上游。幕下翱翔秦禦史，',40,'御定全唐詩/json/440.json','["連山斷處大江流，紅旆逶迤鎮上游。幕下翱翔秦禦史，", "假著緋袍君莫笑，恩深始得向忠州。"]'),
('yuding-89','重贈李大夫','白居易','唐','御定全唐诗','yuding','','[]','早接清班登玉陛，同承別詔直金鑾。鳳巢閣上容身穩，',40,'御定全唐詩/json/440.json','["早接清班登玉陛，同承別詔直金鑾。鳳巢閣上容身穩，", "慚君獨不欺憔悴，猶作銀台舊眼看。"]'),
('yuding-90','對鏡吟','白居易','唐','御定全唐诗','yuding','','[]','閑看明鏡坐清晨，多病姿容半老身。誰論情性乖時事，',40,'御定全唐詩/json/440.json','["閑看明鏡坐清晨，多病姿容半老身。誰論情性乖時事，", "如今所得須甘分，腰佩銀龜朱兩輪。"]'),
('yuding-91','江州赴忠州，至江陵已來，舟中示舍弟五十韻','白居易','唐','御定全唐诗','yuding','','[]','昔作咸秦客，常思江海行。今來仍盡室，此去又專城。',576,'御定全唐詩/json/440.json','["昔作咸秦客，常思江海行。今來仍盡室，此去又專城。", "典午猶為幸，分憂固是榮。簈星州乘送，艛艓驛船迎。", "共載皆妻子，同游即弟兄。寧辭浪跡遠，且貴賞心並。", "雲展帆高掛，飆馳棹迅征。溯流從漢浦，循路轉荊衡。", "山逐時移色，江隨地改名。風光近東早，水木向南清。", "夏口煙孤起，湘川雨半晴。日煎紅浪沸，月射白砂明。", "北渚寒留雁，南枝暖待鶯。駢朱桃露萼，點翠柳含萌。", "亥市魚鹽聚，神林鼓笛鳴。壺漿椒葉氣，歌曲竹枝聲。", "系纜憐沙靜，垂綸愛岸平。水餐紅粒稻，野茹紫花菁。", "甌泛茶如乳，台粘酒似餳。膾長抽錦縷，藕脆削瓊英。", "容易來千里，斯須進一程。未曾勞氣力，漸覺有心情。", "臥穩添春睡，行遲帶酒酲。忽愁牽世網，便欲濯塵纓。", "早接文場戰，曾爭翰苑盟。掉頭稱俊造，翹足取公卿。", "且昧隨時義，徒輸報國誠。眾排恩易失，偏壓勢先傾。", "虎尾憂危切，鴻毛性命輕。燭蛾誰救活，蠶繭自纏縈。", "斂手辭雙闕，回眸望兩京。長沙拋賈誼，漳浦臥劉楨。", "鶗鴂鳴還歇，蟾蜍破又盈。年光同激箭，鄉思極搖旌。", "潦倒親知笑，衰羸舊識驚。烏頭因感白，魚尾為勞赬。", "劍學將何用，丹燒竟不成。孤舟萍一葉，雙鬢雪千莖。", "老見人情盡，閑思物理精。如湯探冷熱，似博鬥輸贏。", "險路應須避，迷途莫共爭。此心知止足，何物要經營。", "玉向泥中潔，松經雪後貞。無妨隱朝市，不必謝寰瀛。", "但在前非悟，期無後患嬰。多知非景福，少語是元亨。", "晦即全身藥，明為伐性兵。昏昏隨世俗，蠢蠢學黎甿。"]'),
('yuding-92','題岳陽樓','白居易','唐','御定全唐诗','yuding','','[]','岳陽城下水漫漫，獨上危樓倚曲欄。春岸綠時連夢澤，',40,'御定全唐詩/json/440.json','["岳陽城下水漫漫，獨上危樓倚曲欄。春岸綠時連夢澤，", "此地唯堪畫圖障，華堂張與貴人看。"]'),
('yuding-93','入峽次巴東','白居易','唐','御定全唐诗','yuding','','[]','不知遠郡何時到，猶喜全家此去同。萬里王程三峽外，',40,'御定全唐詩/json/440.json','["不知遠郡何時到，猶喜全家此去同。萬里王程三峽外，", "兩片紅旌數聲鼓，使君艛艓上巴東。"]'),
('yuding-94','十年三月三十日，別微之於灃上。十四年三月十一日夜，遇微之於峽中，停舟夷陵，三宿而別，言不盡者，以詩終之，因賦七言十七韻以贈，且欲記所遇之地與相見之時，為他年會話張本也','白居易','唐','御定全唐诗','yuding','','[]','灃水店頭春盡日，送君上馬謫通川。夷陵峽口明月夜，',144,'御定全唐詩/json/440.json','["灃水店頭春盡日，送君上馬謫通川。夷陵峽口明月夜，", "坐從日暮唯長歎，語到天明竟未眠。齒發蹉跎將五十，", "往事渺茫都似夢，舊遊流落半歸泉。醉悲灑淚春杯裏，", "別來只是成詩癖，老去何曾更酒顛。各限王程須去住，", "神女台雲閑繚繞，使君灘水急潺湲，風淒暝色愁楊柳，", "君還秦地辭炎徼，我向忠州入瘴煙。未死會應相見在，"]'),
('yuding-95','題峽中石上','白居易','唐','御定全唐诗','yuding','','[]','巫女廟花紅似粉，昭君村柳翠於眉。',32,'御定全唐詩/json/440.json','["巫女廟花紅似粉，昭君村柳翠於眉。", "誠知老去風情少，見此爭無一句詩。"]'),
('yuding-0','夜入瞿唐峽','白居易','唐','御定全唐诗','yuding','','[]','瞿唐天下險，夜上信難哉。岸似雙屏合，天如匹帛開。',49,'御定全唐詩/json/441.json','["瞿唐天下險，夜上信難哉。岸似雙屏合，天如匹帛開。", "逆風驚浪起，拔zB暗船來。欲識愁多少，高於灩澦堆。"]'),
('yuding-1','初到忠州贈李六','白居易','唐','御定全唐诗','yuding','','[]','好在天涯李使君，江頭相見日黃昏。吏人生梗都如鹿，',40,'御定全唐詩/json/441.json','["好在天涯李使君，江頭相見日黃昏。吏人生梗都如鹿，", "更無平地堪行處，虛受朱輪五馬恩。"]'),
('yuding-2','郡齋暇日憶廬山草堂兼寄二林僧社三十韻多敘貶官已來出處之意','白居易','唐','御定全唐诗','yuding','','[]','諫諍知無補，遷移分所當。不堪匡聖主，只合事空王。',360,'御定全唐詩/json/441.json','["諫諍知無補，遷移分所當。不堪匡聖主，只合事空王。", "龍象投新社，鵷鸞失故行。沉吟辭北闕，誘引向西方。", "便住雙林寺，仍開一草堂。平治行道路，安置坐禪床。", "手版支為枕，頭巾閣在牆。先生烏幾舄，居士白衣裳。", "竟歲何曾悶，終身不擬忙。滅除殘夢想，換盡舊心腸。", "世界多煩惱，形神久損傷。正從風鼓浪，轉作日銷霜。", "吾道尋知止，君恩偶未忘。忽蒙頒鳳詔，兼謝剖魚章。", "蓮靜方依水，葵枯重仰陽。三車猶夕會，五馬已晨裝。", "去似尋前世，來如別故鄉。眉低出鷲嶺，腳重下蛇岡。", "漸望廬山遠，彌愁峽路長。香爐峰隱隱，巴字水茫茫。", "瓢掛留庭樹，經收在屋樑。春拋紅藥圃，夏憶白蓮塘。", "唯擬捐塵事，將何答寵光。有期追永遠，無政繼龔黃。", "南國秋猶熱，西齋夜暫涼。閑吟四句偈，靜對一爐香。", "身老同丘井，心空是道場。覓僧為去伴，留俸作歸糧。", "為報山中侶，憑看竹下房。會應歸去在，松菊莫教荒。"]'),
('yuding-3','贈康叟','白居易','唐','御定全唐诗','yuding','','[]','八十秦翁老不歸，南賓太守乞寒衣。',32,'御定全唐詩/json/441.json','["八十秦翁老不歸，南賓太守乞寒衣。", "再三憐汝非他意，天寶遺民見漸稀。"]'),
('yuding-4','鸚鵡','白居易','唐','御定全唐诗','yuding','','[]','竟日語還默，中宵棲複驚。身囚緣彩翠，心苦為分明。',48,'御定全唐詩/json/441.json','["竟日語還默，中宵棲複驚。身囚緣彩翠，心苦為分明。", "暮起歸巢思，春多憶侶聲。誰能拆籠破，從放快飛鳴。"]'),
('yuding-5','京使回累得南省諸公書因以長句詩寄謝蕭五劉二元八吳十一韋大陸郎中崔二十二牛二李七庾三十二李六李十楊三樊大楊十二員外','白居易','唐','御定全唐诗','yuding','','[]','雪壓泥埋未死身，每勞存問愧交親。浮萍飄泊三千里，',40,'御定全唐詩/json/441.json','["雪壓泥埋未死身，每勞存問愧交親。浮萍飄泊三千里，", "瘴鄉得老猶為幸，豈敢傷嗟白髮新。"]'),
('yuding-6','東城春意','白居易','唐','御定全唐诗','yuding','','[]','風軟雲不動，郡城東北隅。晚來春澹澹，天氣似京都。',48,'御定全唐詩/json/441.json','["風軟雲不動，郡城東北隅。晚來春澹澹，天氣似京都。", "弦管隨宜有，杯觴不道無。其如親故遠，無可共歡娛。"]'),
('yuding-7','木蓮樹生巴峽山谷間，巴民亦呼為黃心樹，大者高五丈，涉冬不凋，身如青楊，有白文，葉如桂，厚大無脊，花如蓮，香色豔膩皆同，獨房蕊有異。四月初始開，自開迨謝，僅二十日。忠州西北十里，有鳴玉谿，生者穠茂尤異。元和十四年夏，命道士母丘元志寫，惜其遐僻，因題三絕句云','白居易','唐','御定全唐诗','yuding','','[]','如折芙蓉栽旱地，似拋芍藥掛高枝。',96,'御定全唐詩/json/441.json','["如折芙蓉栽旱地，似拋芍藥掛高枝。", "雲埋水隔無人識，唯有南賓太守知。", "紅似燕支膩如粉，傷心好物不須臾。", "山中風起無時節，明日重來得在無。", "已愁花落荒岩底，複恨根生亂石間。", "幾度欲移移不得，天教拋擲在深山。"]'),
('yuding-8','種桃杏','白居易','唐','御定全唐诗','yuding','','[]','無論海角與天涯，大抵心安即是家。路遠誰能念鄉曲，',24,'御定全唐詩/json/441.json','["無論海角與天涯，大抵心安即是家。路遠誰能念鄉曲，"]'),
('yuding-9','新秋','白居易','唐','御定全唐诗','yuding','','[]','二毛生鏡日，一葉落庭時。老去爭由我，愁來欲泥誰。',48,'御定全唐詩/json/441.json','["二毛生鏡日，一葉落庭時。老去爭由我，愁來欲泥誰。", "空銷閑歲月，不見舊親知。唯弄扶床女，時時強展眉。"]'),
('yuding-10','龍昌寺荷池','白居易','唐','御定全唐诗','yuding','','[]','冷碧新秋水，殘紅半破蓮。從來寥落意，不似此池邊。',24,'御定全唐詩/json/441.json','["冷碧新秋水，殘紅半破蓮。從來寥落意，不似此池邊。"]'),
('yuding-11','聽竹枝贈李侍禦','白居易','唐','御定全唐诗','yuding','','[]','巴童巫女竹枝歌，懊惱何人怨咽多。',32,'御定全唐詩/json/441.json','["巴童巫女竹枝歌，懊惱何人怨咽多。", "暫聽遣君猶悵望，長聞教我複如何。"]'),
('yuding-12','寄胡餅與楊萬州','白居易','唐','御定全唐诗','yuding','','[]','胡麻餅樣學京都，面脆油香新出爐。',32,'御定全唐詩/json/441.json','["胡麻餅樣學京都，面脆油香新出爐。", "寄與饑饞楊大使，嘗看得似輔興無。"]'),
('yuding-13','感櫻桃花，因招飲客','白居易','唐','御定全唐诗','yuding','','[]','櫻桃昨夜開如雪，鬢髮今年白似霜。漸覺花前成老醜，',24,'御定全唐詩/json/441.json','["櫻桃昨夜開如雪，鬢髮今年白似霜。漸覺花前成老醜，"]'),
('yuding-14','東亭閑望','白居易','唐','御定全唐诗','yuding','','[]','東亭盡日坐，誰伴寂寥身。綠桂為佳客，紅蕉當美人。',48,'御定全唐詩/json/441.json','["東亭盡日坐，誰伴寂寥身。綠桂為佳客，紅蕉當美人。", "笑言雖不接，情狀似相親。不作悠悠想，如何度晚春。"]'),
('yuding-15','畫木蓮花圖寄元郎中','白居易','唐','御定全唐诗','yuding','','[]','花房膩似紅蓮朵，豔色鮮如紫牡丹。',32,'御定全唐詩/json/441.json','["花房膩似紅蓮朵，豔色鮮如紫牡丹。", "唯有詩人能解愛，丹青寫出與君看。"]'),
('yuding-16','和李澧州題韋開州經藏詩','白居易','唐','御定全唐诗','yuding','','[]','既悟蓮花藏，須遺貝葉書。菩提無處所，文字本空虛。',48,'御定全唐詩/json/441.json','["既悟蓮花藏，須遺貝葉書。菩提無處所，文字本空虛。", "觀指非知月，忘筌是得魚。聞君登彼岸，舍筏複何如。"]'),
('yuding-17','九日題塗溪','白居易','唐','御定全唐诗','yuding','','[]','蕃草席鋪楓葉岸，竹枝歌送菊花杯。',32,'御定全唐詩/json/441.json','["蕃草席鋪楓葉岸，竹枝歌送菊花杯。", "明年尚作南賓守，或可重陽更一來。"]'),
('yuding-18','即事寄微之','白居易','唐','御定全唐诗','yuding','','[]','畬田澀米不耕鋤，旱地荒園少菜蔬。想念土風今若此，',40,'御定全唐詩/json/441.json','["畬田澀米不耕鋤，旱地荒園少菜蔬。想念土風今若此，", "飽暖饑寒何足道，此身長短是空虛。"]'),
('yuding-19','題郡中荔枝詩十八韻，兼寄萬州楊八使君','白居易','唐','御定全唐诗','yuding','','[]','奇果標南土，芳林對北堂。素華春漠漠，丹實夏煌煌。',216,'御定全唐詩/json/441.json','["奇果標南土，芳林對北堂。素華春漠漠，丹實夏煌煌。", "葉捧低垂戶，枝擎重壓牆。始因風弄色，漸與日爭光。", "夕訝條懸火，朝驚樹點妝。深于紅躑躅，大校白檳榔。", "星綴連心朵，珠排耀眼房。紫羅裁襯殼，白玉裹填瓤。", "早歲曾聞說，今朝始摘嘗。嚼疑天上味，嗅異世間香。", "潤勝蓮生水，鮮逾橘得霜。燕支掌中顆，甘露舌頭漿。", "物少尤珍重，天高苦渺茫。已教生暑月，又使阻遐方。", "粹液靈難駐，妍姿嫩易傷。近南光景熱，向北道途長。", "不得充王賦，無由寄帝鄉。唯君堪擲贈，面白似潘郎。"]'),
('yuding-20','留北客','白居易','唐','御定全唐诗','yuding','','[]','峽外相逢遠，樽前一會難。即須分手別，且強展眉歡。',48,'御定全唐詩/json/441.json','["峽外相逢遠，樽前一會難。即須分手別，且強展眉歡。", "楚袖蕭條舞，巴弦趣數彈。笙歌隨分有，莫作帝鄉看。"]'),
('yuding-21','重寄荔枝與楊使君，時聞楊使君欲種植故有落句之戲','白居易','唐','御定全唐诗','yuding','','[]','摘來正帶淩晨露，寄去須憑下水船。映我緋衫渾不見，',40,'御定全唐詩/json/441.json','["摘來正帶淩晨露，寄去須憑下水船。映我緋衫渾不見，", "聞道萬州方欲種，愁君得吃是何年。"]'),
('yuding-22','和萬州楊使君四絕句：競渡','白居易','唐','御定全唐诗','yuding','','[]','競渡相傳為汨羅，不能止遏意無他。',32,'御定全唐詩/json/441.json','["競渡相傳為汨羅，不能止遏意無他。", "自經放逐來憔悴，能校靈均死幾多。"]'),
('yuding-23','和萬州楊使君四絕句：江邊草','白居易','唐','御定全唐诗','yuding','','[]','聞君澤畔傷春草，憶在天門街裏時。',32,'御定全唐詩/json/441.json','["聞君澤畔傷春草，憶在天門街裏時。", "漠漠淒淒愁滿眼，就中惆悵是江蘺。"]'),
('yuding-24','和萬州楊使君四絕句：嘉慶李','白居易','唐','御定全唐诗','yuding','','[]','東都綠李萬州栽，君手封題我手開。',32,'御定全唐詩/json/441.json','["東都綠李萬州栽，君手封題我手開。", "把得欲嘗先悵望，與渠同別故鄉來。"]'),
('yuding-25','和萬州楊使君四絕句：白槿花','白居易','唐','御定全唐诗','yuding','','[]','秋蕣晚英無豔色，何因栽種在人家。',32,'御定全唐詩/json/441.json','["秋蕣晚英無豔色，何因栽種在人家。", "使君自別羅敷面，爭解回頭愛白花。"]'),
('yuding-26','和行簡望郡南山','白居易','唐','御定全唐诗','yuding','','[]','反照前山雲樹明，從君苦道似華清。',32,'御定全唐詩/json/441.json','["反照前山雲樹明，從君苦道似華清。", "試聽腸斷巴猿叫，早晚驪山有此聲。"]'),
('yuding-27','種荔枝','白居易','唐','御定全唐诗','yuding','','[]','紅顆珍珠誠可愛，白須太守亦何癡。',32,'御定全唐詩/json/441.json','["紅顆珍珠誠可愛，白須太守亦何癡。", "十年結子知誰在，自向庭中種荔枝。"]'),
('yuding-28','陰雨','白居易','唐','御定全唐诗','yuding','','[]','嵐霧今朝重，江山此地深。灘聲秋更急，峽氣曉多陰。',48,'御定全唐詩/json/441.json','["嵐霧今朝重，江山此地深。灘聲秋更急，峽氣曉多陰。", "望闕雲遮眼，思鄉雨滴心。將何慰幽獨，賴此北窗琴。"]'),
('yuding-29','送客歸京','白居易','唐','御定全唐诗','yuding','','[]','水陸四千里，何時歸到秦。舟辭三峽雨，馬入九衢塵。',48,'御定全唐詩/json/441.json','["水陸四千里，何時歸到秦。舟辭三峽雨，馬入九衢塵。", "有酒留行客，無書寄貴人。唯憑遠傳語，好在曲江春。"]'),
('yuding-30','送蕭處士游黔南','白居易','唐','御定全唐诗','yuding','','[]','能文好飲老蕭郎，身似浮雲鬢似霜。生計拋來詩是業，',40,'御定全唐詩/json/441.json','["能文好飲老蕭郎，身似浮雲鬢似霜。生計拋來詩是業，", "不醉黔中爭去得，磨圍山月正蒼蒼。"]'),
('yuding-31','東樓醉','白居易','唐','御定全唐诗','yuding','','[]','天涯深峽無人地，歲暮窮陰欲夜天。',32,'御定全唐詩/json/441.json','["天涯深峽無人地，歲暮窮陰欲夜天。", "不向東樓時一醉，如何擬過二三年。"]'),
('yuding-32','寄微之','白居易','唐','御定全唐诗','yuding','','[]','高天默默物茫茫，各有來由致損傷。鸚為能言長剪翅，',40,'御定全唐詩/json/441.json','["高天默默物茫茫，各有來由致損傷。鸚為能言長剪翅，", "外物竟關身底事，謾排門戟系腰章。"]'),
('yuding-33','東樓招客夜飲','白居易','唐','御定全唐诗','yuding','','[]','莫辭數數醉東樓，除醉無因破得愁。',32,'御定全唐詩/json/441.json','["莫辭數數醉東樓，除醉無因破得愁。", "唯有綠樽紅燭下，暫時不似在忠州。"]'),
('yuding-34','醉後戲題','白居易','唐','御定全唐诗','yuding','','[]','自知清冷似冬淩，每被人呼作律僧。',32,'御定全唐詩/json/441.json','["自知清冷似冬淩，每被人呼作律僧。", "今夜酒醺羅綺暖，被君融盡玉壺冰。"]'),
('yuding-35','冬至夜','白居易','唐','御定全唐诗','yuding','','[]','老去襟懷常濩落，病來須鬢轉蒼浪。心灰不及爐中火，',40,'御定全唐詩/json/441.json','["老去襟懷常濩落，病來須鬢轉蒼浪。心灰不及爐中火，", "今宵始覺房櫳冷，坐索寒衣托孟光。"]'),
('yuding-36','竹枝詞四首','白居易','唐','御定全唐诗','yuding','','[]','瞿唐峽口水煙低，白帝城頭月向西。',128,'御定全唐詩/json/441.json','["瞿唐峽口水煙低，白帝城頭月向西。", "唱到竹枝聲咽處，寒猿暗鳥一時啼。", "竹枝苦怨怨何人，夜靜山空歇又聞。", "蠻兒巴女齊聲唱，愁殺江樓病使君。", "巴東船舫上巴西，波面風生雨腳齊。", "水蓼冷花紅簇簇，江蘺濕葉碧淒淒。", "江畔誰人唱竹枝，前聲斷咽後聲遲。", "怪來調苦緣詞苦，多是通州司馬詩。"]'),
('yuding-37','酬嚴中丞晚眺黔江見寄','白居易','唐','御定全唐诗','yuding','','[]','江水三回曲，愁人兩地情。磨圍山下色，明月峽中聲。',48,'御定全唐詩/json/441.json','["江水三回曲，愁人兩地情。磨圍山下色，明月峽中聲。", "晚後連天碧，秋來徹底清。臨流有新恨，照見白須生。"]'),
('yuding-38','寄題楊萬州四望樓','白居易','唐','御定全唐诗','yuding','','[]','江上新樓名四望，東西南北水茫茫。',32,'御定全唐詩/json/441.json','["江上新樓名四望，東西南北水茫茫。", "無由得與君攜手，同憑欄幹一望鄉。"]'),
('yuding-39','答楊使君登樓見憶','白居易','唐','御定全唐诗','yuding','','[]','忠萬樓中南北望，南州煙水北州雲。',32,'御定全唐詩/json/441.json','["忠萬樓中南北望，南州煙水北州雲。", "兩州何事偏相憶，各是籠禽作使君。"]'),
('yuding-40','除夜','白居易','唐','御定全唐诗','yuding','','[]','歲暮紛多思，天涯渺未歸。老添新甲子，病減舊容輝。',48,'御定全唐詩/json/441.json','["歲暮紛多思，天涯渺未歸。老添新甲子，病減舊容輝。", "鄉國仍留念，功名已息機。明朝四十九，應轉悟前非。"]'),
('yuding-41','聞雷','白居易','唐','御定全唐诗','yuding','','[]','瘴地風霜早，溫天氣候催。窮冬不見雪，正月已聞雷。',48,'御定全唐詩/json/441.json','["瘴地風霜早，溫天氣候催。窮冬不見雪，正月已聞雷。", "震蟄蟲蛇出，驚枯草木開。空餘客方寸，依舊似寒灰。"]'),
('yuding-42','春至','白居易','唐','御定全唐诗','yuding','','[]','若為南國春還至，爭向東樓日又長。白片落梅浮澗水，',40,'御定全唐詩/json/441.json','["若為南國春還至，爭向東樓日又長。白片落梅浮澗水，", "樂事漸無身漸老，從今始擬負風光。"]'),
('yuding-43','感春','白居易','唐','御定全唐诗','yuding','','[]','巫峽中心郡，巴城四面春。草青臨水地，頭白見花人。',48,'御定全唐詩/json/441.json','["巫峽中心郡，巴城四面春。草青臨水地，頭白見花人。", "憂喜皆心火，榮枯是眼塵。除非一杯酒，何物更關身。"]'),
('yuding-44','春江','白居易','唐','御定全唐诗','yuding','','[]','炎涼昏曉苦推遷，不覺忠州已二年。閉閣只聽朝暮鼓，',40,'御定全唐詩/json/441.json','["炎涼昏曉苦推遷，不覺忠州已二年。閉閣只聽朝暮鼓，", "唯有春江看未厭，縈砂繞石淥潺湲。"]'),
('yuding-45','題東樓前李使君所種櫻桃花','白居易','唐','御定全唐诗','yuding','','[]','身入青雲無見日，手栽紅樹又逢春。',32,'御定全唐詩/json/441.json','["身入青雲無見日，手栽紅樹又逢春。", "唯留花向樓前著，故故拋愁與後人。"]'),
('yuding-46','巴水','白居易','唐','御定全唐诗','yuding','','[]','城下巴江水，春來似麹塵。軟沙如渭曲，斜岸憶天津。',48,'御定全唐詩/json/441.json','["城下巴江水，春來似麹塵。軟沙如渭曲，斜岸憶天津。", "影蘸新黃柳，香浮小白蘋。臨流搔首坐，惆悵為何人。"]'),
('yuding-47','野行','白居易','唐','御定全唐诗','yuding','','[]','草潤衫襟重，沙幹屐齒輕。仰頭聽鳥立，信腳望花行。',48,'御定全唐詩/json/441.json','["草潤衫襟重，沙幹屐齒輕。仰頭聽鳥立，信腳望花行。", "暇日無公事，衰年有道情。浮生短於夢，夢裏莫營營。"]'),
('yuding-48','送高侍禦使回，因寄楊八','白居易','唐','御定全唐诗','yuding','','[]','明月峽邊逢制使，黃茅岸上是忠州。',32,'御定全唐詩/json/441.json','["明月峽邊逢制使，黃茅岸上是忠州。", "到城莫說忠州惡，無益虛教楊八愁。"]'),
('yuding-49','奉酬李相公見示絕句','白居易','唐','御定全唐诗','yuding','','[]','碧油幢下捧新詩，榮賤雖殊共一悲。',32,'御定全唐詩/json/441.json','["碧油幢下捧新詩，榮賤雖殊共一悲。", "涕淚滿襟君莫怪，甘泉侍從最多時。"]'),
('yuding-50','喜山石榴花開','白居易','唐','御定全唐诗','yuding','','[]','忠州州裏今日花，廬山山頭去時樹。已憐根損斬新栽，',40,'御定全唐詩/json/441.json','["忠州州裏今日花，廬山山頭去時樹。已憐根損斬新栽，", "但知爛熳恣情開，莫怕南賓桃李妒。"]'),
('yuding-51','戲贈蕭處士、清禪師','白居易','唐','御定全唐诗','yuding','','[]','三杯嵬峨忘機客，百衲頭陀任運僧。',32,'御定全唐詩/json/441.json','["三杯嵬峨忘機客，百衲頭陀任運僧。", "又有放慵巴郡守，不營一事共騰騰。"]'),
('yuding-52','錢虢州以三堂絕句見寄，因以本韻和之','白居易','唐','御定全唐诗','yuding','','[]','同事空王歲月深，相思遠寄定中吟。',32,'御定全唐詩/json/441.json','["同事空王歲月深，相思遠寄定中吟。", "遙知清淨中和化，只用金剛三昧心。"]'),
('yuding-53','三月三日','白居易','唐','御定全唐诗','yuding','','[]','暮春風景初三日，流世光陰半百年。',32,'御定全唐詩/json/441.json','["暮春風景初三日，流世光陰半百年。", "欲作閒遊無好伴，半江惆悵卻回船。"]'),
('yuding-54','寒食夜','白居易','唐','御定全唐诗','yuding','','[]','四十九年身老日，一百五夜月明天。',32,'御定全唐詩/json/441.json','["四十九年身老日，一百五夜月明天。", "抱膝思量何事在，癡男騃女喚秋千。"]'),
('yuding-55','代州民問','白居易','唐','御定全唐诗','yuding','','[]','龍昌寺底開山路，巴子台前種柳林。',32,'御定全唐詩/json/441.json','["龍昌寺底開山路，巴子台前種柳林。", "官職家鄉都忘卻，誰人會得使君心。"]'),
('yuding-56','答州民','白居易','唐','御定全唐诗','yuding','','[]','宦情鬥擻隨塵去，鄉思銷磨逐日無。',32,'御定全唐詩/json/441.json','["宦情鬥擻隨塵去，鄉思銷磨逐日無。", "唯擬騰騰作閒事，遮渠不道使君愚。"]'),
('yuding-57','荔枝樓對酒','白居易','唐','御定全唐诗','yuding','','[]','荔枝新熟雞冠色，燒酒初開琥珀香。',32,'御定全唐詩/json/441.json','["荔枝新熟雞冠色，燒酒初開琥珀香。", "欲摘一枝傾一醆，西樓無客共誰嘗。"]'),
('yuding-58','房家夜宴喜雪，戲贈主人','白居易','唐','御定全唐诗','yuding','','[]','風頭向夜利如刀，賴此溫爐軟錦袍。桑落氣熏珠翠暖，',40,'御定全唐詩/json/441.json','["風頭向夜利如刀，賴此溫爐軟錦袍。桑落氣熏珠翠暖，", "不醉遣儂爭散得，門前雪片似鵝毛。"]'),
('yuding-59','醉後贈人','白居易','唐','御定全唐诗','yuding','','[]','香球趁拍回環匼，花醆拋巡取次飛。',32,'御定全唐詩/json/441.json','["香球趁拍回環匼，花醆拋巡取次飛。", "自入春來未同醉，那能夜去獨先歸。"]'),
('yuding-60','初除尚書郎，脫刺史緋','白居易','唐','御定全唐诗','yuding','','[]','親賓相賀問何如，服色恩光盡反初。頭白喜拋黃草峽，',40,'御定全唐詩/json/441.json','["親賓相賀問何如，服色恩光盡反初。頭白喜拋黃草峽，", "無奈嬌癡三歲女，繞腰啼哭覓金魚。"]'),
('yuding-61','留題開元寺上方','白居易','唐','御定全唐诗','yuding','','[]','東寺台閣好，上方風景清。數來猶未厭，長別豈無情。',48,'御定全唐詩/json/441.json','["東寺台閣好，上方風景清。數來猶未厭，長別豈無情。", "戀水多臨坐，辭花剩繞行。最憐新岸柳，手種未全成。"]'),
('yuding-62','別種東坡花樹兩絕','白居易','唐','御定全唐诗','yuding','','[]','三年留滯在江城，草樹禽魚盡有情。',64,'御定全唐詩/json/441.json','["三年留滯在江城，草樹禽魚盡有情。", "何處殷勤重回首，東坡桃李種新成。", "花林好住莫憔悴，春至但知依舊春。", "樓上明年新太守，不妨還是愛花人。"]'),
('yuding-63','別橋上竹','白居易','唐','御定全唐诗','yuding','','[]','穿橋迸竹不依行，恐礙行人被損傷。',32,'御定全唐詩/json/441.json','["穿橋迸竹不依行，恐礙行人被損傷。", "我去自慚遺愛少，不教君得似甘棠。"]'),
('yuding-64','發白狗峽，次黃牛峽登高寺，卻望忠州','白居易','唐','御定全唐诗','yuding','','[]','白狗次黃牛，灘如竹節稠。路穿天地險，人續古今愁。',120,'御定全唐詩/json/441.json','["白狗次黃牛，灘如竹節稠。路穿天地險，人續古今愁。", "忽見千花塔，因停一葉舟。畏途常迫促，靜境暫淹留。", "巴曲春全盡，巫陽雨半收。北歸雖引領，南望亦回頭。", "昔去悲殊俗，今來念舊遊。別僧山北寺，拋竹水西樓。", "郡樹花如雪，軍廚酒似油。時時大開口，自笑憶忠州。"]'),
('yuding-65','棣華驛見楊八題夢兄弟詩','白居易','唐','御定全唐诗','yuding','','[]','遙聞旅宿夢兄弟，應為郵亭名棣華。',32,'御定全唐詩/json/441.json','["遙聞旅宿夢兄弟，應為郵亭名棣華。", "名作棣華來早晚，自題詩後屬楊家。"]'),
('yuding-66','商山路有感','白居易','唐','御定全唐诗','yuding','','[]','萬里路長在，六年身始歸。所經多舊館，大半主人非。',24,'御定全唐詩/json/441.json','["萬里路長在，六年身始歸。所經多舊館，大半主人非。"]'),
('yuding-67','商山路驛桐樹，昔與微之前後題名處','白居易','唐','御定全唐诗','yuding','','[]','與君前後多遷謫，五度經過此路隅。',32,'御定全唐詩/json/441.json','["與君前後多遷謫，五度經過此路隅。", "笑問中庭老桐樹，這回歸去免來無。"]'),
('yuding-68','惻惻吟','白居易','唐','御定全唐诗','yuding','','[]','惻惻複惻惻，逐臣返鄉國。前事難重論，少年不再得。',48,'御定全唐詩/json/441.json','["惻惻複惻惻，逐臣返鄉國。前事難重論，少年不再得。", "泥塗絳老頭班白，炎瘴靈均面黎黑。六年不死卻歸來，"]'),
('yuding-69','德宗皇帝挽歌詞四首','白居易','唐','御定全唐诗','yuding','','[]','執象宗玄祖，貽謀啟孝孫。文高柏梁殿，禮薄霸陵原。',192,'御定全唐詩/json/441.json','["執象宗玄祖，貽謀啟孝孫。文高柏梁殿，禮薄霸陵原。", "宮仗辭天闕，朝儀出國門。生成不可報，二十七年恩。", "虞帝南巡後，殷宗諒暗中。初辭鑄鼎地，已閉望仙宮。", "曉落當陵月，秋生滿旆風。前星承帝座，不使北辰空。", "業大承宗祖，功成付子孫。睿文詩播樂，遺訓史標言。", "節表中和德，方垂廣利恩。懸知千載後，理代數貞元。", "夢減三齡壽，哀延七月期。寢園愁望遠，宮仗哭行遲。", "雲日添寒慘，笳簫向晚悲。因山有遺詔，如葬漢文時。"]'),
('yuding-70','昭德皇后挽歌詞','白居易','唐','御定全唐诗','yuding','','[]','仙去逍遙境，詩留窈窕章。春歸金屋少，夜入壽宮長。',48,'御定全唐詩/json/441.json','["仙去逍遙境，詩留窈窕章。春歸金屋少，夜入壽宮長。", "鳳引曾辭輦，蠶休昔采桑。陰靈何處感，沙麓月無光。"]'),
('yuding-71','太平樂詞二首','白居易','唐','御定全唐诗','yuding','','[]','歲豐仍節儉，時泰更銷兵。聖念長如此，何憂不太平。',48,'御定全唐詩/json/441.json','["歲豐仍節儉，時泰更銷兵。聖念長如此，何憂不太平。", "湛露浮堯酒，熏風起舜歌。願同堯舜意，所樂在人和。"]'),
('yuding-72','小曲新詞二首','白居易','唐','御定全唐诗','yuding','','[]','霽色鮮宮殿，秋聲脆管弦。聖明千歲樂，歲歲似今年。',48,'御定全唐詩/json/441.json','["霽色鮮宮殿，秋聲脆管弦。聖明千歲樂，歲歲似今年。", "紅裾明月夜，碧簟早秋時。好向昭陽宿，天涼玉漏遲。"]'),
('yuding-73','閨怨詞三首','白居易','唐','御定全唐诗','yuding','','[]','朝憎鶯百囀，夜妒燕雙棲。不慣經春別，誰知到曉啼。',72,'御定全唐詩/json/441.json','["朝憎鶯百囀，夜妒燕雙棲。不慣經春別，誰知到曉啼。", "珠箔籠寒月，紗窗背曉燈。夜來巾上淚，一半是春冰。", "關山征戍遠，閨閣別離難。苦戰應憔悴，寒衣不要寬。"]'),
('yuding-74','殘春曲','白居易','唐','御定全唐诗','yuding','','[]','禁苑殘鶯三四聲，景遲風慢暮春情。',32,'御定全唐詩/json/441.json','["禁苑殘鶯三四聲，景遲風慢暮春情。", "日西無事牆陰下，閑蹋宮花獨自行。"]'),
('yuding-75','長安春','白居易','唐','御定全唐诗','yuding','','[]','青門柳枝軟無力，東風吹作黃金色。',32,'御定全唐詩/json/441.json','["青門柳枝軟無力，東風吹作黃金色。", "街東酒薄醉易醒，滿眼春愁銷不得。"]'),
('yuding-76','長樂坡送人，賦得愁字','白居易','唐','御定全唐诗','yuding','','[]','行人南北分征路，流水東西接禦溝。',32,'御定全唐詩/json/441.json','["行人南北分征路，流水東西接禦溝。", "終日坡前恨離別，謾名長樂是長愁。"]'),
('yuding-77','獨眠吟二首','白居易','唐','御定全唐诗','yuding','','[]','夜長無睡起階前，寥落星河欲曙天。',52,'御定全唐詩/json/441.json','["夜長無睡起階前，寥落星河欲曙天。", "十五年來明月夜，何曾一夜不孤眠。", "獨眠客，夜夜可憐長寂寂。就中今夜最愁人，"]'),
('yuding-78','期不至','白居易','唐','御定全唐诗','yuding','','[]','紅燭清樽久延佇，出門入門天欲曙。',32,'御定全唐詩/json/441.json','["紅燭清樽久延佇，出門入門天欲曙。", "星稀月落竟不來，煙柳朧朧鵲飛去。"]'),
('yuding-79','長洲苑','白居易','唐','御定全唐诗','yuding','','[]','春入長洲草又生，鷓鴣飛起少人行。',32,'御定全唐詩/json/441.json','["春入長洲草又生，鷓鴣飛起少人行。", "年深不辨娃宮處，夜夜蘇台空月明。"]'),
('yuding-80','憶江柳','白居易','唐','御定全唐诗','yuding','','[]','曾栽楊柳江南岸，一別江南兩度春。',32,'御定全唐詩/json/441.json','["曾栽楊柳江南岸，一別江南兩度春。", "遙憶青青江岸上，不知攀折是何人。"]'),
('yuding-81','南浦別','白居易','唐','御定全唐诗','yuding','','[]','南浦淒淒別，西風嫋嫋秋。一看腸一斷，好去莫回頭。',24,'御定全唐詩/json/441.json','["南浦淒淒別，西風嫋嫋秋。一看腸一斷，好去莫回頭。"]'),
('yuding-82','三年別','白居易','唐','御定全唐诗','yuding','','[]','悠悠一別已三年，相望相思明月天。',32,'御定全唐詩/json/441.json','["悠悠一別已三年，相望相思明月天。", "腸斷青天望明月，別來三十六回圓。"]'),
('yuding-83','傷春詞','白居易','唐','御定全唐诗','yuding','','[]','深淺簷花千萬枝，碧紗窗外囀黃鸝。',32,'御定全唐詩/json/441.json','["深淺簷花千萬枝，碧紗窗外囀黃鸝。", "殘妝含淚下簾坐，盡日傷春春不知。"]'),
('yuding-84','後宮詞','白居易','唐','御定全唐诗','yuding','','[]','淚濕羅巾夢不成，夜深前殿按歌聲。',32,'御定全唐詩/json/441.json','["淚濕羅巾夢不成，夜深前殿按歌聲。", "紅顏未老恩先斷，斜倚熏籠坐到明。"]'),
('yuding-0','吟元郎中白須詩，兼飲雪水茶，因題壁上','白居易','唐','御定全唐诗','yuding','','[]','吟詠霜毛句，閑嘗雪水茶。城中展眉處，只是有元家。',24,'御定全唐詩/json/442.json','["吟詠霜毛句，閑嘗雪水茶。城中展眉處，只是有元家。"]'),
('yuding-1','吳七郎中山人，待制班中，偶贈絕句','白居易','唐','御定全唐诗','yuding','','[]','金馬東門只日開，漢庭待詔重仙才。',32,'御定全唐詩/json/442.json','["金馬東門只日開，漢庭待詔重仙才。", "第三松樹非華表，那得遼東鶴下來。"]'),
('yuding-2','和張十八秘書謝裴相公寄馬','白居易','唐','御定全唐诗','yuding','','[]','齒齊膘足毛頭膩，秘閣張郎叱撥駒。洗了頷花翻假錦，',40,'御定全唐詩/json/442.json','["齒齊膘足毛頭膩，秘閣張郎叱撥駒。洗了頷花翻假錦，", "丞相寄來應有意，遣君騎去上雲衢。"]'),
('yuding-3','答山侶','白居易','唐','御定全唐诗','yuding','','[]','頷下髭須半是絲，光陰向後幾多時。非無解掛簪纓意，',40,'御定全唐詩/json/442.json','["頷下髭須半是絲，光陰向後幾多時。非無解掛簪纓意，", "更慚山侶頻傳語，五十歸來道未遲。"]'),
('yuding-4','早朝思退居','白居易','唐','御定全唐诗','yuding','','[]','霜嚴月苦欲明天，忽憶閒居思浩然。自問寒燈夜半起，',40,'御定全唐詩/json/442.json','["霜嚴月苦欲明天，忽憶閒居思浩然。自問寒燈夜半起，", "隨有隨無且歸去，擬求豐足是何年。"]'),
('yuding-5','曲江亭晚望','白居易','唐','御定全唐诗','yuding','','[]','曲江岸北憑欄幹，水面陰生日腳殘。塵路行多綠袍故，',40,'御定全唐詩/json/442.json','["曲江岸北憑欄幹，水面陰生日腳殘。塵路行多綠袍故，", "不被馬前提省印，何人通道是郎官。"]'),
('yuding-6','初除主客郎中知制誥與王十一李七元九三舍人中書同宿話舊感懷','白居易','唐','御定全唐诗','yuding','','[]','閑宵靜話喜還悲，聚散窮通不自知。已分雲泥行異路，',40,'御定全唐詩/json/442.json','["閑宵靜話喜還悲，聚散窮通不自知。已分雲泥行異路，", "莫怪不如君氣味，此中來校十年遲。"]'),
('yuding-7','西省對花憶忠州東坡新花樹，因寄題東樓','白居易','唐','御定全唐诗','yuding','','[]','每看闕下丹青樹，不忘天邊錦繡林。西掖垣中今日眼，',40,'御定全唐詩/json/442.json','["每看闕下丹青樹，不忘天邊錦繡林。西掖垣中今日眼，", "最憶東坡紅爛熳，野桃山杏水林檎。"]'),
('yuding-8','寄題忠州小樓桃花','白居易','唐','御定全唐诗','yuding','','[]','再游巫峽知何日，總是秦人說向誰。',32,'御定全唐詩/json/442.json','["再游巫峽知何日，總是秦人說向誰。", "長憶小樓風月夜，紅欄幹上兩三枝。"]'),
('yuding-9','中書連直，寒食不歸，因懷元九','白居易','唐','御定全唐诗','yuding','','[]','去歲清明日，南巴古郡樓。今年寒食夜，西省鳳池頭。',72,'御定全唐詩/json/442.json','["去歲清明日，南巴古郡樓。今年寒食夜，西省鳳池頭。", "並上新人直，難隨舊伴遊。誠知視草貴，未免對花愁。", "鬢髮莖莖白，光陰寸寸流。經春不同宿，何異在忠州。"]'),
('yuding-10','春憶二林寺舊遊，因寄朗、滿、晦三上人','白居易','唐','御定全唐诗','yuding','','[]','一別東林三度春，每春常似憶情親。頭陀會裏為逋客，',40,'御定全唐詩/json/442.json','["一別東林三度春，每春常似憶情親。頭陀會裏為逋客，", "最慚僧社題橋處，十八人名空一人。"]'),
('yuding-11','和元少尹新授官','白居易','唐','御定全唐诗','yuding','','[]','官穩身應泰，春風信馬行。縱忙無苦事，雖病有心情。',48,'御定全唐詩/json/442.json','["官穩身應泰，春風信馬行。縱忙無苦事，雖病有心情。", "厚祿兒孫飽，前驅道路榮。花時八入直，無暇賀元兄。"]'),
('yuding-12','朝回和元少尹絕句','白居易','唐','御定全唐诗','yuding','','[]','朝客朝回回望好，盡紆朱紫佩金銀。',32,'御定全唐詩/json/442.json','["朝客朝回回望好，盡紆朱紫佩金銀。", "此時獨與君為伴，馬上青袍唯兩人。"]'),
('yuding-13','重和元少尹','白居易','唐','御定全唐诗','yuding','','[]','鳳閣舍人京亞尹，白頭俱未著緋衫。',32,'御定全唐詩/json/442.json','["鳳閣舍人京亞尹，白頭俱未著緋衫。", "南宮起請無消息，朝散何時得入銜。"]'),
('yuding-14','中書夜直夢忠州','白居易','唐','御定全唐诗','yuding','','[]','閣下燈前夢，巴南城裏遊。覓花來渡口，尋寺到山頭。',48,'御定全唐詩/json/442.json','["閣下燈前夢，巴南城裏遊。覓花來渡口，尋寺到山頭。", "江色分明綠，猿聲依舊愁。禁鐘驚睡覺，唯不上東樓。"]'),
('yuding-15','醉後','白居易','唐','御定全唐诗','yuding','','[]','酒後高歌且放狂，門前閒事莫思量。',32,'御定全唐詩/json/442.json','["酒後高歌且放狂，門前閒事莫思量。", "猶嫌小戶長先醒，不得多時住醉鄉。"]'),
('yuding-16','待漏入閣書事，奉贈元九學士閣老','白居易','唐','御定全唐诗','yuding','','[]','衙排宣政仗，門啟紫宸關。彩筆停書命，花磚趁立班。',120,'御定全唐詩/json/442.json','["衙排宣政仗，門啟紫宸關。彩筆停書命，花磚趁立班。", "稀星點銀礫，殘月墮金環。暗漏猶傳水，明河漸下山。", "從東分地色，向北仰天顏。碧縷爐煙直，紅垂佩尾閑。", "綸闈慚併入，翰苑忝先攀。笑我青袍故，饒君茜綬殷。", "詩仙歸洞裏，酒病滯人間。好去鴛鸞侶，沖天便不還。"]'),
('yuding-17','晚春重到集賢院','白居易','唐','御定全唐诗','yuding','','[]','官曹清切非人境，風月鮮明是洞天。滿砌荊花鋪紫毯，',40,'御定全唐詩/json/442.json','["官曹清切非人境，風月鮮明是洞天。滿砌荊花鋪紫毯，", "虛薄至今慚舊職，院名抬舉號為賢。"]'),
('yuding-18','紫薇花','白居易','唐','御定全唐诗','yuding','','[]','絲綸閣下文書靜，鐘鼓樓中刻漏長。',32,'御定全唐詩/json/442.json','["絲綸閣下文書靜，鐘鼓樓中刻漏長。", "獨坐黃昏誰是伴，紫薇花對紫微郎。"]'),
('yuding-19','後宮詞','白居易','唐','御定全唐诗','yuding','','[]','雨露由來一點恩，爭能遍佈及千門。',32,'御定全唐詩/json/442.json','["雨露由來一點恩，爭能遍佈及千門。", "三千宮女胭脂面，幾個春來無淚痕。"]'),
('yuding-20','卜居','白居易','唐','御定全唐诗','yuding','','[]','遊宦京都二十春，貧中無處可安貧。長羨蝸牛猶有舍，',40,'御定全唐詩/json/442.json','["遊宦京都二十春，貧中無處可安貧。長羨蝸牛猶有舍，", "但道吾廬心便足，敢辭湫隘與囂塵。"]'),
('yuding-21','題新居寄元八','白居易','唐','御定全唐诗','yuding','','[]','青龍岡北近西邊，移入新居便泰然。冷巷閉門無客到，',40,'御定全唐詩/json/442.json','["青龍岡北近西邊，移入新居便泰然。冷巷閉門無客到，", "莫羨升平元八宅，自思買用幾多錢。"]'),
('yuding-22','登龍尾道南望，憶廬山舊隱','白居易','唐','御定全唐诗','yuding','','[]','龍尾道邊來一望，香爐峰下去無因。青山舉眼三千里，',40,'御定全唐詩/json/442.json','["龍尾道邊來一望，香爐峰下去無因。青山舉眼三千里，", "君恩壯健猶難報，況被年年老逼身。"]'),
('yuding-23','馮閣老處見與嚴郎中酬和詩，因戲贈絕句','白居易','唐','御定全唐诗','yuding','','[]','乍來天上宜清淨，不用回頭望故山。',32,'御定全唐詩/json/442.json','["乍來天上宜清淨，不用回頭望故山。", "縱有舊游君莫憶，塵心起即墮人間。"]'),
('yuding-24','見於給事暇日上直寄南省諸郎官詩，因以戲贈','白居易','唐','御定全唐诗','yuding','','[]','倚作天仙弄地仙，誇張一日抵千年。黃麻敕勝長生籙，',40,'御定全唐詩/json/442.json','["倚作天仙弄地仙，誇張一日抵千年。黃麻敕勝長生籙，", "東曹漸去西垣近，鶴駕無妨更著鞭。"]'),
('yuding-25','題新昌所居','白居易','唐','御定全唐诗','yuding','','[]','宅小人煩悶，泥深馬鈍頑。街東閑處住，日午熱時還。',48,'御定全唐詩/json/442.json','["宅小人煩悶，泥深馬鈍頑。街東閑處住，日午熱時還。", "院窄難栽竹，牆高不見山。唯應方寸內，此地覓寬閑。"]'),
('yuding-26','西省北院新構小亭種竹開窗東通騎省與李常侍隔窗小飲各題四韻','白居易','唐','御定全唐诗','yuding','','[]','結托白須伴，因依青竹叢。題詩新壁上，過酒小窗中。',48,'御定全唐詩/json/442.json','["結托白須伴，因依青竹叢。題詩新壁上，過酒小窗中。", "深院晚無日，虛簷涼有風。金貂醉看好，回首紫垣東。"]'),
('yuding-27','酬元郎中同制加朝散大夫，書懷見贈','白居易','唐','御定全唐诗','yuding','','[]','命服雖同黃紙上，官班不共紫垣前。青衫脫早差三日，',48,'御定全唐詩/json/442.json','["命服雖同黃紙上，官班不共紫垣前。青衫脫早差三日，", "終身擬作臥雲伴，逐月須收燒藥錢。五品足為婚嫁主，"]'),
('yuding-28','初著緋戲贈元九','白居易','唐','御定全唐诗','yuding','','[]','晚遇緣才拙，先衰被病牽。那知垂白日，始是著緋年。',48,'御定全唐詩/json/442.json','["晚遇緣才拙，先衰被病牽。那知垂白日，始是著緋年。", "身外名徒爾，人間事偶然。我朱君紫綬，猶未得差肩。"]'),
('yuding-29','和韓侍郎苦雨','白居易','唐','御定全唐诗','yuding','','[]','潤氣凝柱礎，繁聲注瓦溝。暗留窗不曉，涼引簟先秋。',48,'御定全唐詩/json/442.json','["潤氣凝柱礎，繁聲注瓦溝。暗留窗不曉，涼引簟先秋。", "葉濕蠶應病，泥稀燕亦愁。仍聞放朝夜，誤出到街頭。"]'),
('yuding-30','連雨','白居易','唐','御定全唐诗','yuding','','[]','風雨暗蕭蕭，雞鳴暮複朝。碎聲籠苦竹，冷翠落芭蕉。',48,'御定全唐詩/json/442.json','["風雨暗蕭蕭，雞鳴暮複朝。碎聲籠苦竹，冷翠落芭蕉。", "水鳥投簷宿，泥蛙入戶跳。仍聞蕃客見，明日欲追朝。"]'),
('yuding-31','初加朝散大夫又轉上柱國','白居易','唐','御定全唐诗','yuding','','[]','紫微今日煙霄地，赤嶺前年泥土身。得水魚還動鱗鬣，',40,'御定全唐詩/json/442.json','["紫微今日煙霄地，赤嶺前年泥土身。得水魚還動鱗鬣，", "柱國勳成私自問，有何功德及生人。"]'),
('yuding-32','行簡初授拾遺，同早朝入閣，因示十二韻','白居易','唐','御定全唐诗','yuding','','[]','夜色尚蒼蒼，槐陰夾路長。聽鐘出長樂，傳鼓到新昌。',144,'御定全唐詩/json/442.json','["夜色尚蒼蒼，槐陰夾路長。聽鐘出長樂，傳鼓到新昌。", "宿雨沙堤潤，秋風樺燭香。馬驕欺地軟，人健得天涼。", "待漏排閶闔，停珂擁建章。爾隨黃合老，吾次紫微郎。", "併入連稱籍，齊趨對折方。鬥班花接萼，綽立雁分行。", "近職誠為美，微才豈合當。綸言難下筆，諫紙易盈箱。", "老去何僥倖，時來不料量。唯求殺身地，相誓答恩光。"]'),
('yuding-33','立秋日登樂遊園','白居易','唐','御定全唐诗','yuding','','[]','獨行獨語曲江頭，回馬遲遲上樂遊。',32,'御定全唐詩/json/442.json','["獨行獨語曲江頭，回馬遲遲上樂遊。", "蕭颯涼風與衰鬢，誰教計會一時秋。"]'),
('yuding-34','新秋早起，有懷元少尹','白居易','唐','御定全唐诗','yuding','','[]','秋來轉覺此身衰，晨起臨階盥漱時。漆匣鏡明頭盡白，',40,'御定全唐詩/json/442.json','["秋來轉覺此身衰，晨起臨階盥漱時。漆匣鏡明頭盡白，", "老去相逢無別計，強開笑口展愁眉。"]'),
('yuding-35','夜箏','白居易','唐','御定全唐诗','yuding','','[]','紫袖紅弦明月中，自彈自感暗低容。',32,'御定全唐詩/json/442.json','["紫袖紅弦明月中，自彈自感暗低容。", "弦凝指咽聲停處，別有深情一萬重。"]'),
('yuding-36','妻初授邑號告身','白居易','唐','御定全唐诗','yuding','','[]','弘農舊縣授新封，鈿軸金泥誥一通。我轉官階常自愧，',40,'御定全唐詩/json/442.json','["弘農舊縣授新封，鈿軸金泥誥一通。我轉官階常自愧，", "倚得身名便慵墮，日高猶睡綠窗中。"]'),
('yuding-37','送客南遷','白居易','唐','御定全唐诗','yuding','','[]','我說南中事，君應不願聽。曾經身困苦，不覺語叮嚀。',145,'御定全唐詩/json/442.json','["我說南中事，君應不願聽。曾經身困苦，不覺語叮嚀。", "燒處愁雲夢，波時憶洞庭。春畬煙勃勃，秋瘴露冥冥。", "蚊蚋經冬活，魚龍欲雨腥。水蟲能射影，山鬼解藏形。", "穴掉巴蛇尾，林飄鴆鳥翎。颶風千里黑，qL草四時青。", "客似驚弦雁，舟如委浪萍。誰人勸言笑，何計慰漂零。", "慎勿琴離膝，長須酒滿瓶。大都從此去，宜醉不宜醒。"]'),
('yuding-38','暮歸','白居易','唐','御定全唐诗','yuding','','[]','不覺百年半，何曾一日閑。朝隨燭影出，暮趁鼓聲還。',48,'御定全唐詩/json/442.json','["不覺百年半，何曾一日閑。朝隨燭影出，暮趁鼓聲還。", "甕裏非無酒，牆頭亦有山。歸來長困臥，早晚得開顏。"]'),
('yuding-39','寄遠','白居易','唐','御定全唐诗','yuding','','[]','欲忘忘未得，欲去去無由。兩腋不生翅，二毛空滿頭。',48,'御定全唐詩/json/442.json','["欲忘忘未得，欲去去無由。兩腋不生翅，二毛空滿頭。", "坐看新落葉，行上最高樓。暝色無邊際，茫茫盡眼愁。"]'),
('yuding-40','舊房','白居易','唐','御定全唐诗','yuding','','[]','遠壁秋聲蟲絡絲，入簷新影月低眉。',32,'御定全唐詩/json/442.json','["遠壁秋聲蟲絡絲，入簷新影月低眉。", "床帷半故簾旌斷，仍是初寒欲夜時。"]'),
('yuding-41','錢侍郎使君以題廬山草堂詩見寄，因酬之','白居易','唐','御定全唐诗','yuding','','[]','殷勤江郡守，悵望掖垣郎。慚見新瓊什，思歸舊草堂。',48,'御定全唐詩/json/442.json','["殷勤江郡守，悵望掖垣郎。慚見新瓊什，思歸舊草堂。", "事隨心未得，名與道相妨。若不休官去，人間到老忙。"]'),
('yuding-42','寄山僧','白居易','唐','御定全唐诗','yuding','','[]','眼看過半百，早晚掃岩扉。白首誰能住，青山自不歸。',48,'御定全唐詩/json/442.json','["眼看過半百，早晚掃岩扉。白首誰能住，青山自不歸。", "百千萬劫障，四十九年非。會擬抽身去，當風斗擻衣。"]'),
('yuding-43','慈恩寺有感','白居易','唐','御定全唐诗','yuding','','[]','自問有何惆悵事，寺門臨入卻遲回。',32,'御定全唐詩/json/442.json','["自問有何惆悵事，寺門臨入卻遲回。", "李家哭泣元家病，柿葉紅時獨自來。"]'),
('yuding-44','酬嚴十八郎中見示','白居易','唐','御定全唐诗','yuding','','[]','口厭含香握厭蘭，紫微青瑣舉頭看。忽驚鬢後蒼浪發，',40,'御定全唐詩/json/442.json','["口厭含香握厭蘭，紫微青瑣舉頭看。忽驚鬢後蒼浪發，", "承明長短君應入，莫憶家江七裏灘。"]'),
('yuding-45','寄王秘書','白居易','唐','御定全唐诗','yuding','','[]','霜菊花萎日，風梧葉碎時。怪來秋思苦，緣詠秘書詩。',24,'御定全唐詩/json/442.json','["霜菊花萎日，風梧葉碎時。怪來秋思苦，緣詠秘書詩。"]'),
('yuding-46','中書寓直','白居易','唐','御定全唐诗','yuding','','[]','繚繞宮牆圍禁林，半開閶闔曉沉沉。天晴更覺南山近，',40,'御定全唐詩/json/442.json','["繚繞宮牆圍禁林，半開閶闔曉沉沉。天晴更覺南山近，", "自嫌野物將何用，土木形骸麋鹿心。"]'),
('yuding-47','自問','白居易','唐','御定全唐诗','yuding','','[]','黑花滿眼絲滿頭，早衰因病病因愁。',32,'御定全唐詩/json/442.json','["黑花滿眼絲滿頭，早衰因病病因愁。", "宦途氣味已諳盡，五十不休何日休。"]'),
('yuding-48','曲江獨行，招張十八','白居易','唐','御定全唐诗','yuding','','[]','曲江新歲後，冰與水相和。南岸猶殘雪，東風未有波。',48,'御定全唐詩/json/442.json','["曲江新歲後，冰與水相和。南岸猶殘雪，東風未有波。", "偶遊身獨自，相憶意如何。莫待春深去，花時鞍馬多。"]'),
('yuding-49','新居早春二首','白居易','唐','御定全唐诗','yuding','','[]','靜巷無來客，深居不出門。鋪沙蓋苔面，掃雪擁松根。',96,'御定全唐詩/json/442.json','["靜巷無來客，深居不出門。鋪沙蓋苔面，掃雪擁松根。", "漸暖宜閒步，初晴愛小園。覓花都未有，唯覺樹枝繁。", "地潤東風暖，閑行蹋草芽。呼童遣移竹，留客伴嘗茶。", "溜滴簷冰盡，塵浮隙日斜。新居未曾到，鄰里是誰家。"]'),
('yuding-50','新昌新居書事四十韻，因寄元郎中、張博士','白居易','唐','御定全唐诗','yuding','','[]','冒寵已三遷，歸期始二年。囊中貯餘俸，園外買閒田。',480,'御定全唐詩/json/442.json','["冒寵已三遷，歸期始二年。囊中貯餘俸，園外買閒田。", "狐兔同三徑，蒿萊共一廛。新園聊剗穢，舊屋且扶顛。", "簷漏移傾瓦，梁欹換蠹椽。平治繞台路，整頓近階磚。", "巷狹開容駕，牆低壘過肩。門閭堪駐蓋，堂室可鋪筵。", "丹鳳樓當後，青龍寺在前。市街塵不到，宮樹影相連。", "省史嫌坊遠，豪家笑地偏。敢勞賓客訪，或望子孫傳。", "不覓他人愛，唯將自性便。等閒栽樹木，隨分占風煙。", "逸致因心得，幽期遇境牽。松聲疑澗底，草色勝河邊。", "虛潤冰銷地，晴和日出天。苔行滑如簟，莎坐軟於綿。", "簾每當山卷，帷多帶月褰。籬東花掩映，窗北竹嬋娟。", "跡慕青門隱，名慚紫禁仙。假歸思晚沐，朝去戀春眠。", "拙薄才無取，疏慵職不專。題牆書命筆，沽酒率分錢。", "柏杵舂靈藥，銅瓶漱暖泉。爐香穿蓋散，籠燭隔紗然。", "陳室何曾掃，陶琴不要弦。屏除俗事盡，養活道情全。", "尚有妻孥累，猶為組綬纏。終須拋爵祿，漸擬斷腥膻。", "大抵宗莊叟，私心事竺幹。浮榮水劃字，真諦火生蓮。", "梵部經十二，玄書字五千。是非都付夢，語默不妨禪。", "博士官猶冷，郎中病已痊。多同僻處住，久結靜中緣。", "緩步攜筇杖，徐吟展蜀箋。老宜閑語話，悶憶好詩篇。", "蠻榼來方瀉，蒙茶到始煎。無辭數相見，鬢髮各蒼然。"]'),
('yuding-51','喜敏中及第，偶示所懷','白居易','唐','御定全唐诗','yuding','','[]','自知群從為儒少，豈料詞場中第頻。桂折一枝先許我，',40,'御定全唐詩/json/442.json','["自知群從為儒少，豈料詞場中第頻。桂折一枝先許我，", "莫學爾兄年五十，蹉跎始得掌絲綸。"]'),
('yuding-52','久不見韓侍郎，戲題四韻以寄之','白居易','唐','御定全唐诗','yuding','','[]','近來韓閣老，疏我我心知。戶大嫌甜酒，才高笑小詩。',48,'御定全唐詩/json/442.json','["近來韓閣老，疏我我心知。戶大嫌甜酒，才高笑小詩。", "靜吟乖月夜，閑醉曠花時。還有愁同處，春風滿鬢絲。"]'),
('yuding-53','寄白頭陀','白居易','唐','御定全唐诗','yuding','','[]','近見頭陀伴，雲師老更慵。性靈閑似鶴，顏狀古於松。',48,'御定全唐詩/json/442.json','["近見頭陀伴，雲師老更慵。性靈閑似鶴，顏狀古於松。", "山裏猶難覓，人間豈易逢。仍聞移住處，太白最高峰。"]'),
('yuding-54','和韓侍郎題楊舍人林池見寄','白居易','唐','御定全唐诗','yuding','','[]','渠水暗流春凍解，風吹日炙不成凝。',32,'御定全唐詩/json/442.json','["渠水暗流春凍解，風吹日炙不成凝。", "鳳池冷暖君諳在，二月因何更有冰。"]'),
('yuding-55','勤政樓西老柳','白居易','唐','御定全唐诗','yuding','','[]','半朽臨風樹，多情立馬人。開元一株柳，長慶二年春。',24,'御定全唐詩/json/442.json','["半朽臨風樹，多情立馬人。開元一株柳，長慶二年春。"]'),
('yuding-56','偶題閣下廳','白居易','唐','御定全唐诗','yuding','','[]','靜愛青苔院，深宜白鬢翁。貌將松共瘦，心與竹俱空。',48,'御定全唐詩/json/442.json','["靜愛青苔院，深宜白鬢翁。貌將松共瘦，心與竹俱空。", "暖有低簷日，春多颺幕風。平生閑境界，盡在五言中。"]'),
('yuding-57','予與故刑部李侍郎早結道友以藥術為事與故京兆元尹晚為詩侶有林泉之期周歲之間二君長逝李住曲江北元居昇平西追感舊遊因貽同志','白居易','唐','御定全唐诗','yuding','','[]','從哭李來傷道氣，自亡元後減詩情。金丹同學都無益，',40,'御定全唐詩/json/442.json','["從哭李來傷道氣，自亡元後減詩情。金丹同學都無益，", "如年七十身猶在，但恐傷心無處行。"]'),
('yuding-58','送馮舍人閣老往襄陽','白居易','唐','御定全唐诗','yuding','','[]','紫微閣底送君回，第二廳簾下不開。',32,'御定全唐詩/json/442.json','["紫微閣底送君回，第二廳簾下不開。", "莫戀漢南風景好，峴山花儘早歸來。"]'),
('yuding-59','莫走柳條詞送別','白居易','唐','御定全唐诗','yuding','','[]','南陌傷心別，東風滿把春。莫欺楊柳弱，勸酒勝於人。',24,'御定全唐詩/json/442.json','["南陌傷心別，東風滿把春。莫欺楊柳弱，勸酒勝於人。"]'),
('yuding-60','酬韓侍郎、張博士雨後游曲江見寄','白居易','唐','御定全唐诗','yuding','','[]','小園新種紅櫻樹，閑繞花行便當遊。',32,'御定全唐詩/json/442.json','["小園新種紅櫻樹，閑繞花行便當遊。", "何必更隨鞍馬隊，沖泥蹋雨曲江頭。"]'),
('yuding-61','元家花','白居易','唐','御定全唐诗','yuding','','[]','今日元家宅，櫻桃發幾枝。稀稠與顏色，一似去年時。',36,'御定全唐詩/json/442.json','["今日元家宅，櫻桃發幾枝。稀稠與顏色，一似去年時。", "失卻東園主，春風可得知。"]'),
('yuding-62','代人贈王員外','白居易','唐','御定全唐诗','yuding','','[]','好在王員外，平生記得不。共賒黃叟酒，同上莫愁樓。',48,'御定全唐詩/json/442.json','["好在王員外，平生記得不。共賒黃叟酒，同上莫愁樓。", "靜接殷勤語，狂隨爛熳遊。那知今日眼，相見冷於秋。"]'),
('yuding-63','惜小園花','白居易','唐','御定全唐诗','yuding','','[]','曉來紅萼凋零盡，但見空枝四五株。',32,'御定全唐詩/json/442.json','["曉來紅萼凋零盡，但見空枝四五株。", "前日狂風昨夜雨，殘芳更合得存無。"]'),
('yuding-64','蕭相公宅遇自遠禪師，有感而贈','白居易','唐','御定全唐诗','yuding','','[]','宦途堪笑不勝悲，昨日榮華今日衰。轉似秋蓬無定處，',40,'御定全唐詩/json/442.json','["宦途堪笑不勝悲，昨日榮華今日衰。轉似秋蓬無定處，", "應是世間緣未盡，欲拋官去尚遲疑。"]'),
('yuding-65','草詞畢遇芍藥初開因詠小謝紅藥當階翻詩以為一句未盡其狀偶成十六韻','白居易','唐','御定全唐诗','yuding','','[]','罷草紫泥詔，起吟紅藥詩。詞頭封送後，花口拆開時。',192,'御定全唐詩/json/442.json','["罷草紫泥詔，起吟紅藥詩。詞頭封送後，花口拆開時。", "坐對鉤簾久，行觀步履遲。兩三叢爛熳，十二葉參差。", "背日房微斂，當階朵旋欹。釵葶抽碧股，粉蕊撲黃絲。", "動盪情無限，低斜力不支。周回看未足，比諭語難為。", "勾漏丹砂裏，僬僥火焰旗。彤雲剩根蒂，絳幘欠纓緌。", "況有晴風度，仍兼宿露垂。疑香熏罨畫，似淚著胭脂。", "有意留連我，無言怨思誰。應愁明日落，如恨來年期。", "菡萏泥連萼，玫瑰刺繞枝。等量無勝者，唯眼與心知。"]'),
('yuding-66','喜張十八博士除水部員外郎','白居易','唐','御定全唐诗','yuding','','[]','老何歿後吟聲絕，雖有郎官不愛詩。無複篇章傳道路，',40,'御定全唐詩/json/442.json','["老何歿後吟聲絕，雖有郎官不愛詩。無複篇章傳道路，", "今日聞君除水部，喜於身得省郎時。"]'),
('yuding-67','與沈、楊二舍人閣老同食敕賜櫻桃玩物感恩因成十四韻','白居易','唐','御定全唐诗','yuding','','[]','清曉趨丹禁，紅櫻降紫宸。驅禽養得熟，和葉摘來新。',168,'御定全唐詩/json/442.json','["清曉趨丹禁，紅櫻降紫宸。驅禽養得熟，和葉摘來新。", "圓轉盤傾玉，鮮明籠透銀。內園題兩字，四掖賜三臣。", "熒惑晶華赤，醍醐氣味真。如珠未穿孔，似火不燒人。", "杏俗難為對，桃頑詎可倫。肉嫌盧橘厚，皮笑荔枝皴。", "瓊液酸甜足，金丸大小勻。偷須防曼倩，惜莫擲安仁。", "手擘才離核，匙抄半是津。甘為舌上露，暖作腹中春。", "已懼長屍祿，仍驚數食珍。最慚恩未報，飽喂不才身。"]'),
('yuding-68','送嚴大夫赴桂州','白居易','唐','御定全唐诗','yuding','','[]','地壓坤方重，官兼憲府雄。桂林無瘴氣，柏署有清風。',48,'御定全唐詩/json/442.json','["地壓坤方重，官兼憲府雄。桂林無瘴氣，柏署有清風。", "山水衙門外，旌旗艛艓中。大夫應絕席，詩酒與誰同。"]'),
('yuding-69','春夜宿直','白居易','唐','御定全唐诗','yuding','','[]','三月十四夜，西垣東北廊。碧梧葉重疊，紅藥樹低昂。',48,'御定全唐詩/json/442.json','["三月十四夜，西垣東北廊。碧梧葉重疊，紅藥樹低昂。", "月砌漏幽影，風簾飄暗香。禁中無宿客，誰伴紫微郎。"]'),
('yuding-70','夏夜宿直','白居易','唐','御定全唐诗','yuding','','[]','人少庭宇曠，夜涼風露清。槐花滿院氣，松子落階聲。',48,'御定全唐詩/json/442.json','["人少庭宇曠，夜涼風露清。槐花滿院氣，松子落階聲。", "寂寞挑燈坐，沉吟蹋月行。年衰自無趣，不是厭承明。"]'),
('yuding-71','七言十二句贈駕部吳郎中七兄','白居易','唐','御定全唐诗','yuding','','[]','四月天氣和且清，綠槐陰合沙堤平。獨騎善馬銜鐙穩，',48,'御定全唐詩/json/442.json','["四月天氣和且清，綠槐陰合沙堤平。獨騎善馬銜鐙穩，", "風生竹夜窗間臥，月照松時台上行。春酒冷嘗三數醆，"]'),
('yuding-72','玉真張觀主下小女冠阿容','白居易','唐','御定全唐诗','yuding','','[]','綽約小天仙，生來十六年。姑山半峰雪，瑤水一枝蓮。',48,'御定全唐詩/json/442.json','["綽約小天仙，生來十六年。姑山半峰雪，瑤水一枝蓮。", "晚院花留立，春窗月伴眠。回眸雖欲語，阿母在傍邊。"]'),
('yuding-73','龍花寺主家小尼','白居易','唐','御定全唐诗','yuding','','[]','頭青眉眼細，十四女沙彌。夜靜雙林怕，春深一食饑。',48,'御定全唐詩/json/442.json','["頭青眉眼細，十四女沙彌。夜靜雙林怕，春深一食饑。", "步慵行道困，起晚誦經遲。應似仙人子，花宮未嫁時。"]'),
('yuding-74','訪陳二','白居易','唐','御定全唐诗','yuding','','[]','曉垂朱綬帶，晚著白綸巾。出去為朝客，歸來是野人。',48,'御定全唐詩/json/442.json','["曉垂朱綬帶，晚著白綸巾。出去為朝客，歸來是野人。", "兩餐聊過日，一榻足容身。此外皆閒事，時時訪老陳。"]'),
('yuding-75','晚亭逐涼','白居易','唐','御定全唐诗','yuding','','[]','送客出門後，移床下砌初。趁涼行繞竹，引睡臥看書。',48,'御定全唐詩/json/442.json','["送客出門後，移床下砌初。趁涼行繞竹，引睡臥看書。", "老更為官拙，慵多向事疏。松窗倚藤杖，人道似僧居。"]'),
('yuding-76','曲江憶李十一','白居易','唐','御定全唐诗','yuding','','[]','李君歿後共誰游，柳岸荷亭兩度秋。',32,'御定全唐詩/json/442.json','["李君歿後共誰游，柳岸荷亭兩度秋。", "獨繞曲江行一匝，依前還立水邊愁。"]'),
('yuding-77','江亭玩春','白居易','唐','御定全唐诗','yuding','','[]','江亭乘曉閱眾芳，春妍景麗草樹光。日消石桂綠嵐氣，',40,'御定全唐詩/json/442.json','["江亭乘曉閱眾芳，春妍景麗草樹光。日消石桂綠嵐氣，", "何物春風吹不變，愁人依舊鬢蒼蒼。"]'),
('yuding-78','聞夜砧','白居易','唐','御定全唐诗','yuding','','[]','誰家思婦秋搗帛，月苦風淒砧杵悲。八月九月正長夜，',24,'御定全唐詩/json/442.json','["誰家思婦秋搗帛，月苦風淒砧杵悲。八月九月正長夜，"]'),
('yuding-79','板橋路','白居易','唐','御定全唐诗','yuding','','[]','梁苑城西二十裏，一渠春水柳千條。若為此路今重過，',24,'御定全唐詩/json/442.json','["梁苑城西二十裏，一渠春水柳千條。若為此路今重過，"]'),
('yuding-80','青門柳','白居易','唐','御定全唐诗','yuding','','[]','青青一樹傷心色，曾入幾人離恨中。',32,'御定全唐詩/json/442.json','["青青一樹傷心色，曾入幾人離恨中。", "為近都門多送別，長條折盡減春風。"]'),
('yuding-81','梨園弟子','白居易','唐','御定全唐诗','yuding','','[]','白頭垂淚話梨園，五十年前雨露恩。',32,'御定全唐詩/json/442.json','["白頭垂淚話梨園，五十年前雨露恩。", "莫問華清今日事，滿山紅葉鎖宮門。"]'),
('yuding-82','暮江吟','白居易','唐','御定全唐诗','yuding','','[]','一道殘陽鋪水中，半江瑟瑟半江紅。',32,'御定全唐詩/json/442.json','["一道殘陽鋪水中，半江瑟瑟半江紅。", "可憐九月初三夜，露似真珠月似弓。"]'),
('yuding-83','思婦眉','白居易','唐','御定全唐诗','yuding','','[]','春風搖盪自東來，折盡櫻桃綻盡梅。',32,'御定全唐詩/json/442.json','["春風搖盪自東來，折盡櫻桃綻盡梅。", "惟餘思婦愁眉結，無限春風吹不開。"]'),
('yuding-84','怨詞','白居易','唐','御定全唐诗','yuding','','[]','奪寵心那慣，尋思倚殿門。不知移舊愛，何處作新恩。',24,'御定全唐詩/json/442.json','["奪寵心那慣，尋思倚殿門。不知移舊愛，何處作新恩。"]'),
('yuding-85','空閨怨','白居易','唐','御定全唐诗','yuding','','[]','寒月沉沉洞房靜，真珠簾外梧桐影。',32,'御定全唐詩/json/442.json','["寒月沉沉洞房靜，真珠簾外梧桐影。", "秋霜欲下手先知，燈底裁縫剪刀冷。"]'),
('yuding-86','秋房夜','白居易','唐','御定全唐诗','yuding','','[]','雲露青天月漏光，中庭立久卻歸房。',32,'御定全唐詩/json/442.json','["雲露青天月漏光，中庭立久卻歸房。", "水窗席冷未能臥，挑盡殘燈秋夜長。"]'),
('yuding-87','採蓮曲','白居易','唐','御定全唐诗','yuding','','[]','菱葉縈波荷颭風，荷花深處小船通。',32,'御定全唐詩/json/442.json','["菱葉縈波荷颭風，荷花深處小船通。", "逢郎欲語低頭笑，碧玉搔頭落水中。"]'),
('yuding-88','鄰女','白居易','唐','御定全唐诗','yuding','','[]','娉婷十五勝天仙，白日姮娥旱地蓮。',32,'御定全唐詩/json/442.json','["娉婷十五勝天仙，白日姮娥旱地蓮。", "何處閑教鸚鵡語，碧紗窗下繡床前。"]'),
('yuding-89','閨婦','白居易','唐','御定全唐诗','yuding','','[]','斜憑繡床愁不動，紅綃帶緩綠鬟低。',32,'御定全唐詩/json/442.json','["斜憑繡床愁不動，紅綃帶緩綠鬟低。", "遼陽春盡無消息，夜合花前日又西。"]'),
('yuding-90','移牡丹栽','白居易','唐','御定全唐诗','yuding','','[]','金錢買得牡丹栽，何處辭叢別主來。',32,'御定全唐詩/json/442.json','["金錢買得牡丹栽，何處辭叢別主來。", "紅芳堪惜還堪恨，百處移將百處開。"]'),
('yuding-91','聽夜箏有感','白居易','唐','御定全唐诗','yuding','','[]','江州去日聽箏夜，白髮新生不願聞。',32,'御定全唐詩/json/442.json','["江州去日聽箏夜，白髮新生不願聞。", "如今格是頭成雪，彈到天明亦任君。"]'),
('yuding-92','代謝好妓答崔員外','白居易','唐','御定全唐诗','yuding','','[]','青娥小謝娘，白髮老崔郎。謾愛胸前雪，其如頭上霜。',40,'御定全唐詩/json/442.json','["青娥小謝娘，白髮老崔郎。謾愛胸前雪，其如頭上霜。", "別後曹家碑背上，思量好字斷君腸。"]'),
('yuding-93','琵琶','白居易','唐','御定全唐诗','yuding','','[]','弦清撥剌語錚錚，背卻殘燈就月明。',32,'御定全唐詩/json/442.json','["弦清撥剌語錚錚，背卻殘燈就月明。", "賴是心無惆悵事，不然爭奈子弦聲。"]'),
('yuding-94','和殷協律琴思','白居易','唐','御定全唐诗','yuding','','[]','秋水蓮冠春草裙，依稀風調似文君。',32,'御定全唐詩/json/442.json','["秋水蓮冠春草裙，依稀風調似文君。", "煩君玉指分明語，知是琴心佯不聞。"]'),
('yuding-95','寄李蘇州，兼示楊瓊','白居易','唐','御定全唐诗','yuding','','[]','真娘墓頭春草碧，心奴鬢上秋霜白。為問蘇台酒席中，',24,'御定全唐詩/json/442.json','["真娘墓頭春草碧，心奴鬢上秋霜白。為問蘇台酒席中，"]'),
('yuding-96','聽彈湘妃怨','白居易','唐','御定全唐诗','yuding','','[]','玉軫朱弦瑟瑟徽，吳娃徵調奏湘妃。',32,'御定全唐詩/json/442.json','["玉軫朱弦瑟瑟徽，吳娃徵調奏湘妃。", "分明曲裏愁雲雨，似道蕭蕭郎不歸。"]'),
('yuding-97','閑坐','白居易','唐','御定全唐诗','yuding','','[]','暖擁紅爐火，閑搔白髮頭。百年慵裏過，萬事醉中休。',48,'御定全唐詩/json/442.json','["暖擁紅爐火，閑搔白髮頭。百年慵裏過，萬事醉中休。", "有室同摩詰，無兒比鄧攸。莫論身在日，身後亦無憂。"]'),
('yuding-98','不睡','白居易','唐','御定全唐诗','yuding','','[]','焰短寒缸盡，聲長曉漏遲。年衰自無睡，不是守三屍。',24,'御定全唐詩/json/442.json','["焰短寒缸盡，聲長曉漏遲。年衰自無睡，不是守三屍。"]'),
('yuding-0','初罷中書舍人','白居易','唐','御定全唐诗','yuding','','[]','自慚拙宦叨清貴，還有癡心怕素餐。或望君臣相獻替，',40,'御定全唐詩/json/443.json','["自慚拙宦叨清貴，還有癡心怕素餐。或望君臣相獻替，", "分寸寵光酬未得，不休更擬覓何官。"]'),
('yuding-1','宿陽城驛對月','白居易','唐','御定全唐诗','yuding','','[]','親故尋回駕，妻孥未出關。鳳凰池上月，送我過商山。',24,'御定全唐詩/json/443.json','["親故尋回駕，妻孥未出關。鳳凰池上月，送我過商山。"]'),
('yuding-2','商山路有感','白居易','唐','御定全唐诗','yuding','','[]','憶昨征還日，三人歸路同。此生都是夢，前事旋成空。',48,'御定全唐詩/json/443.json','["憶昨征還日，三人歸路同。此生都是夢，前事旋成空。", "杓直泉埋玉，虞平燭過風。唯殘樂天在，頭白向江東。"]'),
('yuding-3','重感','白居易','唐','御定全唐诗','yuding','','[]','停驂歇路隅，重感一長籲。擾擾生還死，紛紛榮又枯。',48,'御定全唐詩/json/443.json','["停驂歇路隅，重感一長籲。擾擾生還死，紛紛榮又枯。", "困支青竹杖，閑捋白髭須。莫歎身衰老，交遊半已無。"]'),
('yuding-4','逢張十八員外籍','白居易','唐','御定全唐诗','yuding','','[]','旅思正茫茫，相逢此道傍。曉嵐林葉暗，秋露草花香。',48,'御定全唐詩/json/443.json','["旅思正茫茫，相逢此道傍。曉嵐林葉暗，秋露草花香。", "白髮江城守，青衫水部郎。客亭同宿處，忽似夜歸鄉。"]'),
('yuding-5','赴杭州重宿棣華驛，見楊八舊詩，感題一絕','白居易','唐','御定全唐诗','yuding','','[]','往恨今愁應不殊，題詩梁下又踟躕。',32,'御定全唐詩/json/443.json','["往恨今愁應不殊，題詩梁下又踟躕。", "羨君猶夢見兄弟，我到天明睡亦無。"]'),
('yuding-6','寓言題僧','白居易','唐','御定全唐诗','yuding','','[]','劫風火起燒荒宅，苦海波生蕩破船。',32,'御定全唐詩/json/443.json','["劫風火起燒荒宅，苦海波生蕩破船。", "力小無因救焚溺，清涼山下且安禪。"]'),
('yuding-7','內鄉村路作','白居易','唐','御定全唐诗','yuding','','[]','日下風高野路涼，緩驅疲馬暗思鄉。',32,'御定全唐詩/json/443.json','["日下風高野路涼，緩驅疲馬暗思鄉。", "渭村秋物應如此，棗赤梨紅稻穗黃。"]'),
('yuding-8','路上寄銀匙與阿龜','白居易','唐','御定全唐诗','yuding','','[]','謫宦心都慣，辭鄉去不難。緣留龜子住，涕淚一闌幹。',48,'御定全唐詩/json/443.json','["謫宦心都慣，辭鄉去不難。緣留龜子住，涕淚一闌幹。", "小子須嬌養，鄒婆為好看。銀匙封寄汝，憶我即加餐。"]'),
('yuding-9','山泉煎茶有懷','白居易','唐','御定全唐诗','yuding','','[]','坐酌泠泠水，看煎瑟瑟塵。無由持一碗，寄與愛茶人。',24,'御定全唐詩/json/443.json','["坐酌泠泠水，看煎瑟瑟塵。無由持一碗，寄與愛茶人。"]'),
('yuding-10','郢州贈別王八使君','白居易','唐','御定全唐诗','yuding','','[]','昔是詩狂客，今為酒病夫。強吟翻悵望，縱醉不歡娛。',48,'御定全唐詩/json/443.json','["昔是詩狂客，今為酒病夫。強吟翻悵望，縱醉不歡娛。", "鬢髮三分白，交親一半無。郢城君莫厭，猶校近京都。"]'),
('yuding-11','吉祥寺見錢侍郎題名','白居易','唐','御定全唐诗','yuding','','[]','雲雨三年別，風波萬里行。愁來正蕭索，況見古人名。',24,'御定全唐詩/json/443.json','["雲雨三年別，風波萬里行。愁來正蕭索，況見古人名。"]'),
('yuding-12','重到江州感舊遊，題郡樓十一韻','白居易','唐','御定全唐诗','yuding','','[]','掌綸知是忝，剖竹信為榮。才薄官仍重，恩深責尚輕。',132,'御定全唐詩/json/443.json','["掌綸知是忝，剖竹信為榮。才薄官仍重，恩深責尚輕。", "昔征從典午，今出自承明。鳳詔休揮翰，漁歌欲濯纓。", "還乘小艛艓，卻到古湓城。醉客臨江待，禪僧出郭迎。", "青山滿眼在，白髮半頭生。又校三年老，何曾一事成。", "重過蕭寺宿，再上庾樓行。雲水新秋思，閭閻舊日情。", "郡民猶認得，司馬詠詩聲。"]'),
('yuding-13','贈江州李十使君員外十二韻','白居易','唐','御定全唐诗','yuding','','[]','我本江湖上，悠悠任運身。朝隨賣藥客，暮伴釣魚人。',144,'御定全唐詩/json/443.json','["我本江湖上，悠悠任運身。朝隨賣藥客，暮伴釣魚人。", "跡為燒丹隱，家緣嗜酒貧。經過剡溪雪，尋覓武陵春。", "豈有疏狂性，堪為侍從臣。仰頭驚鳳闕，下口觸龍鱗。", "劍佩辭天上，風波向海濱。非賢虛偶聖，無屈敢求伸。", "昔去曾同日，今來即後塵。中年俱白髮，左宦各朱輪。", "長短才雖異，榮枯事略均。殷勤李員外，不合不相親。"]'),
('yuding-14','題別遺愛草堂兼呈李十使君','白居易','唐','御定全唐诗','yuding','','[]','曾住爐峰下，書堂對藥台。斬新蘿徑合，依舊竹窗開。',72,'御定全唐詩/json/443.json','["曾住爐峰下，書堂對藥台。斬新蘿徑合，依舊竹窗開。", "砌水親開決，池荷手自栽。五年方暫至，一宿又須回。", "縱未長歸得，猶勝不到來。君家白鹿洞，聞道亦生苔。"]'),
('yuding-15','重題','白居易','唐','御定全唐诗','yuding','','[]','泉石尚依依，林疏僧亦稀。何年辭水閣，今夜宿雲扉。',48,'御定全唐詩/json/443.json','["泉石尚依依，林疏僧亦稀。何年辭水閣，今夜宿雲扉。", "謾獻長楊賦，虛拋薜荔衣。不能成一事，贏得白頭歸。"]'),
('yuding-16','夜泊旅望','白居易','唐','御定全唐诗','yuding','','[]','少睡多愁客，中宵起望鄉。沙明連浦月，帆白滿船霜。',48,'御定全唐詩/json/443.json','["少睡多愁客，中宵起望鄉。沙明連浦月，帆白滿船霜。", "近海江彌闊，迎秋夜更長。煙波三十宿，猶未到錢唐。"]'),
('yuding-17','九江北岸遇風雨','白居易','唐','御定全唐诗','yuding','','[]','黃梅縣邊黃梅雨，白頭浪裏白頭翁。九江闊處不見岸，',24,'御定全唐詩/json/443.json','["黃梅縣邊黃梅雨，白頭浪裏白頭翁。九江闊處不見岸，"]'),
('yuding-18','舟中晚起','白居易','唐','御定全唐诗','yuding','','[]','日高猶掩水窗眠，枕簟清涼八月天。泊處或依沽酒店，',40,'御定全唐詩/json/443.json','["日高猶掩水窗眠，枕簟清涼八月天。泊處或依沽酒店，", "且向錢唐湖上去，冷吟閑醉二三年。"]'),
('yuding-19','秋寒','白居易','唐','御定全唐诗','yuding','','[]','雪鬢年顏老，霜庭景氣秋。病看妻檢藥，寒遣婢梳頭。',48,'御定全唐詩/json/443.json','["雪鬢年顏老，霜庭景氣秋。病看妻檢藥，寒遣婢梳頭。", "身外名何有，人間事且休。澹然方寸內，唯擬學虛舟。"]'),
('yuding-20','初到郡齋寄錢湖州李蘇州','白居易','唐','御定全唐诗','yuding','','[]','俱來滄海郡，半作白頭翁。謾道風煙接，何曾笑語同。',72,'御定全唐詩/json/443.json','["俱來滄海郡，半作白頭翁。謾道風煙接，何曾笑語同。", "吏稀秋稅畢，客散晚庭空。霽後當樓月，潮來滿座風。", "霅溪殊冷僻，茂苑太繁雄。唯此錢唐郡，閑忙恰得中。"]'),
('yuding-21','對酒自勉','白居易','唐','御定全唐诗','yuding','','[]','五十江城守，停杯一自思。頭仍未盡白，官亦不全卑。',72,'御定全唐詩/json/443.json','["五十江城守，停杯一自思。頭仍未盡白，官亦不全卑。", "榮寵尋過分，歡娛已校遲。肺傷雖怕酒，心健尚誇詩。", "夜舞吳娘袖，春歌蠻子詞。猶堪三五歲，相伴醉花時。"]'),
('yuding-22','郡樓夜宴留客','白居易','唐','御定全唐诗','yuding','','[]','北客勞相訪，東樓為一開。褰簾待月出，把火看潮來。',48,'御定全唐詩/json/443.json','["北客勞相訪，東樓為一開。褰簾待月出，把火看潮來。", "豔聽竹枝曲，香傳蓮子杯。寒天殊未曉，歸騎且遲回。"]'),
('yuding-23','醉題候仙亭','白居易','唐','御定全唐诗','yuding','','[]','蹇步垂朱綬，華纓映白須。何因駐衰老，只有且歡娛。',48,'御定全唐詩/json/443.json','["蹇步垂朱綬，華纓映白須。何因駐衰老，只有且歡娛。", "酒興還應在，詩情可便無。登山與臨水，猶未要人扶。"]'),
('yuding-24','東院','白居易','唐','御定全唐诗','yuding','','[]','松下軒廊竹下房，暖簷晴日滿繩床。淨名居士經三卷，',40,'御定全唐詩/json/443.json','["松下軒廊竹下房，暖簷晴日滿繩床。淨名居士經三卷，", "有時閑酌無人伴，獨自騰騰入醉鄉。"]'),
('yuding-25','虛白堂','白居易','唐','御定全唐诗','yuding','','[]','虛白堂前衙退後，更無一事到中心。',32,'御定全唐詩/json/443.json','["虛白堂前衙退後，更無一事到中心。", "移床就日簷間臥，臥詠閑詩側枕琴。"]'),
('yuding-26','閑夜詠懷，因招周協律，劉、薛二秀才','白居易','唐','御定全唐诗','yuding','','[]','世名檢束為朝士，心性疏慵是野夫。高置寒燈如客店，',40,'御定全唐詩/json/443.json','["世名檢束為朝士，心性疏慵是野夫。高置寒燈如客店，", "若厭雅吟須俗飲，妓筵勉力為君鋪。"]'),
('yuding-27','晚興','白居易','唐','御定全唐诗','yuding','','[]','極浦收殘雨，高城駐落暉。山明虹半出，松暗鶴雙歸。',48,'御定全唐詩/json/443.json','["極浦收殘雨，高城駐落暉。山明虹半出，松暗鶴雙歸。", "將吏隨衙散，文書入務稀。閑吟倚新竹，筠粉汙朱衣。"]'),
('yuding-28','衰病','白居易','唐','御定全唐诗','yuding','','[]','老與病相仍，華簪發不勝。行多朝散藥，睡少夜停燈。',48,'御定全唐詩/json/443.json','["老與病相仍，華簪發不勝。行多朝散藥，睡少夜停燈。", "祿食分供鶴，朝衣減施僧。性多移不得，郡政謾如繩。"]'),
('yuding-29','病中對病鶴','白居易','唐','御定全唐诗','yuding','','[]','同病病夫憐病鶴，精神不損翅翎傷。未堪再舉摩霄漢，',40,'御定全唐詩/json/443.json','["同病病夫憐病鶴，精神不損翅翎傷。未堪再舉摩霄漢，", "唯應一事宜為伴，我發君毛俱似霜。"]'),
('yuding-30','夜歸','白居易','唐','御定全唐诗','yuding','','[]','半醉閑行湖岸東，馬鞭敲鐙轡瓏璁。萬株松樹青山上，',40,'御定全唐詩/json/443.json','["半醉閑行湖岸東，馬鞭敲鐙轡瓏璁。萬株松樹青山上，", "歸來未放笙歌散，畫戟門開蠟燭紅。"]'),
('yuding-31','臘後歲前遇景詠意','白居易','唐','御定全唐诗','yuding','','[]','海梅半白柳微黃，凍水初融日欲長。度臘都無苦霜霰，',40,'御定全唐詩/json/443.json','["海梅半白柳微黃，凍水初融日欲長。度臘都無苦霜霰，", "公事漸閑身且健，使君殊未厭餘杭。"]'),
('yuding-32','白髮','白居易','唐','御定全唐诗','yuding','','[]','雪發隨梳落，霜毛繞鬢垂。加添老氣味，改變舊容儀。',48,'御定全唐詩/json/443.json','["雪發隨梳落，霜毛繞鬢垂。加添老氣味，改變舊容儀。", "不肯長如漆，無過總作絲。最憎明鏡裏，黑白半頭時。"]'),
('yuding-33','錢湖州以箬下酒李蘇州以五酘酒相次寄到無因同飲聊詠所懷','白居易','唐','御定全唐诗','yuding','','[]','勞將箬下忘憂物，寄與江城愛酒翁。鐺腳三州何處會，',40,'御定全唐詩/json/443.json','["勞將箬下忘憂物，寄與江城愛酒翁。鐺腳三州何處會，", "莫怪殷勤醉相憶，曾陪西省與南宮。"]'),
('yuding-34','花樓望雪命宴賦詩','白居易','唐','御定全唐诗','yuding','','[]','連天際海白皚皚，好上高樓望一回。何處更能分道路，',72,'御定全唐詩/json/443.json','["連天際海白皚皚，好上高樓望一回。何處更能分道路，", "素壁聯題分韻句，紅爐巡飲暖寒杯。冰鋪湖水銀為面，", "輸將虛白堂前鶴，失卻樟亭驛後梅。別有故情偏憶得，"]'),
('yuding-35','晚歲','白居易','唐','御定全唐诗','yuding','','[]','壯歲忽已去，浮榮何足論。身為百口長，官是一州尊。',96,'御定全唐詩/json/443.json','["壯歲忽已去，浮榮何足論。身為百口長，官是一州尊。", "不覺白雙鬢，徒言朱兩轓。病難施郡政，老未答君恩。", "歲暮別兄弟，年衰無子孫。惹愁諳世網，治苦賴空門。", "攬帶知腰瘦，看燈覺眼昏。不緣衣食系，尋合返丘園。"]'),
('yuding-36','宿竹閣','白居易','唐','御定全唐诗','yuding','','[]','晚坐松簷下，宵眠竹閣間。清虛當服藥，幽獨抵歸山。',48,'御定全唐詩/json/443.json','["晚坐松簷下，宵眠竹閣間。清虛當服藥，幽獨抵歸山。", "巧未能勝拙，忙應不及閑。無勞別修道，即此是玄關。"]'),
('yuding-37','歲暮枉衢州張使君書並詩，因以長句報之','白居易','唐','御定全唐诗','yuding','','[]','西州彼此意何如，官職蹉跎歲欲除。浮石潭邊停五馬，',40,'御定全唐詩/json/443.json','["西州彼此意何如，官職蹉跎歲欲除。浮石潭邊停五馬，", "貧薄詩家無好物，反投桃李報瓊琚。"]'),
('yuding-38','和薛秀才尋梅花同飲見贈','白居易','唐','御定全唐诗','yuding','','[]','忽驚林下發寒梅，便試花前飲冷杯。白馬走迎詩客去，',40,'御定全唐詩/json/443.json','["忽驚林下發寒梅，便試花前飲冷杯。白馬走迎詩客去，", "若到歲寒無雨雪，猶應醉得兩三回。"]'),
('yuding-39','與諸客空腹飲','白居易','唐','御定全唐诗','yuding','','[]','隔宿書招客，平明飲暖寒。麹神寅日合，酒聖卯時歡。',72,'御定全唐詩/json/443.json','["隔宿書招客，平明飲暖寒。麹神寅日合，酒聖卯時歡。", "促膝才飛白，酡顏已渥丹。碧籌攢米碗，紅袖拂骰盤。", "醉後歌尤異，狂來舞不難。拋杯語同坐，莫作老人看。"]'),
('yuding-40','小歲日對酒吟錢湖州所寄詩','白居易','唐','御定全唐诗','yuding','','[]','獨酌無多興，閑吟有所思。一杯新歲酒，兩句故人詩。',48,'御定全唐詩/json/443.json','["獨酌無多興，閑吟有所思。一杯新歲酒，兩句故人詩。", "楊柳初黃日，髭須半白時。蹉跎春氣味，彼此老心知。"]'),
('yuding-41','錢唐湖春行','白居易','唐','御定全唐诗','yuding','','[]','孤山寺北賈亭西，水面初平雲腳低。幾處早鶯爭暖樹，',40,'御定全唐詩/json/443.json','["孤山寺北賈亭西，水面初平雲腳低。幾處早鶯爭暖樹，", "最愛湖東行不足，綠楊陰裏白沙堤。"]'),
('yuding-42','題靈隱寺紅辛夷花，戲酬光上人','白居易','唐','御定全唐诗','yuding','','[]','紫粉筆含尖火焰，紅胭脂染小蓮花。',32,'御定全唐詩/json/443.json','["紫粉筆含尖火焰，紅胭脂染小蓮花。", "芳情鄉思知多少，惱得山僧悔出家。"]'),
('yuding-43','重向火','白居易','唐','御定全唐诗','yuding','','[]','火銷灰複死，疏棄已經旬。豈是人情薄，其如天氣春。',48,'御定全唐詩/json/443.json','["火銷灰複死，疏棄已經旬。豈是人情薄，其如天氣春。", "風寒忽再起，手冷重相親。卻就紅爐坐，心如逢故人。"]'),
('yuding-44','候仙亭同諸客醉作','白居易','唐','御定全唐诗','yuding','','[]','謝安山下空攜妓，柳惲洲邊只賦詩。',32,'御定全唐詩/json/443.json','["謝安山下空攜妓，柳惲洲邊只賦詩。", "爭及湖亭今日會，嘲花詠水贈蛾眉。"]'),
('yuding-45','城上','白居易','唐','御定全唐诗','yuding','','[]','城上冬冬鼓，朝衙複晚衙。為君慵不出，落盡繞城花。',24,'御定全唐詩/json/443.json','["城上冬冬鼓，朝衙複晚衙。為君慵不出，落盡繞城花。"]'),
('yuding-46','早行林下','白居易','唐','御定全唐诗','yuding','','[]','披衣未冠櫛，晨起入前林。宿露殘花氣，朝光新葉陰。',48,'御定全唐詩/json/443.json','["披衣未冠櫛，晨起入前林。宿露殘花氣，朝光新葉陰。", "傍松人跡少，隔竹鳥聲深。閑倚小橋立，傾頭時一吟。"]'),
('yuding-47','送李校書趁寒食歸義興山居','白居易','唐','御定全唐诗','yuding','','[]','大見騰騰詩酒客，不憂生計似君稀。',32,'御定全唐詩/json/443.json','["大見騰騰詩酒客，不憂生計似君稀。", "到舍將何作寒食，滿船唯載樹陰歸。"]'),
('yuding-48','題孤山寺山石榴花示諸僧眾','白居易','唐','御定全唐诗','yuding','','[]','山榴花似結紅巾，容豔新妍占斷春。色相故關行地道，',24,'御定全唐詩/json/443.json','["山榴花似結紅巾，容豔新妍占斷春。色相故關行地道，"]'),
('yuding-49','獨行','白居易','唐','御定全唐诗','yuding','','[]','暗誦黃庭經在口，閑攜青竹杖隨身。',32,'御定全唐詩/json/443.json','["暗誦黃庭經在口，閑攜青竹杖隨身。", "晚花新筍堪為伴，獨入林行不要人。"]'),
('yuding-50','二月五日花下作','白居易','唐','御定全唐诗','yuding','','[]','二月五日花如雪，五十二人頭似霜。聞有酒時須笑樂，',40,'御定全唐詩/json/443.json','["二月五日花如雪，五十二人頭似霜。聞有酒時須笑樂，", "只有且來花下醉，從人笑道老顛狂。"]'),
('yuding-51','戲題木蘭花','白居易','唐','御定全唐诗','yuding','','[]','紫房日照胭脂拆，素豔風吹膩粉開。',32,'御定全唐詩/json/443.json','["紫房日照胭脂拆，素豔風吹膩粉開。", "怪得獨饒脂粉態，木蘭曾作女郎來。"]'),
('yuding-52','清明日觀妓舞聽客詩','白居易','唐','御定全唐诗','yuding','','[]','看舞顏如玉，聽詩韻似金。綺羅從許笑，弦管不妨吟。',48,'御定全唐詩/json/443.json','["看舞顏如玉，聽詩韻似金。綺羅從許笑，弦管不妨吟。", "可惜春風老，無嫌酒醆深。辭花送寒食，並在此時心。"]'),
('yuding-53','西湖晚歸，回望孤山寺，贈諸客','白居易','唐','御定全唐诗','yuding','','[]','柳湖松島蓮花寺，晚動歸橈出道場。盧橘子低山雨重，',40,'御定全唐詩/json/443.json','["柳湖松島蓮花寺，晚動歸橈出道場。盧橘子低山雨重，", "到岸請君回首望，蓬萊宮在海中央。"]'),
('yuding-54','湖中自照','白居易','唐','御定全唐诗','yuding','','[]','重重照影看容鬢，不見朱顏見白絲。',32,'御定全唐詩/json/443.json','["重重照影看容鬢，不見朱顏見白絲。", "失卻少年無處覓，泥他湖水欲何為。"]'),
('yuding-55','贈蘇煉師','白居易','唐','御定全唐诗','yuding','','[]','兩鬢蒼然心浩然，松窗深處藥爐前。攜將道士通宵語，',40,'御定全唐詩/json/443.json','["兩鬢蒼然心浩然，松窗深處藥爐前。攜將道士通宵語，", "猶嫌莊子多詞句，唯讀逍遙六七篇。"]'),
('yuding-56','杭州春望','白居易','唐','御定全唐诗','yuding','','[]','望海樓明照曙霞，護江堤白蹋晴沙。濤聲夜入伍員廟，',40,'御定全唐詩/json/443.json','["望海樓明照曙霞，護江堤白蹋晴沙。濤聲夜入伍員廟，", "誰開湖寺西南路，草綠裙腰一道斜。"]'),
('yuding-57','飲散夜歸贈諸客','白居易','唐','御定全唐诗','yuding','','[]','鞍馬夜紛紛，香街起暗塵。回鞭招飲妓，分火送歸人。',48,'御定全唐詩/json/443.json','["鞍馬夜紛紛，香街起暗塵。回鞭招飲妓，分火送歸人。", "風月應堪惜，杯觴莫厭頻。明朝三月盡，忍不送殘春。"]'),
('yuding-58','湖亭晚歸','白居易','唐','御定全唐诗','yuding','','[]','盡日湖亭臥，心閒事亦稀。起因殘醉醒，坐待晚涼歸。',48,'御定全唐詩/json/443.json','["盡日湖亭臥，心閒事亦稀。起因殘醉醒，坐待晚涼歸。", "松雨飄藤帽，江風透葛衣。柳堤行不厭，沙軟絮霏霏。"]'),
('yuding-59','東樓南望八韻','白居易','唐','御定全唐诗','yuding','','[]','不厭東南望，江樓對海門。風濤生有信，天水合無痕。',96,'御定全唐詩/json/443.json','["不厭東南望，江樓對海門。風濤生有信，天水合無痕。", "鷁帶雲帆動，鷗和雪浪翻。魚鹽聚為市，煙火起成村。", "日腳金波碎，峰頭鈿點繁。送秋千裏雁，報暝一聲猿。", "已豁煩襟悶，仍開病眼昏。郡中登眺處，無勝此東軒。"]'),
('yuding-60','醉中酬殷協律','白居易','唐','御定全唐诗','yuding','','[]','泗水亭邊一分散，浙江樓上重遊陪。揮鞭二十年前別，',40,'御定全唐詩/json/443.json','["泗水亭邊一分散，浙江樓上重遊陪。揮鞭二十年前別，", "留君夜住非無分，且盡青娥紅燭臺。"]'),
('yuding-61','孤山寺遇雨','白居易','唐','御定全唐诗','yuding','','[]','拂波雲色重，灑葉雨聲繁。水鷺雙飛起，風荷一向翻。',48,'御定全唐詩/json/443.json','["拂波雲色重，灑葉雨聲繁。水鷺雙飛起，風荷一向翻。", "空蒙連北岸，蕭颯入東軒。或擬湖中宿，留船在寺門。"]'),
('yuding-62','樟亭雙櫻樹','白居易','唐','御定全唐诗','yuding','','[]','南館西軒兩樹櫻，春條長足夏陰成。',32,'御定全唐詩/json/443.json','["南館西軒兩樹櫻，春條長足夏陰成。", "素華朱實今雖盡，碧葉風來別有情。"]'),
('yuding-63','湖上夜飲','白居易','唐','御定全唐诗','yuding','','[]','郭外迎人月，湖邊醒酒風。誰留使君飲，紅燭在舟中。',24,'御定全唐詩/json/443.json','["郭外迎人月，湖邊醒酒風。誰留使君飲，紅燭在舟中。"]'),
('yuding-64','贈沙鷗','白居易','唐','御定全唐诗','yuding','','[]','老逼教垂白，官科遣著緋。形骸雖有累，方寸卻無機。',48,'御定全唐詩/json/443.json','["老逼教垂白，官科遣著緋。形骸雖有累，方寸卻無機。", "遇酒多先醉，逢山愛晚歸。沙鷗不知我，猶避隼旟飛。"]'),
('yuding-65','餘杭形勝','白居易','唐','御定全唐诗','yuding','','[]','餘杭形勝四方無，州傍青山縣枕湖。繞郭荷花三十裏，',40,'御定全唐詩/json/443.json','["餘杭形勝四方無，州傍青山縣枕湖。繞郭荷花三十裏，", "獨有使君年太老，風光不稱白髭須。"]'),
('yuding-66','江樓夕望招客','白居易','唐','御定全唐诗','yuding','','[]','海天東望夕茫茫，山勢川形闊複長。燈火萬家城四畔，',40,'御定全唐詩/json/443.json','["海天東望夕茫茫，山勢川形闊複長。燈火萬家城四畔，", "能就江樓銷暑否，比君茅舍較清涼。"]'),
('yuding-67','新秋病起','白居易','唐','御定全唐诗','yuding','','[]','一葉落梧桐，年光半又空。秋多上階日，涼足入懷風。',72,'御定全唐詩/json/443.json','["一葉落梧桐，年光半又空。秋多上階日，涼足入懷風。", "病瘦形如鶴，愁焦鬢似蓬。損心詩思裏，伐性酒狂中。", "華蓋何曾惜，金丹不致功。猶須自慚愧，得作白頭翁。"]'),
('yuding-68','木芙蓉花下招客飲','白居易','唐','御定全唐诗','yuding','','[]','晚涼思飲兩三杯，召得江頭酒客來。',32,'御定全唐詩/json/443.json','["晚涼思飲兩三杯，召得江頭酒客來。", "莫怕秋無伴醉物，水蓮花盡木蓮開。"]'),
('yuding-69','悲歌','白居易','唐','御定全唐诗','yuding','','[]','白頭新洗鏡新磨，老逼身來不奈何。耳裏頻聞故人死，',40,'御定全唐詩/json/443.json','["白頭新洗鏡新磨，老逼身來不奈何。耳裏頻聞故人死，", "獨有衰顏留不得，醉來無計但悲歌。"]'),
('yuding-70','江樓晚眺，景物鮮奇，吟玩成篇，寄水部張員外','白居易','唐','御定全唐诗','yuding','','[]','澹煙疏雨間斜陽，江色鮮明海氣涼。蜃散雲收破樓閣，',40,'御定全唐詩/json/443.json','["澹煙疏雨間斜陽，江色鮮明海氣涼。蜃散雲收破樓閣，", "好著丹青圖畫取，題詩寄與水曹郎。"]'),
('yuding-71','夜招周協律，兼答所贈','白居易','唐','御定全唐诗','yuding','','[]','滿眼雖多客，開眉複向誰。少年非我伴，秋夜與君期。',48,'御定全唐詩/json/443.json','["滿眼雖多客，開眉複向誰。少年非我伴，秋夜與君期。", "落魄俱耽酒，殷勤共愛詩。相憐別有意，彼此老無兒。"]');
